// ── Security: account lockout (in-memory, per IP) ────────────────────────────
// Tracks failed /api/auth/login attempts. After MAX_FAILURES within the window
// the IP is locked for LOCKOUT_MS.
const LOCKOUT_MAX_FAILURES = 5;
const LOCKOUT_WINDOW_MS    = 15 * 60 * 1000;  // 15 min
const LOCKOUT_DURATION_MS  = 15 * 60 * 1000;  // 15 min

// Emails that are NEVER subject to IP lockout (super admins)
const LOCKOUT_EXEMPT_EMAILS = new Set<string>([
  "oudaialmouti@gmail.com",
  "rmaru2889@gmail.com",
]);

interface FailureRecord { count: number; firstAt: number; lockedUntil: number | null }
const loginFailures = new Map<string, FailureRecord>();

function getLockedOutIps(): Array<{ ip: string; remaining: number; failureCount: number }> {
  const now = Date.now();
  const result: Array<{ ip: string; remaining: number; failureCount: number }> = [];
  for (const [ip, rec] of loginFailures.entries()) {
    if (rec.lockedUntil && rec.lockedUntil > now) {
      result.push({ ip, remaining: Math.ceil((rec.lockedUntil - now) / 1000), failureCount: rec.count });
    }
  }
  return result;
}

function getClientIp(req: Request): string {
  return (req.headers["x-forwarded-for"] as string | undefined)?.split(",")[0]?.trim()
    ?? req.socket.remoteAddress
    ?? "unknown";
}

function recordLoginFailure(ip: string): { locked: boolean; remaining: number } {
  const now = Date.now();
  let rec = loginFailures.get(ip);

  if (rec) {
    // Reset window if it has expired
    if (now - rec.firstAt > LOCKOUT_WINDOW_MS && !rec.lockedUntil) {
      rec = { count: 0, firstAt: now, lockedUntil: null };
    }
    // If currently locked, keep locked
    if (rec.lockedUntil && now < rec.lockedUntil) {
      loginFailures.set(ip, rec);
      return { locked: true, remaining: Math.ceil((rec.lockedUntil - now) / 1000) };
    }
    rec.count += 1;
    if (rec.count >= LOCKOUT_MAX_FAILURES) {
      rec.lockedUntil = now + LOCKOUT_DURATION_MS;
    }
  } else {
    rec = { count: 1, firstAt: now, lockedUntil: null };
  }
  loginFailures.set(ip, rec);
  return { locked: !!rec.lockedUntil, remaining: rec.lockedUntil ? Math.ceil((rec.lockedUntil - now) / 1000) : 0 };
}

function isIpLockedOut(ip: string): { locked: boolean; remaining: number } {
  const rec = loginFailures.get(ip);
  if (!rec?.lockedUntil) return { locked: false, remaining: 0 };
  const now = Date.now();
  if (now >= rec.lockedUntil) {
    loginFailures.delete(ip);
    return { locked: false, remaining: 0 };
  }
  return { locked: true, remaining: Math.ceil((rec.lockedUntil - now) / 1000) };
}

function clearLoginFailures(ip: string) {
  loginFailures.delete(ip);
}

// Periodically clean up expired entries (every 30 min)
setInterval(() => {
  const now = Date.now();
  for (const [ip, rec] of loginFailures.entries()) {
    const expired = (!rec.lockedUntil && now - rec.firstAt > LOCKOUT_WINDOW_MS)
      || (rec.lockedUntil && now >= rec.lockedUntil);
    if (expired) loginFailures.delete(ip);
  }
}, 30 * 60 * 1000);

// ── Security: event logger ────────────────────────────────────────────────────
async function logSecurityEvent(opts: {
  type: string;
  severity?: "low" | "medium" | "high" | "critical";
  ip?: string;
  userId?: number | null;
  path?: string;
  method?: string;
  message: string;
  metadata?: Record<string, unknown>;
}) {
  try {
    await db.insert(securityEvents).values({
      type:     opts.type,
      severity: opts.severity ?? "low",
      ip:       opts.ip ?? null,
      userId:   opts.userId ?? null,
      path:     opts.path ?? null,
      method:   opts.method ?? null,
      message:  opts.message,
      metadata: (opts.metadata ?? null) as any,
    });
  } catch { /* never let logging crash a request */ }
}

// Authentication middleware
const authenticateJWT = async (req: Request, res: Response, next: NextFunction) => {
  try {
    // Priority 1: Session-based authentication (server-side — most reliable)
    const sessionUserId = (req.session as any)?.userId;
    const sessionUserRole = (req.session as any)?.userRole;

    if (sessionUserId) {
      (req as any).user = { id: sessionUserId, role: sessionUserRole };
      return next();
    }

    // Priority 2: Firebase JWT — verified with Firebase Admin SDK (cryptographic check)
    const authHeader = req.headers.authorization;
    if (!authHeader?.startsWith('Bearer ')) {
      return res.status(401).json({ message: "Authentication required" });
    }

    const token = authHeader.split(' ')[1];
    if (!token) {
      return res.status(401).json({ message: "Authentication token missing" });
    }

    // Check cache first — avoids expensive Firebase external verification on every request
    const cachedUser = jwtTokenCache.get(token);
    if (cachedUser) {
      (req as any).user = cachedUser;
      return next();
    }

    try {
      const decoded = await verifyFirebaseToken(token);
      const firebaseUid = decoded.uid;
      const user = await storage.getUserByFirebaseUid(firebaseUid);
      if (!user) {
        return res.status(401).json({ message: "Authentication failed." });
      }
      jwtTokenCache.set(token, user);
      (req as any).user = user;
      return next();
    } catch {
      return res.status(401).json({ message: "Invalid or expired token" });
    }
  } catch (error) {
    console.error("Authentication error:", error);
    return res.status(500).json({ message: "Authentication error" });
  }
};

