  // Authentication routes
  app.post("/api/auth/login", async (req: Request, res: Response) => {
    const ip = getClientIp(req);

    // ── Check account lockout before doing any Firebase work ──
    // Super-admin emails are permanently exempt from IP lockout.
    const requestEmail: string | undefined = typeof req.body?.email === "string" ? req.body.email.toLowerCase().trim() : undefined;
    const isExempt = requestEmail ? LOCKOUT_EXEMPT_EMAILS.has(requestEmail) : false;

    const lockStatus = isExempt ? { locked: false, remaining: 0 } : isIpLockedOut(ip);
    if (lockStatus.locked) {
      logSecurityEvent({
        type: "auth_lockout_blocked",
        severity: "medium",
        ip,
        path: req.path,
        method: req.method,
        message: `Blocked login attempt from locked-out IP. ${lockStatus.remaining}s remaining.`,
      });
      return res.status(429).json({
        message: `Too many failed login attempts. Try again in ${Math.ceil(lockStatus.remaining / 60)} minute(s).`,
        error: "ACCOUNT_LOCKED",
        retryAfter: lockStatus.remaining,
      });
    }

    try {
      // Preferred: token in Authorization header (Bearer <idToken>)
      // Fallback: token in request body (legacy — kept for backward compatibility)
      const authHeader = req.headers.authorization as string | undefined;
      const headerToken = authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : undefined;

      const loginSchema = z.object({
        idToken: z.string().optional(), // optional — may come from Authorization header instead
        email: z.string().email().optional(),
        displayName: z.string().optional(),
        photoURL: z.string().nullable().optional(),
      });
      
      const { idToken: bodyToken, email, displayName, photoURL } = loginSchema.parse(req.body);
      const idToken = headerToken || bodyToken;
      if (!idToken) {
        return res.status(400).json({ error: "Authentication token required" });
      }
      
      // Verify Firebase ID token
      const decodedToken = await verifyFirebaseIdToken(idToken);
      
      // Get or create user
      const user = await getOrCreateUserByFirebaseUid(decodedToken.uid, {
        email: email || decodedToken.email || null,
        displayName: displayName || decodedToken.name || null,
        photoURL: photoURL || decodedToken.picture || null,
      });
      
      // Successful login — reset failure counter
      clearLoginFailures(ip);

      // Log admin logins as a security event for auditability
      if (isAdminRole(user.role)) {
        logSecurityEvent({
          type: "admin_login",
          severity: "low",
          ip,
          userId: user.id,
          path: req.path,
          method: req.method,
          message: `Admin login: ${user.email ?? user.displayName}`,
          metadata: { userAgent: req.headers["user-agent"] },
        });
      }

      // Set session — express-session auto-saves on response close (no need to await session.save())
      if (req.session) {
        req.session.user = user;
        req.session.userId = user.id;
        req.session.userRole = user.role;
      }
      
      // Return user profile immediately — session persists in background
      res.json({
        user,
        expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(), // 24 hours
      });
    } catch (error: any) {
      console.error("[Auth Login] Error:", error);

      // Validation error (missing/malformed request body)
      if (error?.issues || error instanceof z.ZodError) {
        return res.status(400).json({
          message: "Invalid request: idToken is required.",
          error: "VALIDATION_ERROR",
        });
      }
      
      // Check if this is a configuration/service error
      if (error.message?.includes("Authentication service unavailable")) {
        return res.status(503).json({ 
          message: "Authentication service is currently unavailable. Please contact support.",
          error: "SERVICE_UNAVAILABLE",
          details: error.message,
        });
      }
      
      // Check if this is an invalid/expired token — record the failure
      if (error.message?.includes("Invalid or expired") || error.code === "auth/id-token-expired" || error.code === "auth/argument-error") {
        // Never record failures or lock out exempt (super-admin) emails
        const { locked, remaining } = isExempt ? { locked: false, remaining: 0 } : recordLoginFailure(ip);
        logSecurityEvent({
          type: "auth_failure",
          severity: locked ? "high" : "medium",
          ip,
          path: req.path,
          method: req.method,
          message: locked
            ? `IP locked after repeated failed login attempts (${LOCKOUT_MAX_FAILURES} failures).`
            : `Failed login attempt from ${ip}. Error: ${error.message}`,
          metadata: { userAgent: req.headers["user-agent"], errorCode: error.code },
        });
        if (locked) {
          return res.status(429).json({
            message: `Too many failed attempts. Account locked for ${Math.ceil(remaining / 60)} minute(s).`,
            error: "ACCOUNT_LOCKED",
            retryAfter: remaining,
          });
        }
        return res.status(401).json({ 
          message: "Invalid credentials. Please try logging in again.",
          error: "INVALID_TOKEN",
        });
      }
      
      // Generic error
      res.status(500).json({ 
        message: "Login failed. Please try again.",
        error: error.message,
      });
    }
  });
  
