  app.get("/api/users", async (req: Request, res: Response) => {
    try {
      const role = req.query.role as string | undefined;
      const includeHidden = req.query.includeHidden === 'true';
      let users;

      if (role) {
        users = await storage.getUsersByRole(role);
      } else {
        users = await storage.getAllUsers();
      }

      // Check if current user is admin - only admins see hidden artists
      const currentUser = await getCurrentUser(req);
      const isAdmin = isAdminRole(currentUser?.role);
      
      // Filter hidden artists for non-admins (unless includeHidden=true and is admin)
      if (!isAdmin || !includeHidden) {
        users = users.filter((u: any) => !u.isHiddenInCommunity);
      }

      res.json(users);
    } catch (error) {
      res.status(500).json({ message: "Failed to fetch users" });
    }
  });

