  // ── Trending Tags (public) ─────────────────────────────────────────────────
  app.get("/api/community/trending-tags", async (req: Request, res: Response) => {
    try {
      const allPosts = await db.select({ content: posts.content }).from(posts).orderBy(desc(posts.createdAt)).limit(500);
      const tagCounts: Record<string, number> = {};
      const hashtagRegex = /#[\w]+/g;
      for (const post of allPosts) {
        if (!post.content) continue;
        const matches = post.content.match(hashtagRegex);
        if (!matches) continue;
        for (const tag of matches) {
          const normalized = tag.toLowerCase();
          tagCounts[normalized] = (tagCounts[normalized] || 0) + 1;
        }
      }
      const sorted = Object.entries(tagCounts)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 10)
        .map(([tag, count]) => ({ tag, count }));
      res.json(sorted);
    } catch (error) {
      console.error("Error fetching trending tags:", error);
      res.status(500).json({ message: "Failed to fetch trending tags" });
    }
  });

