  // ── Admin: Spotlight a user-submitted location ────────────────────────────
  // Returns the new spotlightedPlaces id so the frontend knows the entry exists
  app.post("/api/admin/locations/:id/spotlight", async (req: Request, res: Response) => {
    try {
      const user = await getCurrentUser(req);
      if (!user || !["admin", "super_admin"].includes(user.role)) return res.status(403).json({ message: "Admin access required" });

      const locationId = parseInt(req.params.id);
      const loc = await storage.getLocation(locationId);
      if (!loc) return res.status(404).json({ message: "Location not found" });
      if (loc.approvalStatus !== "approved") return res.status(400).json({ message: "Only approved locations can be spotlighted" });

      // Check if already spotlighted
      const [existing] = await db.select().from(spotlightedPlaces).where(eq(spotlightedPlaces.linkedLocationId, locationId));
      if (existing) return res.json(existing);

      // Map location type → spotlight category
      const categoryMap: Record<string, string> = {
        dance: "dance", graffiti: "graffiti", skate: "skate", training: "training",
        music: "music", basketball: "basketball", parkour: "parkour", art: "art",
        cafe: "cafe", gym: "gym", studio: "studio",
      };
      const category = categoryMap[loc.type ?? ""] ?? loc.type ?? "other";

      const lat = parseFloat(loc.latitude ?? "0");
      const lon = parseFloat(loc.longitude ?? "0");
      if (!lat || !lon) return res.status(400).json({ message: "Location has no valid coordinates" });

      const [spotlight] = await db.insert(spotlightedPlaces).values({
        name: loc.name,
        lat,
        lon,
        category,
        address: loc.address ?? null,
        website: loc.website ?? null,
        adminNote: req.body.adminNote ?? null,
        active: true,
        isSuperFeatured: req.body.isSuperFeatured ?? false,
        linkedLocationId: locationId,
      }).returning();

      // Bust spotlight caches
      spotlightsCache.del("public");
      adminSpotlightsCache.del("all");

      res.status(201).json(spotlight);
    } catch (error) {
      console.error("Spotlight error:", error);
      res.status(500).json({ message: "Failed to spotlight location" });
    }
  });

