  app.post("/api/locations", async (req: Request, res: Response) => {
    try {
      console.log("Creating location with data:", JSON.stringify(req.body, null, 2));
      const creator = await getCurrentUser(req);
      const isAdmin = creator?.role === "admin" || creator?.role === "super_admin";

      // Any logged-in user can submit — admins get auto-approved, others go pending
      if (!creator) return res.status(401).json({ message: "Authentication required" });

      const bodyData = { ...req.body };
      // Admin spots are auto-approved; others go to pending
      if (isAdmin) {
        bodyData.approvalStatus = "approved";
        bodyData.isVisible = true;
        bodyData.approvedBy = creator.id;
      } else {
        bodyData.approvalStatus = "pending";
      }
      if (creator) bodyData.createdBy = creator.id;

      const locationData = insertLocationSchema.parse(bodyData);
      console.log("Validated location data:", JSON.stringify(locationData, null, 2));
      const location = await storage.createLocation(locationData);
      console.log("Created location:", location.id);
      
      // Send real-time notification about the new spot/location
      try {
        // notifySpotAdded is already imported at the top of the file
        notifySpotAdded(
          location,
          location.createdBy || 0
        );
        console.log(`Sent spot added notification for spot: ${location.id}`);
      } catch (notifyError) {
        console.error("Failed to send spot added notification:", notifyError);
        // Don't fail the request if notification sending fails
      }
      
      res.status(201).json(location);
    } catch (error) {
      console.error("Error creating location:", error);
      if (error instanceof z.ZodError) {
        console.error("Validation errors:", JSON.stringify(error.errors, null, 2));
        return res.status(400).json({ message: "Invalid location data", errors: error.errors });
      }
      res.status(500).json({ message: "Failed to create location", error: String(error) });
    }
  });
  
  // Update a location (spot) - admin or creator can update
  app.patch("/api/locations/:id", async (req: Request, res: Response) => {
    try {
      const locationId = parseInt(req.params.id);
      const locationData = req.body;
      
      // Get the current user
      const user = await getCurrentUser(req);
      
      // Check if location exists
      const existingLocation = await storage.getLocation(locationId);
      if (!existingLocation) {
        return res.status(404).json({ message: "Location not found" });
      }
      
      // Check if user has permission (admin or creator)
      const isAdmin = user?.role === 'admin' || user?.role === 'super_admin';
      const isCreator = user && existingLocation.createdBy === user.id;
      
      if (!isAdmin && !isCreator) {
        return res.status(403).json({ message: "You don't have permission to edit this spot" });
      }
      
      // Update the location
      const updatedLocation = await storage.updateLocation(locationId, locationData);
      
      // Send real-time notification about the updated spot/location
      try {
        notifySpotUpdated(
          updatedLocation,
          user?.id || existingLocation.createdBy || 0
        );
        console.log(`Sent spot updated notification for spot: ${updatedLocation.id}`);
      } catch (notifyError) {
        console.error("Failed to send spot updated notification:", notifyError);
      }
      
      res.json(updatedLocation);
    } catch (error) {
      console.error("Error updating location:", error);
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid location data", errors: error.errors });
      }
      res.status(500).json({ message: "Failed to update location" });
    }
  });
  
