  // Endpoint for current user's saved locations (includes OSM spot rows)
  app.get("/api/users/saved-locations", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      if (!userId) return res.json([]);
      const uid = typeof userId === 'string' ? parseInt(userId) : Number(userId);
      if (isNaN(uid)) return res.json([]);

      // Use raw SQL only — avoids Drizzle ORM schema mismatch with extra osm_ columns
      let rows: any[] = [];
      try {
        const result = await db.execute(sql.raw(
          `SELECT
             sl.id,
             sl.osm_id AS "osmId",
             sl.osm_name AS "osmName",
             sl.osm_category AS "osmCategory",
             sl.osm_lat AS "osmLat",
             sl.osm_lon AS "osmLon",
             sl.osm_address AS "osmAddress",
             sl.location_id AS "locationId",
             l.name AS "locationName",
             l.description AS "locationDescription"
           FROM saved_locations sl
           LEFT JOIN locations l ON l.id = sl.location_id
           WHERE sl.user_id = ${uid}
           ORDER BY sl.id DESC`
        )) as any;
        rows = result?.rows ?? [];
      } catch (queryErr: any) {
        // If osm columns don't exist yet, fall back to location-only query
        console.error("[SAVED-LOCATIONS] Full query failed, trying fallback:", queryErr?.message);
        try {
          const fallback = await db.execute(sql.raw(
            `SELECT sl.id, sl.location_id AS "locationId", l.name AS "locationName"
             FROM saved_locations sl
             LEFT JOIN locations l ON l.id = sl.location_id
             WHERE sl.user_id = ${uid}
             ORDER BY sl.id DESC`
          )) as any;
          rows = fallback?.rows ?? [];
        } catch (fb: any) {
          console.error("[SAVED-LOCATIONS] Fallback also failed:", fb?.message);
        }
      }

      res.json(rows);
    } catch (error: any) {
      console.error("[SAVED-LOCATIONS-ERROR]", error?.message, error?.stack);
      res.status(500).json({ message: "Failed to fetch saved locations" });
    }
  });

  app.post("/api/saved-locations", async (req: Request, res: Response) => {
    try {
      // Verify Firebase token if provided
      const authHeader = req.headers.authorization;
      if (!authHeader) {
        console.warn("No auth header provided for saving location");
        return res.status(401).json({ 
          message: "Authentication required",
          details: "No authorization header was provided" 
        });
      }
      
      try {
        if (!authHeader.startsWith('Bearer ')) {
          return res.status(401).json({ 
            message: "Invalid authorization format",
            details: "Authorization header must use Bearer format" 
          });
        }
        
        const token = authHeader.split('Bearer ')[1];
        if (!token) {
          return res.status(401).json({ 
            message: "Invalid token",
            details: "Token is empty or malformed" 
          });
        }
        
        // Import the firebase verification function
        const { verifyFirebaseToken } = await import('./firebase');
        
        console.log("Attempting to verify token for saved location");
        const decodedToken = await verifyFirebaseToken(token);
        
        if (!decodedToken.uid) {
          return res.status(401).json({ 
            message: "Unauthorized", 
            details: "Token verification succeeded but no user ID was found"
          });
        }
        
        console.log("Token verified, looking up user with Firebase UID:", decodedToken.uid);
        
        // Get user by firebase UID
        const user = await storage.getUserByFirebaseUid(decodedToken.uid);
        
        if (!user) {
          return res.status(404).json({ 
            message: "User not found",
            details: "No user found with the Firebase UID from the token" 
          });
        }
        
        console.log("User found:", user.id);
        
        // Ensure the userId in the request matches the authenticated user
        if (user.id !== req.body.userId) {
          return res.status(403).json({ 
            message: "Unauthorized: User ID mismatch",
            details: `Token user ID (${user.id}) does not match request user ID (${req.body.userId})`
          });
        }
      } catch (verifyError: any) {
        console.error("Token verification error:", verifyError);
        return res.status(401).json({ 
          message: "Invalid token", 
          details: verifyError.message || "Token verification failed"
        });
      }
      
      const savedLocationData = insertSavedLocationSchema.parse(req.body);
      const savedLocation = await storage.saveLocation(savedLocationData);
      res.status(201).json(savedLocation);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid saved location data", errors: error.errors });
      }
      console.error("Error saving location:", error);
      res.status(500).json({ message: "Failed to save location" });
    }
  });

  // ── City Spot Save / Unsave (OSM spots) ────────────────────────────────────
  app.post("/api/city-spots/:osmId/save", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      if (!userId) return res.status(401).json({ message: "Authentication required" });
      const osmId = req.params.osmId; // keep as string for SQL safety
      const { name, category, lat, lon, address } = req.body;
      const uid = typeof userId === 'string' ? parseInt(userId) : userId;
      const osmIdNum = parseInt(osmId);
      if (isNaN(osmIdNum)) return res.status(400).json({ message: "Invalid OSM ID" });

      const safeName = name ? `'${String(name).replace(/'/g, "''")}'` : 'NULL';
      const safeCategory = category ? `'${String(category).replace(/'/g, "''")}'` : 'NULL';
      const safeLat = lat != null && !isNaN(parseFloat(lat)) ? parseFloat(lat) : 'NULL';
      const safeLon = lon != null && !isNaN(parseFloat(lon)) ? parseFloat(lon) : 'NULL';
      const safeAddress = address ? `'${String(address).replace(/'/g, "''")}'` : 'NULL';

      // Ensure columns exist (in case migration hasn't run on this DB yet)
      try {
        await db.execute(sql.raw(`ALTER TABLE saved_locations ADD COLUMN IF NOT EXISTS osm_id BIGINT`));
        await db.execute(sql.raw(`ALTER TABLE saved_locations ADD COLUMN IF NOT EXISTS osm_name TEXT`));
        await db.execute(sql.raw(`ALTER TABLE saved_locations ADD COLUMN IF NOT EXISTS osm_category TEXT`));
        await db.execute(sql.raw(`ALTER TABLE saved_locations ADD COLUMN IF NOT EXISTS osm_lat DOUBLE PRECISION`));
        await db.execute(sql.raw(`ALTER TABLE saved_locations ADD COLUMN IF NOT EXISTS osm_lon DOUBLE PRECISION`));
        await db.execute(sql.raw(`ALTER TABLE saved_locations ADD COLUMN IF NOT EXISTS osm_address TEXT`));
      } catch (_) { /* columns already exist — ignore */ }

      // Check if already saved
      const checkResult = await db.execute(sql.raw(
        `SELECT id FROM saved_locations WHERE user_id = ${uid} AND osm_id = ${osmIdNum} LIMIT 1`
      )) as any;
      const checkRows = checkResult?.rows ?? [];
      if (checkRows.length > 0) return res.json({ saved: true, id: checkRows[0].id });

      const insertResult = await db.execute(sql.raw(
        `INSERT INTO saved_locations (user_id, osm_id, osm_name, osm_category, osm_lat, osm_lon, osm_address)
         VALUES (${uid}, ${osmIdNum}, ${safeName}, ${safeCategory}, ${safeLat}, ${safeLon}, ${safeAddress})
         RETURNING id`
      )) as any;
      const insertedId = (insertResult?.rows ?? [])[0]?.id ?? null;
      res.status(201).json({ saved: true, id: insertedId });
    } catch (error: any) {
      console.error("Save city spot error:", error?.message ?? error);
      res.status(500).json({ message: "Failed to save spot", detail: error?.message });
    }
  });

