  app.get("/api/events/map", async (req: Request, res: Response) => {
    try {
      const cached = mapEventsCache.get("map_approved");
      if (cached) {
        res.setHeader("Cache-Control", "public, max-age=900"); // 15 min browser cache
        return res.json(cached);
      }
      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      const rows = await db.select({
        id: events.id,
        title: events.title,
        titleEn: events.titleEn,
        location: events.location,
        city: events.city,
        category: events.category,
        latitude: events.latitude,
        longitude: events.longitude,
        date: events.date,
        endDate: events.endDate,
        image: events.image,
        isFeatured: events.isFeatured,
        isTrending: events.isTrending,
        priceModel: events.priceModel,
        price: events.price,
        status: events.status,
      }).from(events)
        .where(and(
          eq(events.status, "approved"),
          isNotNull(events.latitude),
          isNotNull(events.longitude),
          ne(events.latitude, ""),
          ne(events.longitude, ""),
          gte(events.date, thirtyDaysAgo)
        ))
        .orderBy(asc(events.date));
      mapEventsCache.set("map_approved", rows);
      res.setHeader("Cache-Control", "public, max-age=900");
      res.json(rows);
    } catch (error) {
      res.status(500).json({ message: "Failed to fetch map events" });
    }
  });

