  app.get("/api/admin/competitions/stats", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const userRole = (req as any).user?.role;
      if (userRole !== 'admin' && userRole !== 'super_admin') {
        return res.status(403).json({ message: "Admin access required" });
      }
      const allComps = await db.select().from(events).where(eq(events.isCompetition, true));
      const allCats = await db.select().from(eventCategories);
      const allMatchups = await db.select().from(battleMatchups);
      const allVotes = await db.select().from(battleVotes);
      const allJudges = await db.select().from(battleJudges);
      const allRegs = await db.select().from(dancerRegistrations);

      const sportBreakdown = allCats.reduce((acc: Record<string, number>, cat) => {
        const s = cat.competitionSport || 'BREAKING';
        acc[s] = (acc[s] || 0) + 1;
        return acc;
      }, {});

      const compsWithStats = await Promise.all(allComps.map(async (comp) => {
        const cats = allCats.filter(c => c.eventId === comp.id);
        const compMatchups = allMatchups.filter(m => m.eventId === comp.id);
        const compRegs = allRegs.filter(r => r.eventId === comp.id);
        const compJudges = allJudges.filter(j => j.eventId === comp.id);
        const compVotes = allVotes.filter(v => compMatchups.some(m => m.id === v.matchupId));
        return {
          ...comp,
          categories: cats,
          stats: {
            categoryCount: cats.length,
            participantCount: compRegs.length,
            matchupCount: compMatchups.length,
            completedMatchups: compMatchups.filter(m => m.status === 'COMPLETED').length,
            judgeCount: compJudges.length,
            voteCount: compVotes.length,
          }
        };
      }));

      res.json({
        totalCompetitions: allComps.length,
        totalParticipants: allRegs.length,
        totalMatchups: allMatchups.length,
        totalJudges: allJudges.length,
        sportBreakdown,
        competitions: compsWithStats,
      });
    } catch (error) {
      console.error("Error fetching competition stats:", error);
      res.status(500).json({ message: "Failed to fetch competition stats" });
    }
  });

