  app.get("/api/events", async (req: Request, res: Response) => {
    try {
      const { category, city, priceModel, kidFriendly, familyFriendly, isIndoor, isFeatured, isTrending, mood, search, sortBy, dateFrom, dateTo, showAll } = req.query;

      // Resolve current user id from all possible sources
      const userId = parseInt((req as any).user?.id ||
                     req.headers['x-user-id'] as string ||
                     req.query.userId as string ||
                     (req.session as any)?.userId) || null;

      // showAll=true is for admin to see all events regardless of status
      if (showAll === "true") {
        const allEvents = await storage.getAllEvents();
        return res.json(allEvents);
      }

      const hasFilters = category || city || priceModel || kidFriendly || familyFriendly || isIndoor || isFeatured || isTrending || mood || search || sortBy || dateFrom || dateTo;

      // Cache key uses filters but NOT userId — base list is always the same approved events
      const cacheKey = !hasFilters ? "approved_upcoming" : `filtered:${JSON.stringify({ category, city, priceModel, kidFriendly, familyFriendly, isIndoor, isFeatured, isTrending, search, sortBy, dateFrom, dateTo })}`;

      let events: any[] = (eventsCache.get(cacheKey) as any[]) || [];

      if (!events || events.length === 0) {
        const rawEvents = await storage.getFilteredEvents({
          category: category as string,
          city: city as string,
          priceModel: priceModel as any,
          kidFriendly: kidFriendly === "true",
          familyFriendly: familyFriendly === "true",
          isIndoor: isIndoor !== undefined ? isIndoor === "true" : undefined,
          isFeatured: isFeatured === "true",
          isTrending: isTrending === "true",
          search: search as string,
          sortBy: sortBy as any,
          dateFrom: dateFrom ? new Date(dateFrom as string) : new Date(),
          dateTo: dateTo ? new Date(dateTo as string) : undefined,
        });
        // Strip heavy description fields from the list view — detail page fetches full event
        events = rawEvents.map(({ description, descriptionEn, ...rest }: any) => rest);
        eventsCache.set(cacheKey, events);
      }

      // Merge in the current user's own pending events so they can see what they submitted
      if (userId) {
        try {
          const [userBlocks, userOwnEvents] = await Promise.all([
            storage.getUserBlocksByBlocker(userId),
            storage.getEventsByUser(userId),
          ]);

          let result = [...events];

          // Apply block filter
          const blockedUserIds = new Set(userBlocks.map((b: any) => b.blockedId));
          if (blockedUserIds.size > 0) {
            result = result.filter((e: any) => !blockedUserIds.has(e.organizerId));
          }

          // Append user's own pending events that aren't already in the list
          const existingIds = new Set(result.map((e: any) => e.id));
          const pendingOwn = userOwnEvents.filter((e: any) => e.status === "pending" && !existingIds.has(e.id));
          if (pendingOwn.length > 0) {
            result = [...result, ...pendingOwn];
          }

          return res.json(result);
        } catch (_) {}
      }

      res.json(events);
    } catch (error) {
      console.error("[GET /api/events] Error fetching events:", error);
      res.status(500).json({ message: "Failed to fetch events" });
    }
  });

