  app.post("/api/events", requireAuth, async (req: Request, res: Response) => {
    try {
      const eventData = insertEventSchema.parse(req.body);

      // Admin/super_admin created events are auto-approved — but respect explicit status from payload
      const creatorRole = (req as any).user?.role;
      const isAdmin = creatorRole === "admin" || creatorRole === "super_admin";
      if (isAdmin && !req.body.status) {
        (eventData as any).status = "approved";
      } else if (isAdmin && req.body.status) {
        (eventData as any).status = req.body.status;
      } else {
        (eventData as any).status = "pending";
      }

      const event = await storage.createEvent(eventData);
      // Flush all cached event keys so the new event appears immediately
      eventsCache.flushAll();
      mapEventsCache.del("map_approved");

      res.status(201).json(event);
    } catch (error) {
      console.error("Event creation error:", error);
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid event data", errors: error.errors });
      }
      res.status(500).json({ message: "Failed to create event" });
    }
  });

