  // Update an event (for users to edit their own events or admins to edit any event)
  app.patch("/api/events/:id", async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.id);
      
      // Get user ID and role from multiple sources (session, headers, query params)
      let userId = (req as any).user?.id;
      let userRole = (req as any).user?.role;
      
      // Check headers for auth info
      const headerUserId = req.headers['x-user-id'];
      const headerUserRole = req.headers['x-user-role'];
      
      // Check query params for auth info
      const queryUserId = req.query.userId;
      const queryUserRole = req.query.userRole;
      
      // Use the first available source
      if (!userId && headerUserId) {
        userId = parseInt(headerUserId as string);
      }
      if (!userId && queryUserId) {
        userId = parseInt(queryUserId as string);
      }
      
      if (!userRole && headerUserRole) {
        userRole = headerUserRole as string;
      }
      if (!userRole && queryUserRole) {
        userRole = queryUserRole as string;
      }
      
      console.log("Event update auth data:", { 
        userId, 
        userRole, 
        headerUserId, 
        headerUserRole,
        queryUserId,
        queryUserRole
      });
      
      const eventData = req.body;
      
      // First check if event exists
      const existingEvent = await storage.getEvent(eventId);
      
      if (!existingEvent) {
        return res.status(404).json({ message: "Event not found" });
      }
      
      // Allow admins to edit any event, but restrict other users to their own events
      if (userRole !== 'admin' && existingEvent.organizerId !== userId) {
        return res.status(403).json({ 
          message: "You don't have permission to edit this event",
          details: {
            userRole,
            userId,
            organizerId: existingEvent.organizerId
          }
        });
      }
      
      const updatedEvent = await storage.updateEvent(eventId, eventData);
      
      if (!updatedEvent) {
        return res.status(404).json({ message: "Event not found" });
      }
      
      eventsCache.flushAll();
      res.json(updatedEvent);
    } catch (error) {
      console.error("Error updating event:", error);
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid event data", errors: error.errors });
      }
      res.status(500).json({ message: "Failed to update event" });
    }
  });
  
  // Delete an event (for users to delete their own events)
  app.delete("/api/events/:id", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.id);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;
      
      // First check if event exists
      const existingEvent = await storage.getEvent(eventId);
      
      if (!existingEvent) {
        return res.status(404).json({ message: "Event not found" });
      }
      
      // Allow admins or the event organizer to delete the event
      if (existingEvent.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to delete this event" });
      }
      
      const deleted = await storage.deleteEvent(eventId);
      
      if (!deleted) {
        return res.status(404).json({ message: "Event not found or could not be deleted" });
      }
      
      eventsCache.flushAll();
      res.json({ message: "Event deleted successfully" });
    } catch (error) {
      console.error("Error deleting event:", error);
      res.status(500).json({ message: "Failed to delete event" });
    }
  });

