      // Map form-friendly field names to schema field names
      const bodyMappedU = {
        ...req.body,
        maxDancers: req.body.maxDancers ?? req.body.maxParticipants,
        battleRules: req.body.battleRules ?? req.body.description,
      };
      delete bodyMappedU.maxParticipants;
      delete bodyMappedU.description;

