  app.delete("/api/events/:eventId/categories/:id", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const categoryId = parseInt(req.params.id);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Verify event exists and user has permission
      const event = await storage.getEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      const isAdminUserD = ['admin', 'super_admin'].includes(userRole || '');
      if (event.organizerId !== userId && !isAdminUserD) {
        return res.status(403).json({ message: "You don't have permission to delete categories for this event" });
      }

      // Delete in order of foreign key dependencies:
      
      // 1. Delete all votes for matchups in this category
      const categoryMatchups = await db.select({ id: battleMatchups.id })
        .from(battleMatchups)
        .where(eq(battleMatchups.categoryId, categoryId));
      
      for (const matchup of categoryMatchups) {
        await db.delete(battleVotes).where(eq(battleVotes.matchupId, matchup.id));
      }
      
      // 2. Delete all matchups for this category
      await db.delete(battleMatchups)
        .where(eq(battleMatchups.categoryId, categoryId));

      // 3. Delete all judges for this category
      await db.delete(battleJudges)
        .where(eq(battleJudges.categoryId, categoryId));

      // 4. Delete all registrations for this category
      await db.delete(dancerRegistrations)
        .where(eq(dancerRegistrations.categoryId, categoryId));

      // 5. Now delete the category
      const [deletedCategory] = await db
        .delete(eventCategories)
        .where(and(eq(eventCategories.id, categoryId), eq(eventCategories.eventId, eventId)))
        .returning();

      if (!deletedCategory) {
        return res.status(404).json({ message: "Category not found" });
      }

      res.json({ message: "Category deleted successfully" });
    } catch (error) {
      console.error("Error deleting event category:", error);
      res.status(500).json({ message: "Failed to delete event category" });
    }
  });

