  app.post("/api/events/:eventId/categories/:categoryId/register", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const categoryId = parseInt(req.params.categoryId);
      const userId = (req as any).user?.id;

      if (!userId) {
        return res.status(401).json({ message: "Authentication required" });
      }

      // Get category details
      const [category] = await db.select().from(eventCategories).where(eq(eventCategories.id, categoryId));
      if (!category || category.eventId !== eventId) {
        return res.status(404).json({ message: "Category not found" });
      }

      // Check if user already registered for this category
      const [existingReg] = await db
        .select()
        .from(dancerRegistrations)
        .where(and(
          eq(dancerRegistrations.categoryId, categoryId),
          eq(dancerRegistrations.userId, userId)
        ));

      if (existingReg) {
        return res.status(409).json({ message: "Already registered for this category" });
      }

      // Check capacity if defined
      if (category.maxParticipants) {
        const currentCount = await db
          .select({ count: sql<number>`count(*)` })
          .from(dancerRegistrations)
          .where(eq(dancerRegistrations.categoryId, categoryId));
        
        if (currentCount[0].count >= category.maxParticipants) {
          return res.status(400).json({ message: "Category is full" });
        }
      }

      // Determine payment status based on registration mode
      let paymentStatus = 'NOT_REQUIRED';
      let status = 'CONFIRMED';

      if (category.registrationMode === 'PAID' && category.registrationFee && category.registrationFee > 0) {
        paymentStatus = 'PENDING';
        status = 'PENDING_PAYMENT';
      } else if (category.registrationMode === 'RESERVATION_ONLY') {
        status = 'CONFIRMED';
      }

      // Create registration
      const registrationData = {
        eventId,
        categoryId,
        userId,
        paymentStatus,
        status,
        seedingIndex: req.body.seedingIndex || null
      };

      const [registration] = await db
        .insert(dancerRegistrations)
        .values(registrationData)
        .returning();

      res.status(201).json(registration);
    } catch (error) {
      console.error("Error creating registration:", error);
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid registration data", errors: error.errors });
      }
      res.status(500).json({ message: "Failed to create registration" });
    }
  });

