  // Admin: Update matchup (edit dancers, notes, bestOf, etc.)
  app.patch("/api/matchups/:id", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const matchupId = parseInt(req.params.id);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Get matchup
      const [matchup] = await db.select().from(battleMatchups).where(eq(battleMatchups.id, matchupId));
      if (!matchup) {
        return res.status(404).json({ message: "Matchup not found" });
      }

      // Verify user has permission
      const event = await storage.getEvent(matchup.eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to update matchups" });
      }

      // Validate request body with Zod
      const parseResult = updateMatchupSchema.safeParse(req.body);
      if (!parseResult.success) {
        return res.status(400).json({ 
          message: "Validation failed", 
          errors: parseResult.error.flatten().fieldErrors 
        });
      }

      const { dancerARegistrationId, dancerBRegistrationId, notes, scheduledTime, status, bestOf, winnerRegistrationId } = parseResult.data;

      const updateData: any = { updatedAt: new Date() };
      
      // Handle standard matchup fields
      if (dancerARegistrationId !== undefined) updateData.dancerARegistrationId = dancerARegistrationId;
      if (dancerBRegistrationId !== undefined) updateData.dancerBRegistrationId = dancerBRegistrationId;
      if (notes !== undefined) updateData.notes = notes;
      if (scheduledTime !== undefined) updateData.scheduledTime = scheduledTime ? new Date(scheduledTime) : null;
      
      // Check if this is a multi-round battle with judge voting - prevent manual completion
      if ((status === 'COMPLETED' || winnerRegistrationId !== undefined) && (matchup.bestOf || 1) > 1) {
        // Get the category to check if judge voting is enabled
        const [category] = await db
          .select()
          .from(eventCategories)
          .where(eq(eventCategories.id, matchup.categoryId));
        
        if (category?.useJudgeVoting) {
          return res.status(400).json({ 
            message: `This is a best-of-${matchup.bestOf} battle with judge voting. Complete it through the voting system instead of manual selection.` 
          });
        }
      }
      
      if (status !== undefined) updateData.status = status;
      if (winnerRegistrationId !== undefined) updateData.winnerRegistrationId = winnerRegistrationId;
      
      // Handle bestOf field with additional runtime validation for round wins
      if (bestOf !== undefined) {
        // Check if bestOf can be changed (can't reduce below current round wins)
        const roundsNeededToWin = Math.ceil(bestOf / 2);
        const currentMaxWins = Math.max(matchup.dancerARoundWins || 0, matchup.dancerBRoundWins || 0);
        
        if (currentMaxWins >= roundsNeededToWin) {
          return res.status(400).json({ 
            message: `Cannot set best of ${bestOf} - a dancer already has ${currentMaxWins} round wins. The matchup would already be decided.` 
          });
        }
        
        updateData.bestOf = bestOf;
      }

      if (Object.keys(updateData).length === 1) { // Only has updatedAt
        return res.status(400).json({ message: "No valid fields to update" });
      }

      const [updatedMatchup] = await db
        .update(battleMatchups)
        .set(updateData)
        .where(eq(battleMatchups.id, matchupId))
        .returning();

      res.json(updatedMatchup);
    } catch (error) {
      console.error("Error updating matchup:", error);
      res.status(500).json({ message: "Failed to update matchup" });
    }
  });

  // Admin: Delete matchup
  app.delete("/api/matchups/:id", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const matchupId = parseInt(req.params.id);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Get matchup
      const [matchup] = await db.select().from(battleMatchups).where(eq(battleMatchups.id, matchupId));
      if (!matchup) {
        return res.status(404).json({ message: "Matchup not found" });
      }

      // Verify user has permission
      const event = await storage.getEvent(matchup.eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to delete matchups" });
      }

      await db.delete(battleMatchups).where(eq(battleMatchups.id, matchupId));

      res.json({ message: "Matchup deleted successfully" });
    } catch (error) {
      console.error("Error deleting matchup:", error);
      res.status(500).json({ message: "Failed to delete matchup" });
    }
  });

  // Admin: Remove dancer from battle
  app.delete("/api/events/:eventId/categories/:categoryId/registrations/:registrationId", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const registrationId = parseInt(req.params.registrationId);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Verify event exists and user has permission
      const event = await storage.getEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to remove dancers" });
      }

      // Check registration exists
      const [registration] = await db.select().from(dancerRegistrations).where(eq(dancerRegistrations.id, registrationId));
      if (!registration) {
        return res.status(404).json({ message: "Registration not found" });
      }

      // Remove from any matchups first
      await db.update(battleMatchups)
        .set({ dancerARegistrationId: null })
        .where(eq(battleMatchups.dancerARegistrationId, registrationId));
      
      await db.update(battleMatchups)
        .set({ dancerBRegistrationId: null })
        .where(eq(battleMatchups.dancerBRegistrationId, registrationId));

      // Delete the registration
      await db.delete(dancerRegistrations).where(eq(dancerRegistrations.id, registrationId));

      res.json({ message: "Dancer removed successfully" });
    } catch (error) {
      console.error("Error removing dancer:", error);
      res.status(500).json({ message: "Failed to remove dancer" });
    }
  });

  // ============ JUDGE MANAGEMENT & LIVE VOTING ROUTES ============

  // Get judges for a category
  app.get("/api/events/:eventId/categories/:categoryId/judges", async (req: Request, res: Response) => {
    try {
      const categoryId = parseInt(req.params.categoryId);
      
      const judgesData = await db
        .select({
          id: battleJudges.id,
          eventId: battleJudges.eventId,
          categoryId: battleJudges.categoryId,
          userId: battleJudges.userId,
          judgeNumber: battleJudges.judgeNumber,
          isActive: battleJudges.isActive,
          assignedAt: battleJudges.assignedAt,
          userEmail: users.email,
          userProfileImage: users.profilePicture,
          userDisplayName: users.displayName,
          userIdJoin: users.id
        })
        .from(battleJudges)
        .leftJoin(users, eq(battleJudges.userId, users.id))
        .where(and(
          eq(battleJudges.categoryId, categoryId),
          eq(battleJudges.isActive, true)
        ))
        .orderBy(battleJudges.judgeNumber);

      // Format response with nested user object
      const judges = judgesData.map(j => ({
        id: j.id,
        eventId: j.eventId,
        categoryId: j.categoryId,
        userId: j.userId,
        judgeNumber: j.judgeNumber,
        isActive: j.isActive,
        assignedAt: j.assignedAt,
        user: j.userIdJoin ? {
          id: j.userIdJoin,
          username: j.userEmail,
          profileImage: j.userProfileImage,
          displayName: j.userDisplayName
        } : null
      }));

      res.json(judges);
    } catch (error) {
      console.error("Error fetching judges:", error);
      res.status(500).json({ message: "Failed to fetch judges" });
    }
  });

  // Assign a judge to a category
  app.post("/api/events/:eventId/categories/:categoryId/judges", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const categoryId = parseInt(req.params.categoryId);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Verify event exists and user has permission
      const event = await storage.getEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to assign judges" });
      }

      const { targetUserId } = req.body;
      if (!targetUserId) {
        return res.status(400).json({ message: "User ID is required" });
      }

      // Check if user exists
      const targetUser = await storage.getUser(targetUserId);
      if (!targetUser) {
        return res.status(404).json({ message: "User not found" });
      }

      // Check if user is already a judge for this category
      const [existingJudge] = await db
        .select()
        .from(battleJudges)
        .where(and(
          eq(battleJudges.categoryId, categoryId),
          eq(battleJudges.userId, targetUserId),
          eq(battleJudges.isActive, true)
        ));

      if (existingJudge) {
        return res.status(409).json({ message: "User is already a judge for this category" });
      }

      // Get the next judge number
      const [maxJudge] = await db
        .select({ maxNumber: sql<number>`MAX(${battleJudges.judgeNumber})` })
        .from(battleJudges)
        .where(and(
          eq(battleJudges.categoryId, categoryId),
          eq(battleJudges.isActive, true)
        ));

      const nextJudgeNumber = (maxJudge?.maxNumber || 0) + 1;

      // Create the judge assignment
      const [newJudge] = await db.insert(battleJudges).values({
        eventId,
        categoryId,
        userId: targetUserId,
        judgeNumber: nextJudgeNumber,
        isActive: true,
        assignedByUserId: userId
      }).returning();

      // Return judge with user info
      const judgeWithUser = {
        ...newJudge,
        user: {
          id: targetUser.id,
          username: targetUser.username,
          profileImage: targetUser.profileImage,
          displayName: targetUser.displayName
        }
      };

      res.status(201).json(judgeWithUser);
    } catch (error) {
      console.error("Error assigning judge:", error);
      res.status(500).json({ message: "Failed to assign judge" });
    }
  });

  // Remove a judge from a category
  app.delete("/api/events/:eventId/categories/:categoryId/judges/:judgeId", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const judgeId = parseInt(req.params.judgeId);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Verify event exists and user has permission
      const event = await storage.getEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to remove judges" });
      }

      // Soft delete by setting isActive to false
      await db
        .update(battleJudges)
        .set({ isActive: false })
        .where(eq(battleJudges.id, judgeId));

      res.json({ message: "Judge removed successfully" });
    } catch (error) {
      console.error("Error removing judge:", error);
      res.status(500).json({ message: "Failed to remove judge" });
    }
  });

  // Get votes for a matchup (optionally filter by round)
  app.get("/api/matchups/:matchupId/votes", async (req: Request, res: Response) => {
    try {
      const matchupId = parseInt(req.params.matchupId);
      const roundNumber = req.query.round ? parseInt(req.query.round as string) : null;

      let query = db
        .select({
          id: battleVotes.id,
          matchupId: battleVotes.matchupId,
          roundNumber: battleVotes.roundNumber,
          judgeId: battleVotes.judgeId,
          judgeUserId: battleVotes.judgeUserId,
          votedForRegistrationId: battleVotes.votedForRegistrationId,
          votedAt: battleVotes.votedAt,
          judgeNumber: battleJudges.judgeNumber,
          userId: users.id,
          userEmail: users.email,
          userProfileImage: users.profilePicture,
          userDisplayName: users.displayName
        })
        .from(battleVotes)
        .leftJoin(battleJudges, eq(battleVotes.judgeId, battleJudges.id))
        .leftJoin(users, eq(battleVotes.judgeUserId, users.id))
        .where(roundNumber 
          ? and(eq(battleVotes.matchupId, matchupId), eq(battleVotes.roundNumber, roundNumber))
          : eq(battleVotes.matchupId, matchupId)
        )
        .orderBy(battleVotes.roundNumber, battleJudges.judgeNumber);

      const votesData = await query;

      // Format response with nested objects
      const votes = votesData.map(v => ({
        id: v.id,
        matchupId: v.matchupId,
        roundNumber: v.roundNumber,
        judgeId: v.judgeId,
        judgeUserId: v.judgeUserId,
        votedForRegistrationId: v.votedForRegistrationId,
        votedAt: v.votedAt,
        judge: {
          judgeNumber: v.judgeNumber
        },
        user: v.userId ? {
          id: v.userId,
          username: v.userEmail,
          profileImage: v.userProfileImage,
          displayName: v.userDisplayName
        } : null
      }));

      res.json(votes);
    } catch (error) {
      console.error("Error fetching votes:", error);
      res.status(500).json({ message: "Failed to fetch votes" });
    }
  });

  // Submit a vote for a matchup (judges only) - supports multi-round voting
  app.post("/api/matchups/:matchupId/votes", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const matchupId = parseInt(req.params.matchupId);
      const userId = (req as any).user?.id;

      const { 
        votedForRegistrationId, 
        notes,
        techniqueScore,
        vocabularyScore,
        executionScore,
        musicalityScore,
        originalityScore,
        roundNumber: requestedRound
      } = req.body;
      if (!votedForRegistrationId) {
        return res.status(400).json({ message: "Vote selection is required" });
      }

      // Get the matchup
      const [matchup] = await db.select().from(battleMatchups).where(eq(battleMatchups.id, matchupId));
      if (!matchup) {
        return res.status(404).json({ message: "Matchup not found" });
      }

      // Use requested round or current round from matchup
      const roundNumber = requestedRound || matchup.currentRound || 1;

      // Check if matchup is in a votable status (SCHEDULED, IN_PROGRESS, or VOTING)
      const votableStatuses = ['SCHEDULED', 'IN_PROGRESS', 'VOTING'];
      if (!votableStatuses.includes(matchup.status)) {
        return res.status(400).json({ message: "Voting is not open for this matchup" });
      }
      
      // Check that winner hasn't been determined yet
      if (matchup.winnerRegistrationId) {
        return res.status(400).json({ message: "This matchup has already been decided" });
      }

      // Check if user is a judge for this category
      const [judge] = await db
        .select()
        .from(battleJudges)
        .where(and(
          eq(battleJudges.categoryId, matchup.categoryId),
          eq(battleJudges.userId, userId),
          eq(battleJudges.isActive, true)
        ));

      if (!judge) {
        return res.status(403).json({ message: "You are not a judge for this category" });
      }

      // Check if judge already voted for this specific round
      const [existingVote] = await db
        .select()
        .from(battleVotes)
        .where(and(
          eq(battleVotes.matchupId, matchupId),
          eq(battleVotes.judgeId, judge.id),
          eq(battleVotes.roundNumber, roundNumber)
        ));

      if (existingVote) {
        // Strictly one-time voting per round - no changes allowed
        return res.status(400).json({ message: `You have already voted for round ${roundNumber}. Votes cannot be changed.` });
      } else {
        // Create new vote with round number
        await db.insert(battleVotes).values({
          matchupId,
          roundNumber,
          judgeId: judge.id,
          judgeUserId: userId,
          votedForRegistrationId,
          notes: notes || null,
          techniqueScore: techniqueScore || null,
          vocabularyScore: vocabularyScore || null,
          executionScore: executionScore || null,
          musicalityScore: musicalityScore || null,
          originalityScore: originalityScore || null,
        });
      }

      // Check if all judges have voted for this round
      const categoryJudges = await db
        .select()
        .from(battleJudges)
        .where(and(
          eq(battleJudges.categoryId, matchup.categoryId),
          eq(battleJudges.isActive, true)
        ));

      const roundVotes = await db
        .select()
        .from(battleVotes)
        .where(and(
          eq(battleVotes.matchupId, matchupId),
          eq(battleVotes.roundNumber, roundNumber)
        ));

      console.log(`[VOTE-DEBUG] Matchup ${matchupId}: ${roundVotes.length} votes, ${categoryJudges.length} judges needed`);
      console.log(`[VOTE-DEBUG] Matchup bestOf=${matchup.bestOf}, currentRound=${matchup.currentRound}`);
      
      const allJudgesVotedForRound = roundVotes.length >= categoryJudges.length;
      console.log(`[VOTE-DEBUG] allJudgesVotedForRound=${allJudgesVotedForRound}`);

      // If all judges have voted for this round, determine round winner
      if (allJudgesVotedForRound) {
        console.log(`[Vote] ALL JUDGES VOTED for matchup ${matchupId}, round ${roundNumber}`);
        console.log(`[Vote] Matchup data: bestOf=${matchup.bestOf}, currentRound=${matchup.currentRound}, dancerA=${matchup.dancerARegistrationId}, dancerB=${matchup.dancerBRegistrationId}`);
        
        // Count votes for each dancer in this round
        const dancerARoundVotes = roundVotes.filter(v => v.votedForRegistrationId === matchup.dancerARegistrationId).length;
        const dancerBRoundVotes = roundVotes.filter(v => v.votedForRegistrationId === matchup.dancerBRegistrationId).length;
        
        console.log(`[Vote] Round votes: A=${dancerARoundVotes}, B=${dancerBRoundVotes}`);

        // Determine round winner
        let roundWinnerRegistrationId: number | null = null;
        let newDancerARoundWins = matchup.dancerARoundWins || 0;
        let newDancerBRoundWins = matchup.dancerBRoundWins || 0;
        
        if (dancerARoundVotes > dancerBRoundVotes) {
          roundWinnerRegistrationId = matchup.dancerARegistrationId;
          newDancerARoundWins++;
        } else if (dancerBRoundVotes > dancerARoundVotes) {
          roundWinnerRegistrationId = matchup.dancerBRegistrationId;
          newDancerBRoundWins++;
        } else {
          // Tie in this round - automatically add a tiebreaker round
          const nextRoundNumber = roundNumber + 1;
          
          // Update matchup to advance to tiebreaker round
          await db
            .update(battleMatchups)
            .set({ 
              status: 'IN_PROGRESS',
              currentRound: nextRoundNumber,
              dancerARoundWins: newDancerARoundWins,
              dancerBRoundWins: newDancerBRoundWins
            })
            .where(eq(battleMatchups.id, matchupId));
          
          return res.json({ 
            message: `Round ${roundNumber} is a TIE! Moving to tiebreaker round ${nextRoundNumber}.`,
            allJudgesVoted: true,
            roundNumber,
            isTie: true,
            dancerARoundVotes,
            dancerBRoundVotes,
            dancerARoundWins: newDancerARoundWins,
            dancerBRoundWins: newDancerBRoundWins,
            nextRound: nextRoundNumber,
            requiresTiebreaker: true
          });
        }

        // Calculate rounds needed to win (majority)
        const bestOf = matchup.bestOf || 3; // Default to Best of 3 if not set
        const roundsNeededToWin = Math.ceil(bestOf / 2);
        
        console.log(`[VOTE-DEBUG] ===== ROUND ${roundNumber} COMPLETE =====`);
        console.log(`[VOTE-DEBUG] bestOf=${bestOf}, roundsNeededToWin=${roundsNeededToWin}`);
        console.log(`[VOTE-DEBUG] Votes: A=${dancerARoundVotes}, B=${dancerBRoundVotes}`);
        console.log(`[VOTE-DEBUG] BEFORE increment: dancerARoundWins=${matchup.dancerARoundWins}, dancerBRoundWins=${matchup.dancerBRoundWins}`);
        console.log(`[VOTE-DEBUG] AFTER increment: newDancerARoundWins=${newDancerARoundWins}, newDancerBRoundWins=${newDancerBRoundWins}`);
        
        // Check if either dancer has won enough rounds to win the matchup
        const matchupComplete = newDancerARoundWins >= roundsNeededToWin || 
                                newDancerBRoundWins >= roundsNeededToWin;
        
        console.log(`[VOTE-DEBUG] matchupComplete=${matchupComplete} (need ${roundsNeededToWin} wins to complete)`);
        
        if (matchupComplete) {
          console.log(`[VOTE-DEBUG] ===> COMPLETING MATCHUP (winner has ${Math.max(newDancerARoundWins, newDancerBRoundWins)} wins)`);
        } else {
          console.log(`[VOTE-DEBUG] ===> ADVANCING TO ROUND ${roundNumber + 1}`);
        }
        
        if (matchupComplete) {
          // Determine matchup winner
          const winnerRegistrationId = newDancerARoundWins >= roundsNeededToWin 
            ? matchup.dancerARegistrationId 
            : matchup.dancerBRegistrationId;

          // Update matchup with winner and final round wins
          await db
            .update(battleMatchups)
            .set({ 
              winnerRegistrationId,
              status: 'COMPLETED',
              currentRound: roundNumber,
              dancerARoundWins: newDancerARoundWins,
              dancerBRoundWins: newDancerBRoundWins
            })
            .where(eq(battleMatchups.id, matchupId));

          // Handle winner advancement to next bracket round
          const allMatchups = await db
            .select()
            .from(battleMatchups)
            .where(eq(battleMatchups.categoryId, matchup.categoryId))
            .orderBy(battleMatchups.round, battleMatchups.position);

          const currentBracketRoundMatchups = allMatchups.filter(m => m.round === matchup.round);
          const isFinal = currentBracketRoundMatchups.length === 1;

          if (!isFinal && winnerRegistrationId) {
            const nextBracketRound = matchup.round + 1;
            const nextPosition = Math.floor(matchup.position / 2);

            const nextMatchup = allMatchups.find(m => 
              m.round === nextBracketRound && m.position === nextPosition
            );

            if (nextMatchup) {
              const isFirstWinner = matchup.position % 2 === 0;
              if (isFirstWinner) {
                await db.update(battleMatchups)
                  .set({ dancerARegistrationId: winnerRegistrationId })
                  .where(eq(battleMatchups.id, nextMatchup.id));
              } else {
                await db.update(battleMatchups)
                  .set({ dancerBRegistrationId: winnerRegistrationId })
                  .where(eq(battleMatchups.id, nextMatchup.id));
              }
            } else {
              // Create new matchup for next bracket round
              const isFirstWinnerInPair = matchup.position % 2 === 0;
              const newMatchupData: any = {
                eventId: matchup.eventId,
                categoryId: matchup.categoryId,
                round: nextBracketRound,
                position: nextPosition,
                status: 'SCHEDULED',
                bestOf: matchup.bestOf || 3, // Inherit bestOf from current matchup
                currentRound: 1,
                dancerARoundWins: 0,
                dancerBRoundWins: 0
              };

              if (isFirstWinnerInPair) {
                newMatchupData.dancerARegistrationId = winnerRegistrationId;
              } else {
                newMatchupData.dancerBRegistrationId = winnerRegistrationId;
              }

              await db.insert(battleMatchups).values(newMatchupData);
            }
          }

          // MATCH-BY-MATCH FLOW: Activate the next matchup after this one completes
          // Re-fetch all matchups to get latest state
          const updatedAllMatchups = await db
            .select()
            .from(battleMatchups)
            .where(eq(battleMatchups.categoryId, matchup.categoryId))
            .orderBy(battleMatchups.round, battleMatchups.position);
          
          // Find the next scheduled matchup in the current round or next round
          let nextToActivate = updatedAllMatchups.find(m => 
            m.round === matchup.round && 
            m.status === 'SCHEDULED' && 
            m.dancerARegistrationId && 
            m.dancerBRegistrationId
          );
          
          // If no more in current round, check next round
          if (!nextToActivate) {
            nextToActivate = updatedAllMatchups.find(m => 
              m.round === matchup.round + 1 && 
              m.status === 'SCHEDULED' && 
              m.dancerARegistrationId && 
              m.dancerBRegistrationId
            );
          }
          
          if (nextToActivate) {
            await db
              .update(battleMatchups)
              .set({ status: 'IN_PROGRESS' })
              .where(eq(battleMatchups.id, nextToActivate.id));
            console.log(`[Match-by-Match] Activated next matchup ${nextToActivate.id} after completing matchup ${matchupId}`);
          }

          return res.json({ 
            message: `Round ${roundNumber} complete. ${newDancerARoundWins >= roundsNeededToWin ? 'Dancer A' : 'Dancer B'} wins the matchup ${newDancerARoundWins}-${newDancerBRoundWins}!`,
            allJudgesVoted: true,
            roundNumber,
            roundWinnerRegistrationId,
            dancerARoundVotes,
            dancerBRoundVotes,
            dancerARoundWins: newDancerARoundWins,
            dancerBRoundWins: newDancerBRoundWins,
            matchupComplete: true,
            winnerRegistrationId,
            nextActiveMatchupId: nextToActivate?.id || null
          });
        } else {
          // Advance to next round within this matchup
          const nextRoundNumber = roundNumber + 1;
          
          await db
            .update(battleMatchups)
            .set({ 
              currentRound: nextRoundNumber,
              dancerARoundWins: newDancerARoundWins,
              dancerBRoundWins: newDancerBRoundWins,
              status: 'IN_PROGRESS'
            })
            .where(eq(battleMatchups.id, matchupId));

          return res.json({ 
            message: `Round ${roundNumber} complete. Score: ${newDancerARoundWins}-${newDancerBRoundWins}. Advancing to round ${nextRoundNumber}!`,
            allJudgesVoted: true,
            roundNumber,
            roundWinnerRegistrationId,
            dancerARoundVotes,
            dancerBRoundVotes,
            dancerARoundWins: newDancerARoundWins,
            dancerBRoundWins: newDancerBRoundWins,
            matchupComplete: false,
            nextRound: nextRoundNumber
          });
        }
      } else {
        res.json({ 
          message: `Vote recorded for round ${roundNumber}`,
          allJudgesVoted: false,
          roundNumber,
          votesReceived: roundVotes.length,
          totalJudges: categoryJudges.length
        });
      }
    } catch (error) {
      console.error("Error submitting vote:", error);
      res.status(500).json({ message: "Failed to submit vote" });
    }
  });

  // Start voting for a matchup (admin/organizer only)
  app.post("/api/matchups/:matchupId/start-voting", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const matchupId = parseInt(req.params.matchupId);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Get the matchup
      const [matchup] = await db.select().from(battleMatchups).where(eq(battleMatchups.id, matchupId));
      if (!matchup) {
        return res.status(404).json({ message: "Matchup not found" });
      }

      // Verify user has permission
      const event = await storage.getEvent(matchup.eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to start voting" });
      }

      // Check if both dancers are present
      if (!matchup.dancerARegistrationId || !matchup.dancerBRegistrationId) {
        return res.status(400).json({ message: "Both dancers must be assigned before starting voting" });
      }

      // Check if there are judges assigned
      const judges = await db
        .select()
        .from(battleJudges)
        .where(and(
          eq(battleJudges.categoryId, matchup.categoryId),
          eq(battleJudges.isActive, true)
        ));

      if (judges.length === 0) {
        return res.status(400).json({ message: "At least one judge must be assigned before starting voting" });
      }

      // Update matchup status to VOTING
      await db
        .update(battleMatchups)
        .set({ status: 'VOTING' })
        .where(eq(battleMatchups.id, matchupId));

      res.json({ 
        message: "Voting started",
        matchupId,
        judgeCount: judges.length
      });
    } catch (error) {
      console.error("Error starting voting:", error);
      res.status(500).json({ message: "Failed to start voting" });
    }
  });

  // Search users to add as judges
  app.get("/api/events/:eventId/judge-search", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const { q } = req.query;
      
      if (!q || typeof q !== 'string' || q.length < 2) {
        return res.json([]);
      }

      const searchTerm = '%' + q + '%';
      
      // Search users by email or displayName
      const searchResults = await db
        .select({
          id: users.id,
          email: users.email,
          profileImage: users.profilePicture,
          displayName: users.displayName
        })
        .from(users)
        .where(
          or(
            sql`LOWER(${users.email}) LIKE LOWER(${searchTerm})`,
            sql`LOWER(${users.displayName}) LIKE LOWER(${searchTerm})`
          )
        )
        .limit(10);

      // Map to expected format with username as email for display
      const formattedResults = searchResults.map(u => ({
        id: u.id,
        username: u.email,
        profileImage: u.profileImage,
        displayName: u.displayName
      }));

      res.json(formattedResults);
    } catch (error) {
      console.error("Error searching users:", error);
      res.status(500).json({ message: "Failed to search users" });
    }
  });

