  app.patch("/api/events/:eventId/categories/:categoryId/judge-settings", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const categoryId = parseInt(req.params.categoryId);
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;

      // Verify event exists and user has permission
      const event = await storage.getEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }

      if (event.organizerId !== userId && userRole !== 'admin') {
        return res.status(403).json({ message: "You don't have permission to update judge settings" });
      }

      const { judgeCount, useJudgeVoting } = req.body;

      // Validate judgeCount is 3, 5, or 7
      if (judgeCount !== undefined && ![3, 5, 7].includes(judgeCount)) {
        return res.status(400).json({ message: "Judge count must be 3, 5, or 7" });
      }

      const updateData: any = {};
      if (judgeCount !== undefined) updateData.judgeCount = judgeCount;
      if (useJudgeVoting !== undefined) updateData.useJudgeVoting = useJudgeVoting;
      updateData.updatedAt = new Date();

      const [updated] = await db
        .update(eventCategories)
        .set(updateData)
        .where(eq(eventCategories.id, categoryId))
        .returning();

      res.json(updated);
    } catch (error) {
      console.error("Error updating judge settings:", error);
      res.status(500).json({ message: "Failed to update judge settings" });
    }
  });

