  // Get live battle state (current matchup, votes, status) - for projector displays
  app.get("/api/events/:eventId/live-state", async (req: Request, res: Response) => {
    try {
      const eventId = parseInt(req.params.eventId);
      const categoryId = req.query.categoryId ? parseInt(req.query.categoryId as string) : null;
      
      // Get event
      const event = await storage.getEvent(eventId);
      if (!event) {
        return res.status(404).json({ message: "Event not found" });
      }
      
      // Get categories for this event
      const categories = await db.select()
        .from(eventCategories)
        .where(eq(eventCategories.eventId, eventId));
      
      // If categoryId is specified, get matchups for that category
      // Otherwise get matchups for all categories
      const targetCategoryId = categoryId || (categories.length > 0 ? categories[0].id : null);
      
      if (!targetCategoryId) {
        return res.json({
          event,
          categories: [],
          currentCategory: null,
          matchups: [],
          currentMatchup: null,
          votes: []
        });
      }
      
      // Get matchups for the category
      const matchups = await db.select()
        .from(battleMatchups)
        .where(eq(battleMatchups.categoryId, targetCategoryId))
        .orderBy(battleMatchups.round, battleMatchups.position);
      
      // Get current/active matchup - support all possible status formats
      // Priority: VOTING > in_progress/IN_PROGRESS > pending/PENDING > SCHEDULED
      const votingMatchup = matchups.find(m => 
        m.status === 'VOTING' || m.status === 'voting'
      );
      const inProgressMatchup = matchups.find(m => 
        m.status === 'in_progress' || m.status === 'IN_PROGRESS'
      );
      const pendingMatchup = matchups.find(m => 
        m.status === 'pending' || m.status === 'PENDING'
      );
      const scheduledMatchup = matchups.find(m => m.status === 'SCHEDULED');
      const currentMatchup = votingMatchup || inProgressMatchup || pendingMatchup || scheduledMatchup;
      
      // Helper function to get dancer details from registration
      const getDancerDetails = async (registrationId: number | null) => {
        if (!registrationId) return null;
        const [reg] = await db.select()
          .from(dancerRegistrations)
          .where(eq(dancerRegistrations.id, registrationId));
        if (!reg) return null;
        
        // First try to get user info if user_id exists
        if (reg.userId) {
          const user = await storage.getUser(reg.userId);
          if (user) {
            return {
              id: user.id,
              username: user.username,
              displayName: user.displayName,
              profilePicture: user.profilePicture,
              registrationId: reg.id
            };
          }
        }
        
        // Fall back to registration's display_name for admin-added dancers without user accounts
        const fallbackName = reg.displayName || `Dancer #${reg.id}`;
        return {
          id: reg.id,
          username: fallbackName,
          displayName: fallbackName,
          profilePicture: null,
          registrationId: reg.id
        };
      };

      // Enrich all matchups with dancer details
      const enrichedMatchups = await Promise.all(
        matchups.map(async (matchup) => ({
          ...matchup,
          dancerA: await getDancerDetails(matchup.dancerARegistrationId),
          dancerB: await getDancerDetails(matchup.dancerBRegistrationId),
          winner: await getDancerDetails(matchup.winnerRegistrationId)
        }))
      );
      
      // Get dancer details for current matchup
      let dancerDetails = null;
      if (currentMatchup) {
        dancerDetails = {
          dancerA: await getDancerDetails(currentMatchup.dancerARegistrationId),
          dancerB: await getDancerDetails(currentMatchup.dancerBRegistrationId),
          winner: await getDancerDetails(currentMatchup.winnerRegistrationId)
        };
      }
      
      // Get votes for current matchup
      let votes: any[] = [];
      if (currentMatchup) {
        votes = await db.select()
          .from(battleVotes)
          .where(eq(battleVotes.matchupId, currentMatchup.id));
        
        // Enrich with judge details
        votes = await Promise.all(
          votes.map(async (vote) => {
            const judge = await storage.getUser(vote.judgeId);
            return {
              ...vote,
              judge: judge ? {
                id: judge.id,
                username: judge.username,
                displayName: judge.displayName
              } : null
            };
          })
        );
      }
      
      // Get the current category
      const currentCategory = categories.find(c => c.id === targetCategoryId);

      // Multi-table support: all IN_PROGRESS matchups with dancer details (sorted by table number)
      const allActiveMatchups = enrichedMatchups
        .filter(m => (m.status === 'IN_PROGRESS' || m.status === 'VOTING') && m.dancerARegistrationId && m.dancerBRegistrationId && !m.winnerRegistrationId)
        .sort((a, b) => (a.tableNumber ?? a.position) - (b.tableNumber ?? b.position));
      
      res.json({
        event,
        categories,
        currentCategory,
        competitionSport: currentCategory?.competitionSport || null,
        matchups: enrichedMatchups,
        currentMatchup: currentMatchup ? {
          ...currentMatchup,
          ...dancerDetails
        } : null,
        allActiveTables: allActiveMatchups,
        votes
      });
    } catch (error) {
      console.error("Error fetching live state:", error);
      res.status(500).json({ message: "Failed to fetch live state" });
    }
  });

