  app.get("/api/posts/feed", async (req: Request, res: Response) => {
    try {
      const userId = parseInt(
        (req.session as any)?.userId ||
        req.headers['x-user-id'] as string ||
        req.query.userId as string
      );
      if (!userId) return res.status(200).json([]);

      // Return per-user cached feed if available
      const cached = feedCache.get(`${userId}`);
      if (cached) return res.json(cached);

      const following = await storage.getFollowingByUserId(userId);
      const followingIds = following.map((f: any) => f.followedId);
      const feedUserIds = new Set([userId, ...followingIds]);

      // Re-use the posts cache if available to avoid a full table scan
      let allPosts: any[] = postsCache.get("all") as any[] || [];
      if (!allPosts.length) {
        const rawPosts = await storage.getAllPosts();
        allPosts = await Promise.all(
          rawPosts.map(async (post) => {
            const [comments, likes] = await Promise.all([
              storage.getCommentsByPost(post.id),
              storage.getLikesByPost(post.id),
            ]);
            return { ...post, commentCount: comments.length, likeCount: likes.length };
          })
        );
        postsCache.set("all", allPosts);
      }

      let posts = allPosts.filter((p: any) => feedUserIds.has(p.userId));
      posts = posts.filter((post: any) => {
        if (!post.privacy || post.privacy === 'public') return true;
        if (post.userId === userId) return true;
        if (post.privacy === 'friends_only') return feedUserIds.has(post.userId);
        return true;
      });
      posts.sort((a: any, b: any) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );

      feedCache.set(`${userId}`, posts);
      res.json(posts);
    } catch (error) {
      console.error("Error fetching personal feed:", error);
      res.status(500).json({ error: "Failed to fetch feed" });
    }
  });

  app.patch("/api/posts/:id", async (req: Request, res: Response) => {
    try {
      const postId = parseInt(req.params.id);
      const updateData = req.body;
      
      // Get the post
      const post = await storage.getPost(postId);
      if (!post) {
        return res.status(404).json({ message: "Post not found" });
      }
      
      // Authorization check - the client side should also handle this
      // but we add a server-side check for security
      const userId = req.body.userId || (req.session as any)?.userId;
      const userRole = req.body.userRole || (req.session as any)?.userRole;
      
      // Only allow the post owner or admins to edit the post
      if (post.userId !== userId && userRole !== "admin") {
        return res.status(403).json({ message: "You don't have permission to edit this post" });
      }
      
      // Only update allowed fields
      const allowedFields = ["title", "content", "image", "tags", "artType"];
      const updateFields: Partial<Post> = {};
      
      allowedFields.forEach(field => {
        if (field in updateData) {
          updateFields[field as keyof Post] = updateData[field];
        }
      });
      
      // Update the post
      const updatedPost = await storage.updatePost(postId, updateFields);
      
      if (!updatedPost) {
        return res.status(500).json({ message: "Failed to update post" });
      }
      
      postsCache.del("all");
      res.status(200).json(updatedPost);
    } catch (error) {
      console.error("Post update error:", error);
      res.status(500).json({ message: "Failed to update post" });
    }
  });

  app.delete("/api/posts/:id", async (req: Request, res: Response) => {
    try {
      const postId = parseInt(req.params.id);
      
      // Get the post
      const post = await storage.getPost(postId);
      if (!post) {
        return res.status(404).json({ message: "Post not found" });
      }
      
      // Try to get user auth from multiple sources (body, query, headers, session)
      // Body is preferred since we just updated the client to send it there
      const userId = req.body?.userId || 
                     req.query.userId || 
                     req.headers['x-user-id'] || 
                     (req.session as any)?.userId;
                     
      const userRole = req.body?.userRole || 
                      req.query.userRole || 
                      req.headers['x-user-role'] || 
                      (req.session as any)?.userRole;
      
      // Add detailed logging to debug permission issues
      console.log("Post deletion request:", {
        requestUserId: userId,
        userIdType: typeof userId,
        parsedUserId: parseInt(userId as string),
        postUserId: post.userId,
        userRole: userRole,
        body: req.body,
        query: req.query,
        headers: {
          'x-user-id': req.headers['x-user-id'],
          'x-user-role': req.headers['x-user-role']
        }
      });
      
      // Only allow the post owner or admins to delete the post
      // Properly handle type conversion and comparison
      const requestUserId = parseInt(userId as string);
      const isAdmin = isAdminRole(userRole);
      const isPostOwner = post.userId === requestUserId;
      
      if (!isPostOwner && !isAdmin) {
        console.log("Permission denied:", { isPostOwner, isAdmin, userId, userRole });
        return res.status(403).json({ message: "You don't have permission to delete this post" });
      }
      
      // Delete the post
      await storage.deletePost(postId);
      postsCache.del("all");
      
      res.status(200).json({ message: "Post deleted successfully" });
    } catch (error) {
      console.error("Post deletion error:", error);
      res.status(500).json({ message: "Failed to delete post" });
    }
  });

  app.get("/api/users/:userId/posts", async (req: Request, res: Response) => {
    try {
      const profileUserId = parseInt(req.params.userId);
      const viewerId = (req as any).user?.id || null;
      let posts = await storage.getPostsByUser(profileUserId);

      // Filter by privacy: only return public posts unless viewer is the owner or follows them
      if (viewerId !== profileUserId) {
        let isFollowing = false;
        if (viewerId) {
          isFollowing = await storage.isUserFollowing(viewerId, profileUserId);
        }
        posts = posts.filter((p: any) => {
          if (!p.privacy || p.privacy === 'public') return true;
          if (p.privacy === 'friends_only') return isFollowing;
          return false;
        });
      }

      res.json(posts);
    } catch (error) {
      res.status(500).json({ message: "Failed to fetch user posts" });
    }
  });

