  // Fetch payment intent details by client secret (for iDEAL redirects in iframe)
  app.get("/api/stripe/payment-intent/:clientSecret", async (req: Request, res: Response) => {
    try {
      const { clientSecret } = req.params;
      
      if (!clientSecret) {
        return res.status(400).json({ message: 'Client secret is required' });
      }
      
      // Extract payment intent ID from client secret (format: pi_XXX_secret_YYY)
      const intentId = clientSecret.split('_secret_')[0];
      if (!intentId) {
        return res.status(400).json({ message: 'Invalid client secret format' });
      }
      
      const { getUncachableStripeClient } = await import('./stripeClient');
      const stripe = await getUncachableStripeClient();
      
      // Retrieve the payment intent from Stripe
      const paymentIntent = await stripe.paymentIntents.retrieve(intentId);
      
      res.json(paymentIntent);
    } catch (error: any) {
      console.error('Error retrieving payment intent:', error);
      return res.status(500).json({ 
        message: 'Failed to retrieve payment intent',
        error: error.message 
      });
    }
  });

  app.post("/api/payments/create-intent", requireAuth, async (req: Request, res: Response) => {
    try {
      const { amount, name, email, eventId, ticketQuantity, currency = "eur", description, metadata = {} } = req.body;
      
      // Get userId from authenticated user
      const user = (req as any).user;
      const userId = user?.id;
      
      // Validate amount - Stripe requires at least 50 cents in EUR
      if (!amount || isNaN(Number(amount)) || Number(amount) < 50) {
        console.warn(`Invalid payment amount: ${amount}. Minimum of 50 cents required.`);
        return res.status(400).json({ 
          message: "Invalid amount. Stripe requires a minimum of 50 cents in EUR currency."
        });
      }
      
      // Determine what type of payment this is based on the request
      let paymentMetadata: Record<string, string> = {};
      
      if (eventId && ticketQuantity) {
        // For event ticket purchases
        paymentMetadata = {
          eventId: eventId.toString(),
          ticketQuantity: ticketQuantity.toString(),
          customerName: name || "",
          customerEmail: email || "",
          type: "event_ticket",
          userId: userId?.toString() || ""
        };
      } else if (metadata.productId) {
        // For product purchases
        // Convert any non-string values to strings for Stripe metadata
        Object.keys(metadata).forEach(key => {
          paymentMetadata[key] = String(metadata[key]);
        });
        paymentMetadata.type = "product_purchase";
      } else {
        // For generic payments
        // Convert any non-string values to strings for Stripe metadata
        Object.keys(metadata).forEach(key => {
          paymentMetadata[key] = String(metadata[key]);
        });
        paymentMetadata.type = "generic_payment";
      }

      console.log("Creating payment intent with amount:", amount, "cents and currency:", currency);
      
      const paymentIntent = await createPaymentIntent({
        amount: Number(amount),
        currency,
        description,
        metadata: paymentMetadata
      });

      res.json({ 
        clientSecret: paymentIntent.client_secret,
        paymentIntentId: paymentIntent.id
      });
    } catch (error: any) {
      console.error("Error creating payment intent:", error);
      
      // Return more detailed error message if available from Stripe
      if (error.message && error.message.includes("Stripe error:")) {
        return res.status(400).json({ 
          message: error.message 
        });
      }
      
      res.status(500).json({ 
        message: "Failed to create payment intent. Please try again later."
      });
    }
  });

