  // QR code ticket validation endpoint
  app.post("/api/tickets/validate", async (req: Request, res: Response) => {
    try {
      const { qrCode, scannerInfo } = req.body;
      const requestTimestamp = new Date().toISOString();
      
      // Add base debug information for all responses
      const baseDebugInfo = {
        requestTimestamp,
        endpoint: '/api/tickets/validate',
        scannerInfoProvided: !!scannerInfo,
        scannerType: scannerInfo?.deviceType || 'unknown'
      };

      if (!qrCode) {
        return res.status(400).json({ 
          message: "QR code is required",
          valid: false,
          debug: {
            ...baseDebugInfo,
            error: 'missing_qr_code',
            errorType: 'validation_error'
          }
        });
      }

      // Check if this is a BTTS ticket QR code first
      try {
        const parsed = JSON.parse(typeof qrCode === "string" ? qrCode : JSON.stringify(qrCode));
        if (parsed?.type === "btts_ticket" && parsed?.purchaseId) {
          const { db: bttsDb } = await import("./db");
          const { bttsTicketPurchases, bttsTickets } = await import("@shared/schema");
          const { eq } = await import("drizzle-orm");

          const [purchase] = await bttsDb.select().from(bttsTicketPurchases)
            .where(eq(bttsTicketPurchases.id, parsed.purchaseId)).limit(1);

          if (!purchase) {
            return res.json({ valid: false, message: "BTTS ticket not found", debug: { ...baseDebugInfo, type: "btts_ticket" } });
          }
          if (purchase.status !== "confirmed") {
            return res.json({
              valid: false,
              message: `BTTS ticket status is "${purchase.status}" — not yet confirmed`,
              debug: { ...baseDebugInfo, status: purchase.status }
            });
          }

          const alreadyCheckedIn = !!purchase.checkedIn;
          const newScanCount = (purchase.scanCount ?? 0) + 1;
          const now = new Date();

          // Mark ticket as checked-in and increment scan count
          await bttsDb.update(bttsTicketPurchases)
            .set({
              checkedIn: true,
              checkedInAt: alreadyCheckedIn ? purchase.checkedInAt : now,
              scanCount: newScanCount,
            })
            .where(eq(bttsTicketPurchases.id, purchase.id));

          const [bttsTicket] = await bttsDb.select().from(bttsTickets)
            .where(eq(bttsTickets.id, purchase.ticketId!)).limit(1);

          return res.json({
            valid: !alreadyCheckedIn,        // false if this is a duplicate scan
            alreadyUsed: alreadyCheckedIn,   // mirrors the regular-ticket flag the UI reads
            message: alreadyCheckedIn
              ? `Ticket already checked in (scanned ${newScanCount} times)`
              : "BTTS ticket checked in successfully ✓",
            ticketType: "btts_ticket",
            scanCount: newScanCount,
            lastScanned: now.toISOString(),
            firstCheckedIn: alreadyCheckedIn ? purchase.checkedInAt?.toISOString() : now.toISOString(),
            ticketInfo: {
              type: bttsTicket?.type ?? "entry",
              ticketName: bttsTicket?.name ?? "BTTS Ticket",
              holderName: purchase.guestName ?? null,
              holderEmail: purchase.guestEmail ?? null,
              purchaseId: purchase.id,
              spotNumber: purchase.spotNumber,
              amountPaid: purchase.amountPaid ?? "0",
              battleFormat: bttsTicket?.battleFormat ?? null,
            },
            debug: { ...baseDebugInfo, type: "btts_ticket", alreadyCheckedIn, newScanCount }
          });
        }
      } catch (_) { /* not a BTTS ticket, fall through to normal validation */ }

      // Pass scanner info if available - this can include location, device info, etc.
      const validationResult = await validateTicket(qrCode, scannerInfo);

      if (validationResult.valid) {
        // If ticket is valid, get additional details for display
        let ticketDetails = null;

        if (validationResult.ticketId) {
          const ticket = await storage.getTicket(validationResult.ticketId);

          if (ticket && ticket.eventId && ticket.userId) {
            const event = await storage.getEvent(ticket.eventId);
            const user = await storage.getUser(ticket.userId);

            ticketDetails = {
              ticket,
              event,
              user
            };
            
            // Create admin action for ticket validation
            if (req.session?.user?.id) {
              try {
                const isAdmin = req.session.user.role === UserRole.ADMIN;
                await storage.createAdminAction({
                  adminId: req.session.user.id,
                  actionType: isAdmin ? AdminActionType.TICKET_VALIDATION : AdminActionType.TICKET_SCAN,
                  targetId: validationResult.ticketId,
                  targetType: "ticket",
                  details: JSON.stringify({
                    message: `Ticket ${validationResult.ticketNumber || ticket.ticketNumber} validated for event ${event.title}`,
                    scannerInfo,
                    timestamp: requestTimestamp,
                    debug: validationResult.debug || {
                      ticketFound: true,
                      validationSuccessful: true,
                      scanHistory: {
                        previousScans: ticket.scanCount || 0,
                        lastScanned: ticket.lastScanned
                      }
                    }
                  })
                });
              } catch (adminActionErr) {
                console.error("Error creating admin action:", adminActionErr);
                // Non-critical error, continue processing
              }
            }
            
            // Update system stats for ticket validations
            try {
              await storage.updateDailyStats();
            } catch (statsErr) {
              console.error("Error updating system stats:", statsErr);
              // Non-critical error, continue processing
            }
          }
        }

        // Ensure debug info is included in the response
        return res.json({
          ...validationResult,
          details: ticketDetails,
          debug: validationResult.debug || {
            ...baseDebugInfo,
            validationSuccessful: true,
            ticketFound: true,
            ticketInfo: {
              ticketId: validationResult.ticketId,
              ticketNumber: validationResult.ticketNumber,
              scanCount: validationResult.scanCount
            }
          }
        });
      } else {
        // For already used tickets, still record the scan attempt
        if (validationResult.alreadyUsed && validationResult.ticketId && req.session?.user?.id) {
          try {
            await storage.createAdminAction({
              adminId: req.session.user.id,
              actionType: AdminActionType.TICKET_SCAN,
              targetId: validationResult.ticketId,
              targetType: "ticket",
              details: JSON.stringify({
                message: `Attempted to validate already used ticket ${validationResult.ticketNumber}`,
                scannerInfo,
                timestamp: requestTimestamp,
                scanCount: validationResult.scanCount,
                debug: validationResult.debug || {
                  ticketFound: true,
                  invalidReason: 'already_used',
                  scanHistory: {
                    scanCount: validationResult.scanCount
                  }
                }
              })
            });
          } catch (adminActionErr) {
            console.error("Error creating admin action for used ticket:", adminActionErr);
          }
        }
        
        // For invalid tickets due to format, data or lookup issues, log diagnostic info
        if (!validationResult.valid && !validationResult.alreadyUsed && req.session?.user?.id && validationResult.ticketId) {
          try {
            await storage.createAdminAction({
              adminId: req.session.user.id,
              actionType: AdminActionType.TICKET_SCAN,
              targetId: validationResult.ticketId,
              targetType: "ticket",
              details: JSON.stringify({
                message: `Invalid ticket scan attempt: ${validationResult.message}`,
                scannerInfo,
                timestamp: requestTimestamp,
                debug: validationResult.debug || {
                  ticketFound: true,
                  invalidReason: validationResult.message.toLowerCase().replace(/\s+/g, '_'),
                  validationError: true
                }
              })
            });
          } catch (adminActionErr) {
            console.error("Error creating admin action for invalid ticket:", adminActionErr);
          }
        }
        
        // Ensure debug info is included in the response for failed validations too
        return res.json({
          ...validationResult,
          debug: validationResult.debug || {
            ...baseDebugInfo,
            validationSuccessful: false,
            invalidReason: validationResult.alreadyUsed ? 'already_used' : 
                           validationResult.message ? validationResult.message.toLowerCase().replace(/\s+/g, '_') : 
                           'unknown_validation_error',
            ticketFound: !!validationResult.ticketId,
            scanCount: validationResult.scanCount
          }
        });
      }
    } catch (error) {
      console.error("Error validating ticket:", error);
      res.status(500).json({ 
        message: "Failed to validate ticket",
        valid: false,
        debug: { 
          errorType: error instanceof Error ? error.name : "Unknown",
          errorMessage: error instanceof Error ? error.message : String(error),
          timestamp: new Date().toISOString(),
          requestPath: '/api/tickets/validate',
          scannerInfo: !!req.body.scannerInfo
        }
      });
    }
  });

