  app.post("/api/marketplace/ai/improve-listing", async (req: Request, res: Response) => {
    try {
      const { name, category, condition, brand, currentDescription } = req.body;

      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const anthropic = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY || "",
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL || undefined,
      });

      const prompt = `You are a marketplace listing expert specializing in urban culture items (streetwear, art, vinyl, skate equipment, etc.) for the Dutch market.

A seller wants to improve their listing. Here's what they have:
- Title: ${name || "(not set yet)"}
- Category: ${category || "unknown"}
- Condition: ${condition || "good"}
- Brand: ${brand || "unknown"}
- Current description: ${currentDescription || "(empty)"}

Improve this listing for a Dutch urban culture marketplace. Return ONLY a JSON object with these fields:
{
  "title": "improved title (specific, descriptive, max 80 chars)",
  "description": "improved description in Dutch-friendly English (honest, clear, 50-200 words, mention condition, any defects, dimensions if relevant)",
  "price": "suggested fair price in EUR as a string number (e.g. '45.00'), based on typical Dutch secondhand/Marktplaats/Vinted pricing for this category and condition"
}

Be honest and practical. Don't oversell the condition.`;

      const response = await anthropic.messages.create({
        model: "claude-haiku-4-5",
        max_tokens: 500,
        messages: [{ role: "user", content: prompt }],
      });

      const content = response.content[0];
      if (content.type === "text") {
        const jsonMatch = content.text.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          const parsed = JSON.parse(jsonMatch[0]);
          return res.json({
            title: parsed.title,
            description: parsed.description,
            price: parsed.price,
          });
        }
      }

      res.status(500).json({ message: "Could not generate suggestions" });
    } catch (error) {
      console.error("AI listing improvement error:", error);
      res.status(500).json({ message: "AI service unavailable" });
    }
  });

