  // Marketplace Admin Analytics endpoint
  app.get("/api/marketplace/admin/analytics", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = req.session?.user?.id;
      if (!userId) return res.status(401).json({ message: "Authentication required" });
      const user = await storage.getUser(userId);
      if (!user || !["admin", "super_admin"].includes(user.role || "")) {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { db } = await import("./db");
      const { products: productsTable, orders: ordersTable, orderItems: orderItemsTable } = await import("../shared/schema");
      const { sql, count, sum, avg, ne } = await import("drizzle-orm");

      const allProducts = await db.select().from(productsTable);
      const allOrders = await db.select().from(ordersTable);
      const allOrderItems = await db.select().from(orderItemsTable);

      const activeProducts = allProducts.filter(p => p.status !== "deleted" && !p.isDigital);
      const totalRevenue = allOrders
        .filter(o => ["paid", "shipped", "delivered", "completed"].includes(o.status))
        .reduce((sum, o) => sum + parseFloat(o.totalAmount || "0"), 0);

      // Category breakdown
      const categoryStats: Record<string, { count: number; avgPrice: number; revenue: number }> = {};
      for (const p of activeProducts) {
        if (!categoryStats[p.category]) categoryStats[p.category] = { count: 0, avgPrice: 0, revenue: 0 };
        categoryStats[p.category].count++;
        categoryStats[p.category].avgPrice += parseFloat(p.price || "0");
      }
      for (const cat of Object.keys(categoryStats)) {
        const c = categoryStats[cat];
        c.avgPrice = c.count > 0 ? parseFloat((c.avgPrice / c.count).toFixed(2)) : 0;
      }

      // Condition breakdown
      const conditionStats: Record<string, number> = {};
      for (const p of activeProducts) {
        const cond = (p as any).condition || "unknown";
        conditionStats[cond] = (conditionStats[cond] || 0) + 1;
      }

      // Listing type breakdown
      const listingTypeStats: Record<string, number> = {};
      for (const p of activeProducts) {
        const lt = (p as any).listingType || "unknown";
        listingTypeStats[lt] = (listingTypeStats[lt] || 0) + 1;
      }

      // Low quality listings (no images, no description, or short description)
      const lowQualityListings = activeProducts.filter(p => {
        const hasImages = p.images && (Array.isArray(p.images) ? p.images.length > 0 : true);
        const hasDesc = p.description && p.description.length >= 20;
        return !hasImages || !hasDesc;
      });

      // Stock alerts (out of stock but active)
      const outOfStock = activeProducts.filter(p => typeof p.stock === "number" && p.stock === 0);

      // Recent listings (last 7 days)
      const sevenDaysAgo = new Date();
      sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
      const recentListings = activeProducts.filter(p => p.createdAt && new Date(p.createdAt) > sevenDaysAgo);

      // Top sellers (by number of products)
      const sellerProductCounts: Record<number, number> = {};
      for (const p of activeProducts) {
        if (p.sellerId) {
          sellerProductCounts[p.sellerId] = (sellerProductCounts[p.sellerId] || 0) + 1;
        }
      }

      // Pricing distribution
      const prices = activeProducts.map(p => parseFloat(p.price || "0")).filter(p => p > 0);
      const avgPrice = prices.length > 0 ? prices.reduce((a, b) => a + b, 0) / prices.length : 0;
      const minPrice = prices.length > 0 ? Math.min(...prices) : 0;
      const maxPrice = prices.length > 0 ? Math.max(...prices) : 0;

      // Price ranges
      const priceRanges = {
        "Free (€0)": prices.filter(p => p === 0).length,
        "Under €10": prices.filter(p => p > 0 && p < 10).length,
        "€10–25": prices.filter(p => p >= 10 && p < 25).length,
        "€25–50": prices.filter(p => p >= 25 && p < 50).length,
        "€50–100": prices.filter(p => p >= 50 && p < 100).length,
        "Over €100": prices.filter(p => p >= 100).length,
      };

      res.json({
        overview: {
          totalListings: activeProducts.length,
          totalOrders: allOrders.length,
          totalRevenue: parseFloat(totalRevenue.toFixed(2)),
          recentListings: recentListings.length,
          outOfStockCount: outOfStock.length,
          lowQualityCount: lowQualityListings.length,
          uniqueSellers: Object.keys(sellerProductCounts).length,
        },
        categoryBreakdown: Object.entries(categoryStats)
          .sort((a, b) => b[1].count - a[1].count)
          .map(([cat, stats]) => ({ category: cat, ...stats })),
        conditionBreakdown: Object.entries(conditionStats)
          .map(([condition, count]) => ({ condition, count })),
        listingTypeBreakdown: Object.entries(listingTypeStats)
          .map(([type, count]) => ({ type, count })),
        pricing: {
          avgPrice: parseFloat(avgPrice.toFixed(2)),
          minPrice,
          maxPrice,
          priceRanges,
        },
        alerts: {
          lowQualityListings: lowQualityListings.slice(0, 10).map(p => ({
            id: p.id,
            name: p.name,
            issues: [
              ...(!p.images || (Array.isArray(p.images) && p.images.length === 0) ? ["No images"] : []),
              ...(!p.description || p.description.length < 20 ? ["Short/missing description"] : []),
            ],
          })),
          outOfStockListings: outOfStock.slice(0, 10).map(p => ({ id: p.id, name: p.name })),
        },
      });
    } catch (error) {
      console.error("Marketplace analytics error:", error);
      res.status(500).json({ message: "Failed to load analytics" });
    }
  });

