  // Orders routes
  app.get("/api/orders", async (req: Request, res: Response) => {
    try {
      const status = req.query.status as string | undefined;
      const buyerId = req.query.buyerId ? parseInt(req.query.buyerId as string) : undefined;
      // Get userId from local storage if available
      const userId = req.query.userId ? parseInt(req.query.userId as string) : undefined;

      let orders;
      if (status) {
        orders = await storage.getOrdersByStatus(status);
      } else if (buyerId) {
        orders = await storage.getOrdersByBuyer(buyerId);
      } else if (userId) {
        // If userId is provided, return orders for that user
        orders = await storage.getOrdersByBuyer(userId);
      } else {
        // For payment intent lookups, return all orders
        if (req.query.payment_intent) {
          orders = await storage.getAllOrders();
          
          // Filter orders by payment intent
          const paymentIntentId = req.query.payment_intent as string;
          orders = orders.filter(order => order.paymentIntentId === paymentIntentId);
        } else {
          // Default: Return all orders for admins, empty for others
          const adminId = req.query.adminId ? parseInt(req.query.adminId as string) : null;
          
          if (adminId) {
            const admin = await storage.getUser(adminId);
            if (admin && isAdminRole(admin.role)) {
              orders = await storage.getAllOrders();
            } else {
              orders = [];
            }
          } else {
            orders = [];
          }
        }
      }

      res.json(orders);
    } catch (error) {
      res.status(500).json({ message: "Failed to fetch orders" });
    }
  });

