  /**
   * Reject an order (seller cannot fulfill it)
   */
  app.post("/api/orders/:id/reject", async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const { reason } = req.body;
      
      if (!reason) {
        return res.status(400).json({ message: "Rejection reason is required" });
      }
      
      // Get the current order
      const currentOrder = await storage.getOrder(parseInt(id));
      if (!currentOrder) {
        return res.status(404).json({ message: `Order with ID ${id} not found` });
      }
      
      // Update order status to rejected
      const updatedOrder = await storage.updateOrder(parseInt(id), {
        status: OrderStatus.REJECTED,
        rejectionReason: reason
      });
      
      if (!updatedOrder) {
        return res.status(500).json({ message: "Failed to update order status" });
      }
      
      // Get user details
      const user = await storage.getUser(updatedOrder.buyerId as number);
      if (!user) {
        return res.status(500).json({ 
          message: "Failed to retrieve user information",
          order: updatedOrder 
        });
      }
      
      // Get order items and product details for email
      const orderItems = await storage.getOrderItemsByOrder(parseInt(id));
      if (!orderItems || orderItems.length === 0) {
        return res.status(500).json({ 
          message: "Failed to retrieve order items",
          order: updatedOrder
        });
      }
      
      // Get product details
      const productIds = orderItems.map(item => item.productId).filter(Boolean) as number[];
      const products = await Promise.all(
        productIds.map(async (pid) => {
          const product = await storage.getProduct(pid);
          return product;
        })
      );
      const validProducts = products.filter(Boolean) as Product[];
      
      // Attempt to process refund
      let refundResult;
      try {
        if (currentOrder.paymentIntentId) {
          refundResult = await createRefund(currentOrder.paymentIntentId);
          console.log("Refund processed:", refundResult);
        }
      } catch (refundError) {
        console.error("Error processing refund:", refundError);
      }
      
      // Send refund confirmation email
      try {
        const emailSent = await sendRefundConfirmationEmail(
          user,
          updatedOrder,
          reason
        );
        
        if (emailSent) {
          // Mark email as sent in the database
          await storage.updateOrder(parseInt(id), { emailSent: true });
        } else {
          console.warn(`Failed to send refund email for order ${id}`);
        }
        
        // Use WebSocket to notify the user in real-time if available
        if (notifyOrderStatusUpdate) {
          notifyOrderStatusUpdate(updatedOrder, "Your order has been rejected and refunded");
        }
        
        return res.json({
          message: "Order rejected and refund processed",
          order: updatedOrder,
          emailSent,
          refund: refundResult
        });
      } catch (emailError) {
        console.error("Error sending refund email:", emailError);
        return res.status(200).json({
          message: "Order rejected but email failed",
          order: updatedOrder,
          emailSent: false,
          refund: refundResult,
          emailError: emailError instanceof Error ? emailError.message : "Unknown error"
        });
      }
    } catch (error) {
      console.error("Error rejecting order:", error);
      res.status(500).json({ 
        message: "Failed to reject order",
        error: error instanceof Error ? error.message : "Unknown error"
      });
    }
  });

