  // Judge assignments endpoint - returns events where user is assigned as a judge
  app.get("/api/users/:userId/judge-assignments", async (req: Request, res: Response) => {
    try {
      const userId = parseInt(req.params.userId);
      if (isNaN(userId)) {
        return res.status(400).json({ message: "Invalid user ID" });
      }

      // Get all active judge assignments for this user with full event and category data
      const rawAssignments = await db
        .select({
          id: battleJudges.id,
          eventId: battleJudges.eventId,
          categoryId: battleJudges.categoryId,
          userId: battleJudges.userId,
          judgeNumber: battleJudges.judgeNumber,
          isActive: battleJudges.isActive,
          assignedAt: battleJudges.assignedAt,
          eventTitle: events.title,
          eventDate: events.date,
          eventImage: events.image,
          categoryName: eventCategories.name,
          useJudgeVoting: eventCategories.useJudgeVoting,
          judgeCount: eventCategories.judgeCount,
          competitionSport: eventCategories.competitionSport,
        })
        .from(battleJudges)
        .innerJoin(events, eq(events.id, battleJudges.eventId))
        .innerJoin(eventCategories, eq(eventCategories.id, battleJudges.categoryId))
        .where(and(
          eq(battleJudges.userId, userId),
          eq(battleJudges.isActive, true)
        ))
        .orderBy(desc(events.date));

      // Transform to nested structure expected by frontend
      const assignments = rawAssignments.map(a => ({
        id: a.id,
        eventId: a.eventId,
        categoryId: a.categoryId,
        userId: a.userId,
        judgeNumber: a.judgeNumber,
        isActive: a.isActive,
        event: {
          id: a.eventId,
          title: a.eventTitle,
          date: a.eventDate,
          image: a.eventImage,
        },
        category: {
          id: a.categoryId,
          name: a.categoryName,
          useJudgeVoting: a.useJudgeVoting ?? false,
          judgeCount: a.judgeCount ?? 3,
          competitionSport: a.competitionSport ?? null,
        },
      }));

      res.json(assignments);
    } catch (error) {
      console.error("Error fetching judge assignments:", error);
      res.status(500).json({ message: "Failed to fetch judge assignments" });
    }
  });

  app.post("/api/subscriptions/create", async (req: Request, res: Response) => {
    try {
      const { userId, tier, period } = req.body;

      // Get user information
      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }

      // Check if user already has an active membership
      const existingMembership = await storage.getMembershipByUser(userId);
      if (existingMembership && existingMembership.isActive) {
        return res.status(400).json({ 
          message: "User already has an active membership",
          membership: existingMembership
        });
      }

      // Create or retrieve Stripe customer
      let stripeCustomerId = user.stripeCustomerId;
      if (!stripeCustomerId) {
        const customer = await createCustomer(user.email, user.displayName);
        stripeCustomerId = customer.id;

        // Update user with Stripe customer ID if needed
        if (user.stripeCustomerId !== stripeCustomerId) {
          await storage.updateUser(userId, { stripeCustomerId });
        }
      }

      // Determine price ID based on tier and period
      let priceId;
      let price;
      if (tier === "premium") {
        if (period === "monthly") {
          priceId = SUBSCRIPTION_PRICES.PREMIUM_MONTHLY;
          price = SUBSCRIPTION_TIERS.PREMIUM.monthlyPrice.toString();
        } else if (period === "yearly") {
          priceId = SUBSCRIPTION_PRICES.PREMIUM_YEARLY;
          price = SUBSCRIPTION_TIERS.PREMIUM.yearlyPrice.toString();
        } else {
          return res.status(400).json({ message: "Invalid subscription period" });
        }
      } else {
        return res.status(400).json({ message: "Invalid subscription tier" });
      }

      // Create subscription in Stripe
      const subscription = await createSubscription({
        customerId: stripeCustomerId,
        priceId,
        metadata: {
          userId: userId.toString(),
          tier,
          period
        }
      });

      // Create membership record (will be updated when payment is confirmed)
      const membership = await storage.createMembership({
        userId,
        tier,
        period,
        price,
        stripeSubscriptionId: subscription.id,
        stripeCustomerId,
        autoRenew: true,
        features: tier === "premium" ? SUBSCRIPTION_TIERS.PREMIUM.features : SUBSCRIPTION_TIERS.FREE.features,
        // isActive property is set via the status field instead
        status: "pending"
      });

      // Return necessary details for the client to complete payment
      // Cast here to access payment_intent property that may not be in the type definition
      const subscriptionAny = subscription as any;
      const clientSecret = subscriptionAny.latest_invoice?.payment_intent?.client_secret;

      res.json({
        membership,
        subscription: {
          id: subscription.id,
          clientSecret
        }
      });
    } catch (error: any) {
      console.error("Error creating subscription:", error);
      res.status(500).json({ message: "Failed to create subscription", error: error.message });
    }
  });

