  app.patch("/api/memberships/:id", async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const membershipData = req.body;

      const existingMembership = await storage.getMembership(id);
      if (!existingMembership) {
        return res.status(404).json({ message: "Membership not found" });
      }

      // If changing subscription period, update in Stripe
      if (membershipData.period && 
          existingMembership.stripeSubscriptionId && 
          membershipData.period !== existingMembership.period) {
        const priceId = membershipData.period === "monthly" 
          ? SUBSCRIPTION_PRICES.PREMIUM_MONTHLY 
          : SUBSCRIPTION_PRICES.PREMIUM_YEARLY;

        await updateSubscription(existingMembership.stripeSubscriptionId, priceId);

        // Update price based on new period
        if (membershipData.period === "monthly") {
          membershipData.price = SUBSCRIPTION_TIERS.PREMIUM.monthlyPrice.toString();
        } else if (membershipData.period === "yearly") {
          membershipData.price = SUBSCRIPTION_TIERS.PREMIUM.yearlyPrice.toString();
        }
      }

      const membership = await storage.updateMembership(id, membershipData);
      res.json(membership);
    } catch (error) {
      console.error("Error updating membership:", error);
      res.status(500).json({ message: "Failed to update membership" });
    }
  });

