  // Admin check middleware
  const isAdmin = (req: Request, res: Response, next: NextFunction) => {
    if (!(req as any).user) {
      return res.status(401).json({ message: "Authentication required" });
    }

    if ((req as any).user.role !== 'admin' && (req as any).user.role !== 'super_admin') {
      return res.status(403).json({ message: "Admin privileges required" });
    }

    next();
  };

  // Admin middleware — session-only, no header/body/query bypass
  const requireAdmin = async (req: Request, res: Response, next: NextFunction) => {
    try {
      const sessionUserId = (req.session as any)?.userId;
      const sessionUserRole = (req.session as any)?.userRole;

      if (!sessionUserId) {
        return res.status(401).json({ message: "Admin authentication required" });
      }

      const allowedRoles = ['admin', 'moderator', 'super_admin'];
      if (!allowedRoles.includes(sessionUserRole)) {
        return res.status(403).json({ message: "Admin privileges required" });
      }

      const admin = await storage.getUser(sessionUserId);
      if (!admin || !allowedRoles.includes(admin.role)) {
        return res.status(403).json({ message: "Admin privileges required" });
      }

      (req as any).admin = admin;
      next();
    } catch (error) {
      console.error("Admin authentication error:", error);
      res.status(500).json({ message: "Admin authentication failed" });
    }
  };

