  app.post("/api/admin/ai-access/settings", requireAdmin, async (req: Request, res: Response) => {
    try {
      const adminId = (req as any).admin?.id;
      const { mode, subscriptionEnabled, monthlyPriceEur } = req.body;
      const updates: { key: string; value: string; label: string; description: string }[] = [];
      if (mode !== undefined) updates.push({ key: "aiAccessMode", value: mode, label: "AI Access Mode", description: "contact_admin or subscription" });
      if (subscriptionEnabled !== undefined) updates.push({ key: "aiSubscriptionEnabled", value: String(subscriptionEnabled), label: "AI Subscription Enabled", description: "Whether users can self-subscribe for AI access" });
      if (monthlyPriceEur !== undefined) updates.push({ key: "aiSubscriptionPriceEur", value: String(monthlyPriceEur), label: "AI Monthly Price (EUR)", description: "Monthly subscription price in EUR" });

      for (const update of updates) {
        const existing = await db.select().from(appSettings).where(eq(appSettings.key, update.key)).limit(1);
        if (existing.length > 0) {
          await db.update(appSettings).set({ value: update.value, updatedBy: adminId, updatedAt: new Date() }).where(eq(appSettings.key, update.key));
        } else {
          await db.insert(appSettings).values({ key: update.key, value: update.value, label: update.label, description: update.description, updatedBy: adminId });
        }
      }
      res.json({ success: true });
    } catch (err: any) {
      res.status(500).json({ message: "Failed to update AI settings", error: err.message });
    }
  });

