  // Admin save (PUT replaces, PATCH shallow-merges top level)
  const saveAiAppContent = async (req: Request, res: Response, replace: boolean) => {
    try {
      const adminId = (req as any).admin?.id ?? (req as any).user?.id;
      const body = req.body && typeof req.body === "object" ? req.body : {};
      const next = replace ? body : { ...(await loadAiAppContent()), ...body };
      const value = JSON.stringify(next);
      const existing = await db.select().from(appSettings).where(eq(appSettings.key, AI_APP_CONTENT_KEY)).limit(1);
      if (existing.length > 0) {
        await db.update(appSettings).set({ value, updatedBy: adminId, updatedAt: new Date() }).where(eq(appSettings.key, AI_APP_CONTENT_KEY));
      } else {
        await db.insert(appSettings).values({ key: AI_APP_CONTENT_KEY, value, label: "AI App Content", description: "Editable copy for the public /ai-assistant page", updatedBy: adminId });
      }
      res.json({ success: true, content: next });
    } catch (err: any) {
      res.status(500).json({ message: "Failed to save AI app content", error: err.message });
    }
  };
  app.put("/api/admin/ai-app-content",   requireAdmin, (req, res) => saveAiAppContent(req, res, true));
  app.patch("/api/admin/ai-app-content", requireAdmin, (req, res) => saveAiAppContent(req, res, false));

