  // ADMIN: Comprehensive spot owners overview with analytics
  app.get("/api/admin/spots/overview", requireAdmin, async (req: Request, res: Response) => {
    try {
      // Get all users who have submitted spots (any user, regardless of canAddSpots flag)
      const allCreatorIds = await db.selectDistinct({ createdBy: locations.createdBy })
        .from(locations).where(sql`${locations.createdBy} IS NOT NULL`);
      const creatorIdSet = new Set(allCreatorIds.map(r => r.createdBy));

      const creatorIds = [...creatorIdSet].filter(Boolean) as number[];
      const spotOwnerUsers = await db.select({
        id: users.id,
        displayName: users.displayName,
        email: users.email,
        role: users.role,
        artType: users.artType,
        canAddSpots: users.canAddSpots,
        profilePicture: users.profilePicture,
        createdAt: users.createdAt,
      }).from(users).where(
        creatorIds.length > 0
          ? sql`${users.role} = 'spot_owner' OR ${users.canAddSpots} = true OR ${users.id} IN (${sql.join(creatorIds.map(id => sql`${id}`), sql`, `)})`
          : sql`${users.role} = 'spot_owner' OR ${users.canAddSpots} = true`
      ).orderBy(desc(users.createdAt));

      // Get all community spots
      const allSpots = await db.select({
        id: locations.id,
        name: locations.name,
        type: locations.type,
        address: locations.address,
        approvalStatus: locations.approvalStatus,
        isVisible: locations.isVisible,
        createdBy: locations.createdBy,
        createdAt: locations.createdAt,
        latitude: locations.latitude,
        longitude: locations.longitude,
      }).from(locations).orderBy(desc(locations.createdAt));

      // Get programme access grants
      const allAccess = await db.select().from(programmeAccess);

      // Get programme items grouped by owner
      const allProgrammeItems = await db.select({
        id: programmeItems.id,
        userId: programmeItems.userId,
        locationId: programmeItems.locationId,
        title: programmeItems.title,
        category: programmeItems.category,
        startTime: programmeItems.startTime,
        isPublic: programmeItems.isPublic,
        isActive: programmeItems.isActive,
      }).from(programmeItems).orderBy(desc(programmeItems.startTime));

      // Aggregate stats per owner
      const ownerStats = spotOwnerUsers.map(u => {
        const mySpots = allSpots.filter(s => s.createdBy === u.id);
        const myAccess = allAccess.find(a => a.userId === u.id);
        const myItems = allProgrammeItems.filter(p => p.userId === u.id);
        return {
          ...u,
          totalSpots: mySpots.length,
          approvedSpots: mySpots.filter(s => s.approvalStatus === 'approved').length,
          pendingSpots: mySpots.filter(s => s.approvalStatus === 'pending').length,
          programmeAccess: myAccess ? { isEnabled: myAccess.isEnabled, venueName: myAccess.venueName } : null,
          programmeItemCount: myItems.length,
          activeItemCount: myItems.filter(i => i.isActive && i.isPublic).length,
          spots: mySpots,
        };
      });

      // Global stats
      const globalStats = {
        totalSpotOwners: spotOwnerUsers.length,
        totalCommunitySpots: allSpots.length,
        approvedSpots: allSpots.filter(s => s.approvalStatus === 'approved').length,
        pendingSpots: allSpots.filter(s => s.approvalStatus === 'pending').length,
        totalProgrammeItems: allProgrammeItems.length,
        ownersWithProgrammeAccess: allAccess.filter(a => a.isEnabled).length,
      };

      res.json({ owners: ownerStats, globalStats, allSpots });
    } catch (err: any) {
      console.error("Admin spots overview error:", err);
      res.status(500).json({ message: "Failed to get spots overview", error: err.message });
    }
  });

