  // ── USER AI ACCESS STATUS ─────────────────────────────────────────────────

  app.get("/api/ai-access/status", async (req: Request, res: Response) => {
    try {
      const user = await getCurrentUser(req);
      if (!user) return res.json({ hasAccess: false, mode: "contact_admin", isPremium: false, isAdmin: false });

      const isAdmin = user.role === "admin" || user.role === "super_admin";
      const isPremium = !!(user as any).isAiPremium;
      const hasAccess = isAdmin || isPremium;

      // Cache per user — settings rarely change, no need to hit DB on every page load
      const cacheKey = `ai_access_${user.id}`;
      const cached = aiAccessCache.get(cacheKey) as any;
      if (cached) return res.json({ ...cached, hasAccess, isPremium, isAdmin });

      // Single query for all 3 settings instead of 3 separate round-trips
      const settings = await db.select().from(appSettings)
        .where(inArray(appSettings.key, ["aiAccessMode", "aiSubscriptionEnabled", "aiSubscriptionPriceEur"]));
      const settingsMap = Object.fromEntries(settings.map(s => [s.key, s.value]));

      const result = {
        hasAccess,
        isPremium,
        isAdmin,
        mode: settingsMap["aiAccessMode"] || "contact_admin",
        subscriptionEnabled: settingsMap["aiSubscriptionEnabled"] === "true",
        monthlyPrice: settingsMap["aiSubscriptionPriceEur"] || "9.99",
      };
      // Cache the settings part (user-specific access flags are recalculated on cache hit above)
      aiAccessCache.set(cacheKey, { mode: result.mode, subscriptionEnabled: result.subscriptionEnabled, monthlyPrice: result.monthlyPrice });
      res.json(result);
    } catch (err: any) {
      res.status(500).json({ message: "Failed to get AI access status" });
    }
  });

  // ── AI PREMIUM STRIPE SUBSCRIPTION ───────────────────────────────────────

  app.post("/api/ai-premium/checkout", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = await getCurrentUser(req);
      if (!user) return res.status(401).json({ message: "Authentication required" });

      const [subEnabledSetting] = await db.select().from(appSettings).where(eq(appSettings.key, "aiSubscriptionEnabled")).limit(1);
      if (subEnabledSetting?.value !== "true") {
        return res.status(403).json({ message: "Subscription purchases are not currently enabled. Please contact the admin." });
      }

      const [priceSetting] = await db.select().from(appSettings).where(eq(appSettings.key, "aiSubscriptionPriceEur")).limit(1);
      const priceEur = parseFloat(priceSetting?.value || "9.99");

      const { getUncachableStripeClient } = await import('./stripeClient');
      const stripe = await getUncachableStripeClient();

      const origin =
        process.env.APP_URL?.replace(/\/$/, "") ||
        (process.env.REPLIT_DEV_DOMAIN ? `https://${process.env.REPLIT_DEV_DOMAIN}` : null) ||
        (req.headers.origin as string) ||
        "http://localhost:5000";

      const session = await stripe.checkout.sessions.create({
        payment_method_types: ["card", "ideal"],
        customer_email: user.email,
        line_items: [{
          price_data: {
            currency: "eur",
            product_data: {
              name: "AI Premium Access",
              description: "Unlock AI-powered features: Find My Spot, AI Spot Descriptions, and more.",
            },
            unit_amount: Math.round(priceEur * 100),
            recurring: { interval: "month" },
          },
          quantity: 1,
        }],
        mode: "subscription",
        success_url: `${origin}/ai-premium/success?session_id={CHECKOUT_SESSION_ID}`,
        cancel_url: `${origin}/map`,
        metadata: {
          type: "ai_premium",
          userId: user.id.toString(),
        },
      });

      res.json({ url: session.url, sessionId: session.id });
    } catch (err: any) {
      console.error("AI premium checkout error:", err);
      res.status(500).json({ message: "Failed to create checkout session", error: err.message });
    }
  });

  // Activate AI premium after successful Stripe checkout
  app.get("/api/ai-premium/activate", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const sessionId = req.query.session_id as string;
      const user = await getCurrentUser(req);
      if (!user) return res.status(401).json({ message: "Authentication required" });
      if (!sessionId) return res.status(400).json({ message: "Missing session_id" });

      const { getUncachableStripeClient } = await import('./stripeClient');
      const stripe = await getUncachableStripeClient();

      const session = await stripe.checkout.sessions.retrieve(sessionId);
      if (session.payment_status !== "paid" || session.metadata?.type !== "ai_premium") {
        return res.status(400).json({ message: "Invalid or unpaid session" });
      }
      if (session.metadata?.userId && session.metadata.userId !== user.id.toString()) {
        return res.status(403).json({ message: "Session does not belong to this user" });
      }

      await storage.updateUser(user.id, { isAiPremium: true } as any);
      res.json({ success: true, message: "AI Premium activated!" });
    } catch (err: any) {
      console.error("AI premium activate error:", err);
      res.status(500).json({ message: "Failed to activate AI premium", error: err.message });
    }
  });

