  // Content Moderation
  // Content flagging route - allows users to report inappropriate content
  app.post("/api/content-flags", async (req: Request, res: Response) => {
    try {
      // Validate required fields
      if (!req.body.contentType || !req.body.contentId || !req.body.reason) {
        return res.status(400).json({ 
          message: "Missing required fields: contentType, contentId, and reason are required" 
        });
      }
      
      // Set up flag data with proper defaults
      const flagData = {
        contentType: req.body.contentType,
        contentId: req.body.contentId,
        reason: req.body.reason,
        reporterId: req.body.reporterId || null,
        status: ContentFlagStatus.PENDING,
        reviewerId: null,
        notes: null
      };

      console.log(`Creating content flag: ${JSON.stringify(flagData)}`);
      const contentFlag = await storage.createContentFlag(flagData);
      
      if (!contentFlag) {
        return res.status(500).json({ message: "Failed to create content flag - database error" });
      }
      
      // Get reporter information if available for real-time notification
      let reporter = null;
      if (flagData.reporterId) {
        try {
          reporter = await storage.getUser(flagData.reporterId);
        } catch (userError) {
          console.error("Failed to get reporter user details:", userError);
        }
      }
      
      // Send real-time WebSocket notification to admins
      try {
        // notifyContentReported is already imported at the top of the file
        notifyContentReported(contentFlag, reporter);
        console.log('Real-time notification sent to admins for content flag');
      } catch (wsError) {
        console.error("Failed to send real-time notification for content flag:", wsError);
        // Continue despite WebSocket error - the flag was created successfully
      }
      
      // Also create admin notification about new flag (persistent notification)
      try {
        await storage.createAdminNotification({
          message: `New content flag: ${flagData.reason}`,
          type: "content_flag",
          targetType: flagData.contentType,
          targetId: flagData.contentId,
          fromUserId: flagData.reporterId,
        });
      } catch (notifyError) {
        console.error("Failed to create admin notification for content flag:", notifyError);
        // Continue despite notification error - the flag was created successfully
      }

      // Update system stats for flagged content
      try {
        const stats = await storage.getLatestSystemStats();
        if (stats) {
          await storage.updateSystemStat(stats.id, {
            flaggedContent: (stats.flaggedContent || 0) + 1
          });
        }
      } catch (statsError) {
        console.error("Failed to update stats for flagged content:", statsError);
      }

      res.status(201).json({
        ...contentFlag,
        message: "Thank you for your report. Our moderation team will review it within 24 hours."
      });
    } catch (error) {
      console.error("Failed to create content flag:", error);
      res.status(500).json({ 
        message: "Failed to create content flag", 
        error: error instanceof Error ? error.message : "Unknown error" 
      });
    }
  });

