  app.post("/api/admin/content-flags/:id/review", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const { status, notes, reviewerId: bodyReviewerId } = req.body;
      
      // Get admin ID from multiple sources for redundancy
      const adminId = (req as any).admin?.id;
      
      // Get the reviewer ID with multiple fallbacks for reliability
      const reviewerId = bodyReviewerId
        ? (typeof bodyReviewerId === 'string' ? parseInt(bodyReviewerId) : bodyReviewerId)
        : req.query.adminId 
          ? parseInt(req.query.adminId as string) 
          : adminId || 1; // Final fallback to admin ID 1
      
      // Ensure we have a valid flag ID
      if (isNaN(id)) {
        return res.status(400).json({ 
          message: "Invalid flag ID format",
          success: false
        });
      }
      
      // Ensure we have a valid status
      if (!status || !['approved', 'rejected', 'pending'].includes(status)) {
        return res.status(400).json({ 
          message: "Invalid status - must be 'approved', 'rejected', or 'pending'",
          success: false
        });
      }
      
      console.log(`Content flag review: Flag ID ${id}, reviewer ID ${reviewerId}, status ${status}`);
      console.log(`Review notes: ${notes || "No notes provided"}`);
      
      const updatedFlag = await storage.reviewContentFlag(id, reviewerId, status, notes);

      if (!updatedFlag) {
        return res.status(404).json({ 
          message: "Content flag not found", 
          success: false 
        });
      }
      
      // If report is approved, take appropriate action based on content type
      if (status === 'approved') {
        try {
          // For posts, automatically delete them
          if (updatedFlag.contentType === 'post') {
            const postId = Number(updatedFlag.contentId);
            if (isNaN(postId)) {
              console.error(`Invalid post ID format in content flag: ${updatedFlag.contentId}`);
            } else {
              console.log(`Admin approved post report: Automatically deleting post #${postId}`);
              
              try {
                // First verify the post exists
                const post = await storage.getPost(postId);
                if (!post) {
                  console.error(`Post #${postId} not found for deletion after report approval`);
                } else {
                  // Post exists, proceed with deletion
                  const deleteResult = await storage.deletePost(postId);
                  console.log(`Post deletion result:`, deleteResult);
                  
                  if (!deleteResult) {
                    console.error(`Failed to delete post #${postId} after report approval`);
                  }
                }
              } catch (deleteError) {
                console.error(`Exception when deleting post #${postId}:`, deleteError);
              }
            }
          }
          
          // Send real-time WebSocket notification to reporter and admins
          try {
            // notifyContentModerationAction is already imported at the top of the file
            notifyContentModerationAction(updatedFlag, reviewerId, 'approved');
            console.log('Real-time content moderation approval notification sent');
          } catch (wsError) {
            console.error('Failed to send WebSocket notification for flag approval:', wsError);
          }
          
          // Create persistent notification for the reporter
          if (updatedFlag.reporterId) {
            await storage.createUserNotification({
              userId: updatedFlag.reporterId,
              type: NotificationType.CONTENT_MODERATION,
              title: "Report Action Taken",
              message: `Your report about ${updatedFlag.contentType} #${updatedFlag.contentId} has been reviewed and approved. The reported content has been removed.`,
            });
          }
        } catch (actionError) {
          console.error(`Error taking action on approved flag ${id}:`, actionError);
          // Continue with the response even if the action fails
        }
      } else if (status === 'rejected') {
        // If rejected, send real-time WebSocket notification
        try {
          // notifyContentModerationAction is already imported at the top of the file
          notifyContentModerationAction(updatedFlag, reviewerId, 'rejected');
          console.log('Real-time content moderation rejection notification sent');
        } catch (wsError) {
          console.error('Failed to send WebSocket notification for flag rejection:', wsError);
        }
        
        // Create persistent notification for the reporter
        try {
          if (updatedFlag.reporterId) {
            await storage.createUserNotification({
              userId: updatedFlag.reporterId,
              type: NotificationType.CONTENT_MODERATION,
              title: "Report Decision",
              message: `Your report about ${updatedFlag.contentType} #${updatedFlag.contentId} has been reviewed but did not require action at this time.`,
            });
          }
        } catch (notifyError) {
          console.error(`Error notifying reporter for rejected flag ${id}:`, notifyError);
        }
      }

      res.json({
        flag: updatedFlag,
        success: true,
        message: `Content flag successfully ${status}`
      });
    } catch (error) {
      console.error("Failed to review content flag:", error);
      res.status(500).json({ 
        message: "Failed to review content flag", 
        success: false,
        error: error instanceof Error ? error.message : "Unknown error"
      });
    }
  });

