  /**
   * Admin endpoint to send custom order status notifications to users
   */
  app.post("/api/admin/orders/:id/notify", requireAdmin, async (req: Request, res: Response) => {
    try {
      const orderId = parseInt(req.params.id);
      const { message, status } = req.body;
      const adminId = (req as any).admin?.id || 1; // Default to admin ID 1 if not provided
      
      // Validate the order exists
      const order = await storage.getOrder(orderId);
      if (!order) {
        return res.status(404).json({ message: "Order not found" });
      }
      
      if (!order.buyerId) {
        return res.status(400).json({ message: "Order does not have a valid buyer" });
      }

      // Get admin user info for email notifications
      const adminUser = await storage.getUser(adminId);
      if (!adminUser) {
        console.warn(`Admin user with ID ${adminId} not found for detailed notification`);
      }
      
      // Get buyer user info for notifications
      const buyer = await storage.getUser(order.buyerId);
      if (!buyer) {
        return res.status(404).json({ message: "Buyer not found" });
      }
      
      // If status is provided, update the order
      if (status) {
        await storage.updateOrder(orderId, { status });
      }
      
      // Log the admin action
      await storage.createAdminAction({
        adminId: adminId,
        actionType: "notify_order",
        targetId: orderId,
        targetType: "order",
        details: `Admin sent notification for order #${orderId}: "${message}"${status ? ` and changed status to ${status}` : ''}`
      });
      
      // Send the custom notification
      try {
        // 1. Send WebSocket notification
        const { notifyAdminOrderUpdate } = await import('./websocket');
        notifyAdminOrderUpdate(
          order.buyerId,
          orderId,
          status || order.status,
          adminId,
          message || `Your order #${orderId} has been updated by an administrator`
        );
        
        console.log(`Admin notification sent to user ${order.buyerId} for order ${orderId}`);
        
        // 2. Create a database notification record for persistence
        try {
          await storage.createUserNotification({
            userId: order.buyerId,
            fromUserId: adminId,
            title: "Order Update",
            message: message || `Your order #${orderId} has been updated by an administrator`,
            type: "order_update",
            actionLink: `/orders/${orderId}`,
            actionText: "View Order",
            targetId: orderId,
            targetType: "order",
            importance: "high"
          });
        } catch (dbError) {
          console.error("Error creating notification record:", dbError);
          // Continue even if database record creation fails
        }
        
        // 3. Send email notification
        try {
          const { sendOrderStatusUpdateEmail, emailSystem } = await import('./email');
          
          // Make sure email system is properly configured before attempting to send
          if (!emailSystem.isConfigured) {
            console.warn("Email system not configured. Email notification will not be sent.");
          } else if (!emailSystem.isEnabled) {
            console.warn("Email system is disabled. Email notification will not be sent.");
          } else {
            // Enable the email system explicitly
            emailSystem.isEnabled = true;
            
            const emailSent = await sendOrderStatusUpdateEmail(
              buyer,
              order,
              status || order.status,
              message,
              adminUser
            );
            
            console.log(`Email notification ${emailSent ? 'sent successfully' : 'failed to send'} to ${buyer.email}`);
          }
        } catch (emailError) {
          console.error("Error sending email notification:", emailError);
          console.error("Email error details:", emailError instanceof Error ? emailError.message : String(emailError));
          // Continue even if email sending fails
        }
        
        res.json({ 
          success: true, 
          message: "Notification sent successfully",
          order
        });
      } catch (wsError) {
        console.error("Error sending WebSocket notification:", wsError);
        res.status(500).json({ 
          success: false, 
          message: "Failed to send notification via WebSocket, but order was updated if status was provided",
          error: wsError instanceof Error ? wsError.message : "Unknown error" 
        });
      }
    } catch (error) {
      console.error("Error in admin order notification:", error);
      res.status(500).json({ 
        success: false, 
        message: "Failed to process the notification request",
        error: error instanceof Error ? error.message : "Unknown error"
      });
    }
  });

