  /**
   * Record a content share event and send notifications
   * This can be used when WebSockets aren't available or as a fallback
   */
  app.post("/api/share", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const { contentType, contentId, platform } = req.body;

      // Validate required parameters
      if (!contentType || !contentId) {
        return res.status(400).json({
          success: false,
          message: "Content type and content ID are required"
        });
      }

      // Derive userId from authenticated session — never trust client-supplied userId
      const authUser: any = (req as any).user;
      const userId: number | null = authUser?.id ?? null;

      // For post / reel sharing, enforce admin-controlled share permission
      if (contentType === "post" || contentType === "reel") {
        let canShare = false;
        if (authUser?.role === "admin" || authUser?.role === "super_admin") {
          canShare = true;
        } else if (typeof authUser?.canShareContent === "boolean") {
          canShare = authUser.canShareContent === true;
        } else if (authUser?.id) {
          const fresh = await storage.getUser(authUser.id);
          canShare = !!(fresh && ((fresh as any).canShareContent || fresh.role === "admin" || fresh.role === "super_admin"));
        }
        if (!canShare) {
          return res.status(403).json({
            success: false,
            message: "Sharing is restricted. Contact an admin to request share access.",
          });
        }
      }

      // Create a record of the share event (optional future feature)
      // const shareRecord = await storage.createShareEvent({ contentType, contentId, platform, userId });

      // Send a notification using WebSocket system
      notifyContentShared(contentType, contentId, userId, platform || 'unknown');
      
      // Create an admin notification
      const adminNotification = await storage.createAdminNotification({
        message: `Content ${contentType} (ID: ${contentId}) was shared on ${platform || 'unknown'}.`,
        type: "CONTENT_SHARED",
        title: `${contentType.charAt(0).toUpperCase() + contentType.slice(1)} Shared`,
        fromAdminId: null,
        toUserId: null,
        actionLink: `/${contentType}s/${contentId}`,
        actionText: "View Content"
      });
      
      res.json({ 
        success: true, 
        message: "Share event recorded and notifications sent" 
      });
    } catch (error) {
      console.error("Error recording share event:", error);
      res.status(500).json({ 
        success: false, 
        message: "Failed to record share event" 
      });
    }
  });

