  app.post("/api/services", async (req: Request, res: Response) => {
    try {
      const serviceData = insertServiceSchema.parse(req.body);

      // First check if the user is verified for business services
      const provider = await storage.getUser(serviceData.providerId);

      if (!provider) {
        return res.status(404).json({ message: "Provider not found" });
      }

      // Check if we're in fallback mode due to KVK API issues
      const kvkStatus = getKvkApiStatus();
      const isFallbackMode = kvkStatus.status === 'error' || kvkStatus.status === 'inactive';

      // Check if the provider has business verification
      if (provider.kvkVerificationStatus !== 'verified') {
        // Allow users to proceed if:
        // 1. They have provided a KVK number (regardless of verification status)
        // 2. OR they have a pending verification status
        // 3. OR they are in fallback mode
        const hasKvkNumber = provider.kvkNumber && provider.kvkNumber.length > 0;
        const isPending = provider.kvkVerificationStatus === 'pending';
        const canProceed = hasKvkNumber || isPending || isFallbackMode;

        if (!canProceed) {
          return res.status(403).json({ 
            message: "Business verification required before creating services",
            verificationStatus: provider.kvkVerificationStatus,
            needsVerification: true,
            isFallbackMode
          });
        }

        // If in fallback mode, automatically update verification status if they have a KVK number
        if (isFallbackMode && hasKvkNumber && provider.id && provider.kvkVerificationStatus !== 'pending') {
          console.log(`Auto-verifying user ${provider.id} with KVK ${provider.kvkNumber} due to fallback mode`);
          await storage.updateUser(provider.id, {
            kvkVerificationStatus: 'verified',
            kvkVerifiedAt: new Date()
          });
        }
      }

      const service = await storage.createService(serviceData);
      res.status(201).json(service);
    } catch (error) {
      console.error("Error creating service:", error);
      res.status(400).json({ message: "Failed to create service", error });
    }
  });

  app.patch("/api/services/:id", async (req: Request, res: Response) => {
    try {
      const serviceId = parseInt(req.params.id);
      const service = await storage.getService(serviceId);

      if (!service) {
        return res.status(404).json({ message: "Service not found" });
      }
      
      // Get user ID and role from multiple sources (session, headers, query params)
      let userId = (req as any).user?.id;
      let userRole = (req as any).user?.role;
      
      // Check for user ID in session
      if (req.session && (req.session as any).user) {
        userId = (req.session as any).user.id;
        userRole = (req.session as any).user.role;
      }
      
      // Check if we already have a user from session
      if (!userId) {
        // Try to get from localStorage stored in a cookie
        const userFromLocalStorage = req.cookies && req.cookies.user ? 
          JSON.parse(req.cookies.user) : null;
        
        if (userFromLocalStorage && userFromLocalStorage.id) {
          userId = userFromLocalStorage.id;
          userRole = userFromLocalStorage.role;
        }
      }
      
      // Check headers for auth info (fallback)
      const headerUserId = req.headers['x-user-id'];
      const headerUserRole = req.headers['x-user-role'];
      
      // Check query params for auth info (explicit parameters)
      const queryUserId = req.query.userId;
      const queryUserRole = req.query.userRole;
      
      // Use query params with highest priority (explicitly provided)
      if (queryUserId) {
        userId = parseInt(queryUserId as string);
      }
      
      if (queryUserRole) {
        userRole = queryUserRole as string;
      }
      
      // If still no userId, try header as fallback
      if (!userId && headerUserId) {
        userId = parseInt(headerUserId as string);
      }
      
      if (!userRole && headerUserRole) {
        userRole = headerUserRole as string;
      }
      
      // Add request body as another possible source
      if (!userId && req.body && req.body.providerId) {
        userId = req.body.providerId;
      }
      
      console.log("Service update auth data:", { 
        userId, 
        userRole,
        sessionUser: req.session ? (req.session as any).user : undefined,
        headerUserId, 
        headerUserRole,
        queryUserId,
        queryUserRole,
        serviceProviderId: service.providerId,
        reqBody: req.body
      });
      
      // Check if user has permission to update this service
      // Only the provider or an admin can update a service
      if (!userId || (userId !== service.providerId && userRole !== "admin")) {
        return res.status(403).json({ 
          message: "You don't have permission to update this service",
          details: {
            userId,
            serviceProviderId: service.providerId,
            userRole
          } 
        });
      }

      const updatedService = await storage.updateService(serviceId, req.body);
      res.json(updatedService);
    } catch (error) {
      console.error("Error updating service:", error);
      res.status(400).json({ message: "Failed to update service", error });
    }
  });

  app.delete("/api/services/:id", async (req: Request, res: Response) => {
    try {
      const serviceId = parseInt(req.params.id);
      const service = await storage.getService(serviceId);

      if (!service) {
        return res.status(404).json({ message: "Service not found" });
      }
      
      // Get user ID and role from multiple sources (session, headers, query params)
      let userId = (req as any).user?.id;
      let userRole = (req as any).user?.role;
      
      // Check Authorization header for Bearer token
      const authHeader = req.headers.authorization;
      if (authHeader && authHeader.startsWith('Bearer ')) {
        const token = authHeader.substring(7); // Remove 'Bearer ' prefix
        try {
          // Verify Firebase token
          const admin = await import('firebase-admin');
          const decodedToken = await admin.auth().verifyIdToken(token);
          const firebaseUid = decodedToken.uid;
          
          console.log(`Successfully verified Firebase token for UID: ${firebaseUid}`);
          
          // Get user from database using Firebase UID
          if (firebaseUid) {
            try {
              const user = await storage.getUserByFirebaseUid(firebaseUid);
              if (user) {
                userId = user.id;
                userRole = user.role;
                console.log(`Authenticated user from token: ID ${userId}, Role ${userRole}`);
              } else {
                console.warn(`No user found with Firebase UID: ${firebaseUid}`);
              }
            } catch (dbError) {
              console.error("Error getting user by Firebase UID:", dbError);
            }
          }
        } catch (tokenError) {
          console.error("Token verification error:", tokenError);
          // Continue with other auth methods if token verification fails
        }
      }
      
      // Check headers for auth info as fallback
      const headerUserId = req.headers['x-user-id'];
      const headerUserRole = req.headers['x-user-role'];
      
      // Check query params for auth info as fallback
      const queryUserId = req.query.userId;
      const queryUserRole = req.query.userRole;
      
      // Use the first available source
      if (!userId && headerUserId) {
        userId = parseInt(headerUserId as string);
      }
      if (!userId && queryUserId) {
        userId = parseInt(queryUserId as string);
      }
      
      if (!userRole && headerUserRole) {
        userRole = headerUserRole as string;
      }
      if (!userRole && queryUserRole) {
        userRole = queryUserRole as string;
      }
      
      console.log("Service deletion request:", {
        serviceId,
        serviceName: service.name,
        serviceProviderId: service.providerId,
        userId,
        userRole,
        hasAuthHeader: !!req.headers.authorization,
        headerUserId: req.headers['x-user-id'],
        headerUserRole: req.headers['x-user-role'],
        queryUserId: req.query.userId,
        queryUserRole: req.query.userRole
      });

      // Check if user has permission to delete this service
      // Only the provider or an admin can delete a service
      // Also check explicit isAdmin flag from the request body, and get user ID and role from body if not available
      
      // Get values from body if not available through token
      if (!userId && req.body?.userId) {
        userId = parseInt(req.body.userId);
      }
      
      if (!userRole && req.body?.userRole) {
        userRole = req.body.userRole;
      }
      
      const isAdminFromBody = req.body?.isAdmin === true || req.body?.userRole === "admin";
      const isAdmin = userRole === "admin" || isAdminFromBody;
      
      console.log("Permission check for service deletion:", {
        userId,
        userRole,
        providerId: service.providerId,
        isAdmin,
        isAdminFromRole: userRole === "admin",
        isAdminFromBody,
        isProvider: userId === service.providerId,
        body: req.body
      });
      
      // Allow admin users to delete any service
      if (isAdmin) {
        console.log("Admin user permission granted for service deletion");
      }
      // If not admin, check if user is the service provider
      else if (!userId || userId !== service.providerId) {
        return res.status(403).json({ 
          message: "You don't have permission to delete this service",
          details: {
            requiredId: service.providerId,
            yourId: userId,
            yourRole: userRole,
            isAdmin,
            isAdminFromRole: userRole === "admin",
            isAdminFromBody
          }
        });
      }

      const success = await storage.deleteService(serviceId);
      if (success) {
        // Add a log before responding
        console.log(`Service ${serviceId} deleted successfully by user ${userId} (role: ${userRole})`);
        res.json({ message: "Service deleted successfully" });
      } else {
        console.error(`Failed to delete service ${serviceId}`);
        res.status(400).json({ message: "Failed to delete service" });
      }
    } catch (error) {
      console.error("Error deleting service:", error);
      
      // Check specifically for foreign key constraint violations
      const errorStr = String(error);
      if (errorStr.includes("foreign key constraint") && errorStr.includes("service_bookings")) {
        // If the service has bookings, provide a more helpful error message
        res.status(400).json({ 
          message: "Failed to delete service", 
          error: "This service has existing bookings and cannot be deleted. The service has been deactivated instead.",
          details: "Service will no longer appear in search results or the marketplace, but existing bookings are preserved."
        });
      } else {
        res.status(400).json({ 
          message: "Failed to delete service", 
          error: error instanceof Error ? error.message : String(error) 
        });
      }
    }
  });

