  // Service Booking Routes
  
  // Generic update booking status endpoint that handles all status changes
  app.post("/api/service-bookings/:id/status", async (req: Request, res: Response) => {
    try {
      const bookingId = parseInt(req.params.id);
      const { status, message } = req.body;
      
      if (!status) {
        return res.status(400).json({ message: "Status is required" });
      }
      
      // Validate the status is one of the allowed values
      if (!Object.values(BookingStatus).includes(status)) {
        return res.status(400).json({ message: "Invalid status value" });
      }
      
      // Get the booking to check current status
      const currentBooking = await storage.getServiceBooking(bookingId);
      if (!currentBooking) {
        return res.status(404).json({ message: "Service booking not found" });
      }
      
      // Update the booking status
      let updatedBooking: ServiceBooking | undefined;
      
      // Use the appropriate method based on the requested status
      switch (status) {
        case BookingStatus.APPROVED:
          updatedBooking = await storage.approveServiceBooking(bookingId);
          break;
        case BookingStatus.REJECTED:
          updatedBooking = await storage.rejectServiceBooking(bookingId, message);
          break;
        case BookingStatus.COMPLETED:
          updatedBooking = await storage.completeServiceBooking(bookingId);
          break;
        case BookingStatus.CANCELLED:
          updatedBooking = await storage.cancelServiceBooking(bookingId, message);
          break;
        default:
          // For any other status, use the general update method
          updatedBooking = await storage.updateServiceBooking(bookingId, { 
            status, 
            adminMessage: message || null 
          });
      }
      
      if (!updatedBooking) {
        return res.status(500).json({ message: "Failed to update booking status" });
      }
      
      // Get the necessary data for notifications and emails
      const service = await storage.getService(updatedBooking.serviceId);
      const user = await storage.getUser(updatedBooking.userId);
      const provider = await storage.getUser(updatedBooking.providerId);
      
      if (service && user && provider) {
        try {
          // Import required functions
          const { sendBookingStatusUpdateEmail, sendProviderStatusUpdateEmail } = await import('./email');
          const { notifyBookingStatusUpdate } = await import('./websocket');
          
          // Send email to customer
          const customerEmailSent = await sendBookingStatusUpdateEmail(user, service, updatedBooking);
          
          if (customerEmailSent) {
            console.log(`Booking status update email sent to customer (ID: ${user.id})`);
          } else {
            console.warn(`Failed to send booking status update email to customer (ID: ${user.id})`);
          }
          
          // Send email to provider
          const providerEmailSent = await sendProviderStatusUpdateEmail(provider, user, service, updatedBooking);
          
          if (providerEmailSent) {
            console.log(`Booking status update notification sent to provider (ID: ${provider.id})`);
          } else {
            console.warn(`Failed to send booking status update notification to provider (ID: ${provider.id})`);
          }
          
          // Send real-time WebSocket notifications
          const statusMessage = `Your booking for ${service.name} has been updated to ${status.toUpperCase()}${message ? `: ${message}` : ''}`;
          
          // Notify customer
          notifyBookingStatusUpdate(
            user.id,
            provider.id,
            updatedBooking, 
            service,
            statusMessage
          );
          
          console.log(`WebSocket notification sent to customer (ID: ${user.id}) for booking status update`);
          
          // Update booking to mark email as sent
          await storage.updateServiceBooking(bookingId, { emailSent: true });
        } catch (error) {
          console.error("Error sending booking status update notifications:", error);
          // Continue even if notifications fail
        }
      }
      
      res.json(updatedBooking);
    } catch (error) {
      console.error("Error updating service booking status:", error);
      res.status(500).json({ message: "Failed to update service booking status" });
    }
  });
  
