            console.warn(`Failed to send payment notification email to provider (ID: ${provider.id})`);
            // Retry once after delay
            console.log("Retrying provider email after 1 second delay...");
            await new Promise(resolve => setTimeout(resolve, 1000));
            providerEmailSent = await sendProviderNotificationEmail(provider, user, service, updatedBooking);
            console.log(`Provider email retry ${providerEmailSent ? 'successful' : 'failed'}`);
