  app.post("/api/service-bookings/:id/payment-intent", async (req: Request, res: Response) => {
    try {
      const bookingId = parseInt(req.params.id);
      const booking = await storage.getServiceBooking(bookingId);

      if (!booking) {
        return res.status(404).json({ message: "Service booking not found" });
      }

      if (booking.isPaid) {
        return res.status(400).json({ message: "Booking is already paid" });
      }

      // Get service data for the price
      const service = await storage.getService(booking.serviceId);
      if (!service) {
        return res.status(404).json({ message: "Service not found" });
      }

      // Calculate amount to charge
      const priceInCents = parseInt(parseFloat(service.price) * 100);

      // Create or retrieve a payment intent
      try {
        const { createPaymentIntent } = await import('./stripe');

        // If there's already a payment intent ID stored, use that
        if (booking.paymentIntentId) {
          // Retrieve existing payment intent
          const stripe = await import('stripe').then(module => new module.default(process.env.STRIPE_SECRET_KEY!));
          const paymentIntent = await stripe.paymentIntents.retrieve(booking.paymentIntentId);

          // Return the client secret for the frontend to use
          res.json({ clientSecret: paymentIntent.client_secret });
        } else {
          // Create a new payment intent
          const paymentIntent = await createPaymentIntent({
            amount: priceInCents,
            metadata: {
              bookingId: booking.id.toString(),
              serviceId: service.id.toString(),
              userId: booking.userId.toString(),
              providerId: service.providerId.toString()
            }
          });

          // Update the booking with the payment intent ID
          await storage.updateServiceBooking(bookingId, { 
            paymentIntentId: paymentIntent.id 
          });

          // Return the client secret for the frontend to use
          res.json({ clientSecret: paymentIntent.client_secret });
        }
      } catch (stripeError) {
        console.error("Error creating/retrieving payment intent:", stripeError);
        res.status(500).json({ message: "Failed to create payment intent" });
      }
    } catch (error) {
      console.error("Error creating payment intent for booking:", error);
      res.status(500).json({ message: "Failed to create payment intent for booking" });
    }
  });
  
  // New endpoint for direct payment intents (without prior booking creation)
  app.post("/api/service-bookings/direct-payment-intent", async (req: Request, res: Response) => {
    try {
      const { serviceId, amount, metadata } = req.body;
      
      if (!serviceId || !amount) {
        return res.status(400).json({ message: "Missing required parameters: serviceId and amount" });
      }
      
      // Get service data
      const service = await storage.getService(parseInt(serviceId));
      if (!service) {
        return res.status(404).json({ message: "Service not found" });
      }
      
      // Create a new direct payment intent
      try {
        const { createPaymentIntent } = await import('./stripe');
        
        const paymentIntent = await createPaymentIntent({
          amount: amount, // Already provided in cents from the client
          metadata: {
            serviceId: serviceId.toString(),
            directPayment: "true",
            ...metadata
          },
          description: `Direct payment for ${service.name}`
        });
        
        // Return the client secret for the frontend to use
        res.json({ 
          clientSecret: paymentIntent.client_secret,
          data: {
            serviceId,
            serviceName: service.name,
            amount
          }
        });
      } catch (stripeError) {
        console.error("Error creating direct payment intent:", stripeError);
        res.status(500).json({ message: "Failed to create direct payment intent" });
      }
    } catch (error) {
      console.error("Error processing direct payment intent request:", error);
      res.status(500).json({ message: "Failed to process direct payment request" });
    }
  });

