  // Standard payment intent status endpoint with enhanced cache controls
  app.get('/api/payment-intent-status/:id', async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      
      if (!id) {
        return res.status(400).json({ message: 'Payment intent ID is required' });
      }
      
      console.log(`Checking status for payment intent ${id}`);
      
      const { getPaymentIntentStatus } = await import('./stripe');
      const paymentIntent = await getPaymentIntentStatus(id);
      
      console.log(`Payment intent ${id} status: ${paymentIntent.status}`);
      
      // Check if this payment intent already has an associated booking
      const existingBookings = await storage.getServiceBookingsByPaymentIntentId(id);
      const hasBooking = existingBookings && existingBookings.length > 0;
      
      // Set cache control headers to prevent caching
      res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
      res.setHeader('Pragma', 'no-cache');
      
      return res.json({
        id: paymentIntent.id,
        status: paymentIntent.status,
        metadata: paymentIntent.metadata || {},
        hasBooking,
        bookingDetails: hasBooking ? {
          bookingId: existingBookings[0].id,
          serviceId: existingBookings[0].serviceId
        } : null
      });
    } catch (error: any) {
      console.error('Error getting payment intent status:', error);
      return res.status(500).json({ 
        message: 'Failed to retrieve payment intent status',
        error: error.message 
      });
    }
  });
  
