  // Email System Status and Reset Endpoint
  app.get("/api/email-status", async (req: Request, res: Response) => {
    try {
      const { emailSystem, checkSendGridApiKey, setEmailDebugMode, sendTestEmail } = await import('./email');
      
      // If reset parameter is provided, attempt to reset email system
      if (req.query.reset === 'true') {
        console.log("Resetting email system and validating API key...");
        
        // Reset error counters
        emailSystem.totalAttempts = 0;
        emailSystem.successfulAttempts = 0;
        emailSystem.failedAttempts = 0;
        emailSystem.maxCreditsExceeded = false;
        emailSystem.hasCredits = true;
        emailSystem.errorMessage = '';
        emailSystem.lastError = null;
        emailSystem.debugLogs = [];
        
        // Always enable debug mode when we reset
        setEmailDebugMode(true);
        console.log("Email debug mode enabled during system reset");
        
        // Re-validate API key
        const apiKeyValid = await checkSendGridApiKey();
      }
      
      // If test parameter is provided, send a test email
      if (req.query.test === 'true') {
        console.log("Sending test email to verify email system...");
        
        // Try to get the test destination from query params
        const testEmail = req.query.email as string || process.env.ADMIN_EMAIL;
        
        if (!testEmail) {
          console.warn("No test email address provided and no admin email configured");
          return res.status(400).json({
            message: "Cannot send test email - no destination address provided and no admin email configured",
            emailSystem: {
              isConfigured: emailSystem.isConfigured,
              isEnabled: emailSystem.isEnabled,
              hasErrors: !!emailSystem.errorMessage
            }
          });
        }
        
        // Determine the test type - 'booking' parameter sends a full booking test with PDF
        const testType = req.query.type as string || 'simple'; 
        
        try {
          console.log(`Sending ${testType} test email to ${testEmail}...`);
          const testResult = await sendTestEmail(testEmail, testType);
          console.log(`Test email result: ${testResult ? 'Success' : 'Failed'}`);
        } catch (testError) {
          console.error("Error sending test email:", testError);
          return res.status(500).json({
            message: "Failed to send test email",
            error: testError instanceof Error ? testError.message : String(testError)
          });
        }
      }
      
      // If enable_debug parameter is provided, set debug mode
      if (req.query.enable_debug !== undefined) {
        const enableDebug = req.query.enable_debug === 'true';
        console.log(`Setting email debug mode to: ${enableDebug}`);
        setEmailDebugMode(enableDebug);
      }
      
      // Return current status
      return res.json({
        emailSystem: {
          isConfigured: emailSystem.isConfigured,
          isEnabled: emailSystem.isEnabled,
          hasCredits: emailSystem.hasCredits,
          maxCreditsExceeded: emailSystem.maxCreditsExceeded,
          isApiKeyWorking: emailSystem.isApiKeyWorking,
          lastApiKeyCheck: emailSystem.lastApiKeyCheck,
          errorMessage: emailSystem.errorMessage,
          stats: {
            totalAttempts: emailSystem.totalAttempts,
            successfulAttempts: emailSystem.successfulAttempts,
            failedAttempts: emailSystem.failedAttempts,
            lastSuccessfulSendTime: emailSystem.lastSuccessfulSendTime
          },
          debug: emailSystem.debug,
          recentLogs: emailSystem.debugLogs.slice(0, 10) // Only return the 10 most recent logs
        },
        environment: {
          sendgridApiKeyPresent: !!process.env.SENDGRID_API_KEY,
          sendgridApiKeyLength: process.env.SENDGRID_API_KEY ? process.env.SENDGRID_API_KEY.length : 0,
          verifiedSenderEmail: process.env.VERIFIED_SENDER_EMAIL || null,
          adminEmail: process.env.ADMIN_EMAIL || null
        }
      });
    } catch (error) {
      console.error("Error getting email system status:", error);
      return res.status(500).json({
        message: "Failed to retrieve email system status",
        error: error instanceof Error ? error.message : String(error)
      });
    }
  });

