  app.get("/api/service-time-slots", async (req: Request, res: Response) => {
    try {
      // Check for authentication
      const user = await getCurrentUser(req);
      
      // If unauthorized and requesting specific provider's slots, reject
      if (!user && req.query.providerId) {
        return res.status(401).json({ error: "Authentication required to view provider time slots" });
      }
      
      const { serviceId, providerId, date } = req.query;
      let timeSlots: ServiceTimeSlot[] = [];
      
      if (serviceId) {
        const id = parseInt(serviceId as string);
        if (req.query.available === 'true') {
          timeSlots = await storage.getAvailableServiceTimeSlots(id);
        } else {
          // If requesting all slots for a service, require auth if not available=true
          if (req.query.available !== 'true' && !user) {
            return res.status(401).json({ error: "Authentication required to view all service time slots" });
          }
          timeSlots = await storage.getServiceTimeSlotsByService(id);
        }
      } else if (providerId) {
        const id = parseInt(providerId as string);
        
        // For provider-specific slots, verify the user is the provider or an admin
        if (user && (user.id === id || isAdminRole(user.role))) {
          if (date) {
            const dateObj = new Date(date as string);
            timeSlots = await storage.getServiceTimeSlotsByDate(id, dateObj);
          } else {
            timeSlots = await storage.getServiceTimeSlotsByProvider(id);
          }
        } else {
          return res.status(403).json({ error: "You can only view your own time slots" });
        }
      } else {
        return res.status(400).json({ error: "serviceId or providerId parameter is required" });
      }
      
      res.json(timeSlots);
    } catch (error) {
      console.error("Error fetching time slots:", error);
      res.status(500).json({ error: "Failed to fetch time slots" });
    }
  });

  app.post("/api/service-time-slots", async (req: Request, res: Response) => {
    try {
      // Authenticate user and check if they're the service provider
      const user = await getCurrentUser(req);
      if (!user) {
        return res.status(401).json({ error: "Unauthorized" });
      }
      
      const { serviceId, providerId, date, startTime, endTime, maxBookings, notes } = req.body;
      
      // Validate that providerId matches the current user
      if (providerId !== user.id) {
        return res.status(403).json({ error: "You can only create time slots for your own services" });
      }
      
      // Get the service to verify ownership
      const service = await storage.getService(serviceId);
      if (!service) {
        return res.status(404).json({ error: "Service not found" });
      }
      
      if (service.providerId !== user.id) {
        return res.status(403).json({ error: "You can only create time slots for your own services" });
      }
      
      // Process date and time strings to create Date objects
      const timeSlotDate = new Date(date);
      const startTimeDate = new Date(startTime);
      const endTimeDate = new Date(endTime);
      
      // Validate the timeSlot data
      const now = new Date();
      if (timeSlotDate < now) {
        return res.status(400).json({ error: "Time slot date cannot be in the past" });
      }
      
      // Validate that endTime is after startTime
      if (endTimeDate <= startTimeDate) {
        return res.status(400).json({ error: "End time must be after start time" });
      }
      
      // Create time slot
      const timeSlot = await storage.createServiceTimeSlot({
        serviceId,
        providerId,
        date: timeSlotDate,
        startTime: startTimeDate,
        endTime: endTimeDate,
        status: TimeSlotStatus.AVAILABLE,
        maxBookings: maxBookings || 1,
        currentBookings: 0,
        notes: notes || null
      });
      
      res.status(201).json(timeSlot);
    } catch (error) {
      console.error("Error creating time slot:", error);
      res.status(500).json({ error: "Failed to create time slot" });
    }
  });

  app.patch("/api/service-time-slots/:id", async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const timeSlot = await storage.getServiceTimeSlot(id);
      
      if (!timeSlot) {
        return res.status(404).json({ error: "Time slot not found" });
      }
      
      // Authenticate user and check if they're the service provider
      const user = await getCurrentUser(req);
      if (!user) {
        return res.status(401).json({ error: "Unauthorized" });
      }
      
      // Check if the user owns this time slot
      if (timeSlot.providerId !== user.id) {
        return res.status(403).json({ error: "You can only update your own time slots" });
      }
      
      // Only allow certain fields to be updated
      const { startTime, endTime, status, maxBookings, notes } = req.body;
      
      // Convert date strings to Date objects if provided
      const updateData: Partial<InsertServiceTimeSlot> = {};
      
      if (startTime) {
        updateData.startTime = new Date(startTime);
      }
      
      if (endTime) {
        updateData.endTime = new Date(endTime);
      }
      
      if (status) {
        updateData.status = status;
      }
      
      if (notes !== undefined) {
        updateData.notes = notes;
      }
      
      // Don't allow reducing maxBookings below currentBookings
      if (maxBookings !== undefined) {
        if (maxBookings < timeSlot.currentBookings) {
          return res.status(400).json({ 
            error: "Cannot reduce maximum bookings below current booking count" 
          });
        }
        updateData.maxBookings = maxBookings;
      }
      
      // Validate that if both start and end times are provided, end is after start
      if (updateData.startTime && updateData.endTime) {
        if (updateData.endTime <= updateData.startTime) {
          return res.status(400).json({ error: "End time must be after start time" });
        }
      }
      
      // Update the time slot
      const updatedTimeSlot = await storage.updateServiceTimeSlot(id, updateData);
      
      res.json(updatedTimeSlot);
    } catch (error) {
      console.error("Error updating time slot:", error);
      res.status(500).json({ error: "Failed to update time slot" });
    }
  });

  app.delete("/api/service-time-slots/:id", async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const timeSlot = await storage.getServiceTimeSlot(id);
      
      if (!timeSlot) {
        return res.status(404).json({ error: "Time slot not found" });
      }
      
      // Authenticate user and check if they're the service provider
      const user = await getCurrentUser(req);
      if (!user) {
        return res.status(401).json({ error: "Unauthorized" });
      }
      
      // Check if the user owns this time slot
      if (timeSlot.providerId !== user.id) {
        return res.status(403).json({ error: "You can only delete your own time slots" });
      }
      
      // Don't allow deletion if there are already bookings
      if (timeSlot.currentBookings > 0) {
        return res.status(400).json({ 
          error: "Cannot delete time slot with existing bookings. Cancel the bookings first." 
        });
      }
      
      // Delete the time slot
      const success = await storage.deleteServiceTimeSlot(id);
      
      if (success) {
        res.status(200).json({ message: "Time slot deleted successfully" });
      } else {
        res.status(500).json({ error: "Failed to delete time slot" });
      }
    } catch (error) {
      console.error("Error deleting time slot:", error);
      res.status(500).json({ error: "Failed to delete time slot" });
    }
  });

