  app.get("/api/notifications", async (req: Request, res: Response) => {
    try {
      // Try to get user ID from multiple sources
      let userId = req.session?.user?.id;
      
      // If not in session, check query parameters
      if (!userId && req.query.userId) {
        userId = parseInt(req.query.userId as string, 10);
      }
      
      // If still no userId, check authorization header
      if (!userId && req.headers.authorization) {
        try {
          const authHeader = req.headers.authorization;
          if (authHeader.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            // Simple token format: "userId:role"
            const [userIdStr] = token.split(':');
            userId = parseInt(userIdStr, 10);
          }
        } catch (authError) {
          console.error("Error parsing authorization header:", authError);
        }
      }
      
      if (!userId) {
        console.log("Notification API authentication failed - no valid user ID found");
        return res.status(401).json({ message: "Authentication required" });
      }

      const unreadOnly = req.query.unreadOnly === 'true';
      
      
      const notifCacheKey = `notif_${userId}_${unreadOnly ? "unread" : "all"}`;
      const cachedNotifs = notificationsCache.get(notifCacheKey);
      if (cachedNotifs) return res.json(cachedNotifs);

      let notifications;
      if (unreadOnly) {
        notifications = await storage.getUnreadUserNotificationsByUser(userId);
      } else {
        notifications = await storage.getUserNotificationsByUser(userId);
      }

      notificationsCache.set(notifCacheKey, notifications);
      res.json(notifications);
    } catch (error) {
      console.error("Error fetching notifications:", error);
      res.status(500).json({ message: "Failed to fetch notifications" });
    }
  });

  app.post("/api/notifications/:id/read", async (req: Request, res: Response) => {
    try {
      // Try to get user ID from multiple sources
      let userId = req.session?.user?.id;
      
      // If not in session, check query or body
      if (!userId) {
        if (req.query.userId) {
          userId = parseInt(req.query.userId as string, 10);
        } else if (req.body.userId) {
          userId = parseInt(req.body.userId as string, 10);
        }
      }
      
      if (!userId) {
        return res.status(401).json({ message: "Authentication required" });
      }

      const id = parseInt(req.params.id);
      const notification = await storage.getUserNotification(id);
      
      if (!notification) {
        return res.status(404).json({ message: "Notification not found" });
      }
      
      // Security check - ensure users can only mark their own notifications as read
      if (notification.userId !== userId) {
        return res.status(403).json({ message: "Access denied" });
      }

      const updatedNotification = await storage.markUserNotificationAsRead(id);
      // Bust cache so next fetch reflects the read state
      notificationsCache.del(`notif_${userId}_all`);
      notificationsCache.del(`notif_${userId}_unread`);
      res.json(updatedNotification);
    } catch (error) {
      console.error("Error marking notification as read:", error);
      res.status(500).json({ message: "Failed to mark notification as read" });
    }
  });

