  /**
   * Send a custom real-time notification to a specific user via WebSocket
   */
  app.post("/api/notifications/send", async (req: Request, res: Response) => {
    try {
      const { userId, type, data } = req.body;
      
      if (!userId || !type || !data) {
        return res.status(400).json({ 
          message: "Missing required fields", 
          required: "userId, type, data" 
        });
      }
      
      // Validate notification type against the enum
      if (!Object.values(NotificationType).includes(type)) {
        return res.status(400).json({
          message: "Invalid notification type",
          validTypes: Object.values(NotificationType)
        });
      }
      
      // Send real-time notification via WebSocket
      notifyUserWithData(parseInt(userId, 10), type, data);
      
      // Optionally persist notification to database
      if (req.body.persist === true) {
        try {
          await storage.createUserNotification({
            userId: parseInt(userId, 10),
            fromUserId: req.body.fromUserId ? parseInt(req.body.fromUserId, 10) : undefined,
            type,
            title: data.title || "New Notification",
            message: data.message || JSON.stringify(data),
            actionLink: data.actionLink,
            actionText: data.actionText
          });
        } catch (dbError) {
          console.error("Failed to persist notification to database:", dbError);
          // Continue even if persistence fails - the WebSocket notification was sent
        }
      }
      
      res.json({ success: true, message: "Notification sent" });
    } catch (error) {
      console.error("Error sending notification:", error);
      res.status(500).json({ message: "Failed to send notification" });
    }
  });

