  // Admin: Reset all user consents for a document type (forces everyone to re-accept)
  app.post("/api/admin/legal/reset-consents", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { type } = req.body; // "terms", "privacy", or "all"
      if (!type || !["terms", "privacy", "all"].includes(type)) {
        return res.status(400).json({ message: "type must be 'terms', 'privacy', or 'all'" });
      }

      let updatedCount = 0;
      if (type === "terms" || type === "all") {
        const result = await db.execute(
          sql`UPDATE legal_consent SET terms_accepted = false, terms_accepted_at = NULL, updated_at = NOW()`
        );
        updatedCount += Number((result as any).rowCount ?? 0);
      }
      if (type === "privacy" || type === "all") {
        const result = await db.execute(
          sql`UPDATE legal_consent SET privacy_accepted = false, privacy_accepted_at = NULL, updated_at = NOW()`
        );
        updatedCount += Number((result as any).rowCount ?? 0);
      }

      await storage.createAdminAction({
        adminId: Number(req.query.adminId || 1),
        actionType: "legal_consent_reset",
        targetId: 0,
        targetType: "legal_consent",
        details: `Reset ${type} consent for all users — ${updatedCount} records updated`
      });

      res.json({ success: true, type, message: `Reset ${type} consent for all users. ${updatedCount} records updated.` });
    } catch (error) {
      console.error("Error resetting legal consents:", error);
      res.status(500).json({ message: "Failed to reset consents" });
    }
  });

