  /**
   * Get the user's legal consent history
   */
  app.get("/api/legal/user-consents", async (req: Request, res: Response) => {
    try {
      let userId: number | undefined;
      
      // Try to get user ID from session
      if (req.session && (req.session as any).userId) {
        userId = (req.session as any).userId;
      } 
      // Check Firebase auth from custom property
      else if ((req as any).user && (req as any).user.id) {
        userId = (req as any).user.id;
      }
      // Try authorization header
      else if (req.headers.authorization) {
        const authHeader = req.headers.authorization;
        if (authHeader.startsWith('Bearer ')) {
          const token = authHeader.substring(7);
          
          try {
            // In a real implementation, we would verify the Firebase token here
            // and extract the user ID from the verified token payload
            // For now, just check if we have a session with the user
            if (req.session && (req.session as any).firebaseUid) {
              const firebaseUid = (req.session as any).firebaseUid;
              const user = await storage.getUserByFirebaseUid(firebaseUid);
              if (user) {
                userId = user.id;
              }
            }
          } catch (tokenError) {
            console.error("Error extracting user from token:", tokenError);
          }
        }
      }
      
      if (!userId) {
        return res.status(401).json({ 
          message: "Authentication required to view consent history" 
        });
      }
      
      // Get user consent history
      const consent = await storage.getUserConsent(userId);
      
      if (!consent) {
        return res.json([]);  // Return empty array if no consents found
      }
      
      // Return as array to support future multi-version consent history
      res.json([consent]);
    } catch (error) {
      console.error("Error fetching user consent history:", error);
      res.status(500).json({ message: "Failed to fetch user consent history" });
    }
  });

  /**
   * Record legal consent during signup process
   * This endpoint is used before the user has been fully created
   */
  app.post("/api/signup/legal-consent", async (req: Request, res: Response) => {
    try {
      const { termsAccepted, privacyAccepted, dataProcessingAccepted, communicationAccepted, consentVersion } = req.body;
      
      // Try to get user ID from various sources
      let userId: number | undefined;
      
      // Try to get from session
      if (req.session && (req.session as any).userId) {
        userId = (req.session as any).userId;
      } 
      // Try to get from Firebase user object
      else if ((req as any).user && (req as any).user.id) {
        userId = (req as any).user.id;
      }
      // Try to get from authorization header (Firebase token)
      else if (req.headers.authorization) {
        try {
          const authHeader = req.headers.authorization;
          if (authHeader.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            
            // Extract Firebase UID from token if possible
            // This code is simplified for brevity - refer to /api/legal/accept-terms for full token parsing
            if (token.length > 100) {
              console.log("Attempting to extract user ID from Firebase token for signup consent");
              
              // Token parsing code omitted - admin consent endpoint has the full implementation
              // If implemented here, this would attempt to look up the user by Firebase UID
            }
          }
        } catch (error) {
          console.error("Error parsing authorization header for signup consent:", error);
        }
      }
      
      // Get the IP and user agent for audit purposes
      const ipAddress = req.headers['x-forwarded-for'] || req.socket.remoteAddress;
      const userAgent = req.headers['user-agent'];
      
      // If we have a userId, store the consent now
      if (userId) {
        console.log(`Recording legal consent during signup for user ID: ${userId}`);
        
        // Check if consent already exists
        const existingConsent = await storage.getUserConsent(userId);
        
        if (existingConsent) {
          // Update existing consent record
          await storage.updateUserConsent(userId, {
            termsAccepted: termsAccepted === true,
            privacyAccepted: privacyAccepted === true,
            termsAcceptedAt: termsAccepted ? new Date() : existingConsent.termsAcceptedAt,
            privacyAcceptedAt: privacyAccepted ? new Date() : existingConsent.privacyAcceptedAt,
            ipAddress: ipAddress as string,
            userAgent: userAgent as string,
            updatedAt: new Date()
          });
        } else {
          // Create new consent record
          await storage.recordUserConsent({
            userId,
            termsAccepted: termsAccepted === true,
            privacyAccepted: privacyAccepted === true,
            termsAcceptedAt: termsAccepted ? new Date() : null,
            privacyAcceptedAt: privacyAccepted ? new Date() : null,
            ipAddress: ipAddress as string,
            userAgent: userAgent as string
          });
        }
        
        return res.status(200).json({ 
          success: true, 
          message: "Legal consent recorded for user",
          userId
        });
      } else {
        console.log("No user ID available during signup - consent will be stored when user is created");
        
        // For signup without userId, we acknowledge the consent without storing it yet
        // The actual consent record will be created when the user is fully registered
        // and we have a proper userId assigned
        
        // Store consent in session so it can be associated with the user once created
        if (req.session) {
          (req.session as any).pendingConsent = {
            termsAccepted,
            privacyAccepted,
            dataProcessingAccepted,
            communicationAccepted,
            consentVersion,
            consentTimestamp: new Date().toISOString(),
            ipAddress,
            userAgent
          };
        }
        
        return res.status(200).json({ 
          success: true, 
          message: "Legal consent acknowledged for signup, will be recorded when user is created",
          pendingConsent: true
        });
      }
    } catch (error) {
      console.error("Error recording signup consent:", error);
      res.status(500).json({ message: "Failed to record signup consent" });
    }
  });
  
