  app.post("/api/users/:userId/data-deletion-request", async (req: Request, res: Response) => {
    try {
      const userId = parseInt(req.params.userId);
      
      // Validate user exists
      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }
      
      // Check if there is already a pending or processing request
      const existingRequests = await storage.getDataDeletionRequestsByUser(userId);
      const activeRequest = existingRequests.find(
        req => req.status === "pending" || req.status === "processing"
      );
      
      if (activeRequest) {
        return res.status(409).json({ 
          message: "A data deletion request is already in progress",
          requestId: activeRequest.id,
          status: activeRequest.status
        });
      }
      
      // Create new deletion request
      const request = await storage.createDataDeletionRequest({
        userId,
        reason: req.body.reason || "User requested data deletion",
        additionalInfo: req.body.additionalInfo
      });
      
      // Create notifications for all admins
      const adminUsers = await storage.getUsersByRole('admin');
      
      for (const adminUser of adminUsers) {
        await storage.createAdminNotification({
          toUserId: adminUser.id,
          title: "New Data Deletion Request",
          message: `User ${user.displayName} has requested their data to be deleted. Reason: ${request.reason}`,
          type: "data_deletion_request",
          actionLink: "/admin/data-deletion-requests",
          actionText: "Review Request"
        });
      }
      
      res.status(201).json(request);
    } catch (error) {
      console.error("Error creating data deletion request:", error);
      res.status(500).json({ message: "Failed to create data deletion request" });
    }
  });
  
  app.get("/api/users/:userId/data-deletion-requests", async (req: Request, res: Response) => {
    try {
      const userId = parseInt(req.params.userId);
      const requests = await storage.getDataDeletionRequestsByUser(userId);
      res.json(requests);
    } catch (error) {
      console.error("Error fetching data deletion requests:", error);
      res.status(500).json({ message: "Failed to fetch data deletion requests" });
    }
  });
  
  app.get("/api/admin/data-deletion-requests", requireAdmin, async (req: Request, res: Response) => {
    try {
      const status = req.query.status as string;
      let requests;
      
      if (status) {
        requests = await storage.getDataDeletionRequestsByStatus(status);
      } else {
        // Get all requests and sort by status and date
        const allRequests = [];
        const pendingRequests = await storage.getDataDeletionRequestsByStatus("pending");
        const processingRequests = await storage.getDataDeletionRequestsByStatus("processing");
        const completedRequests = await storage.getDataDeletionRequestsByStatus("approved");
        const rejectedRequests = await storage.getDataDeletionRequestsByStatus("rejected");
        
        allRequests.push(...pendingRequests, ...processingRequests, ...completedRequests, ...rejectedRequests);
        requests = allRequests;
      }
      
      // Enrich with user information
      const enrichedRequests = await Promise.all(
        requests.map(async (request) => {
          const user = await storage.getUser(request.userId);
          return {
            ...request,
            user: user ? {
              id: user.id,
              displayName: user.displayName,
              email: user.email,
              role: user.role
            } : null
          };
        })
      );
      
      res.json(enrichedRequests);
    } catch (error) {
      console.error("Error fetching data deletion requests:", error);
      res.status(500).json({ message: "Failed to fetch data deletion requests" });
    }
  });
  
  app.post("/api/admin/data-deletion-requests/:id/process", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const adminId = Number(req.query.adminId || 1);
      const { status, notes } = req.body;
      
      if (!["approved", "rejected", "processing"].includes(status)) {
        return res.status(400).json({ message: "Invalid status. Must be 'approved', 'rejected', or 'processing'" });
      }
      
      const processedRequest = await storage.processDataDeletionRequest(id, adminId, status, notes);
      
      if (!processedRequest) {
        return res.status(404).json({ message: "Data deletion request not found" });
      }
      
      // Record admin action
      await storage.createAdminAction({
        adminId,
        actionType: "data_deletion_request_processed",
        targetId: id,
        targetType: "data_deletion_request",
        details: `Data deletion request ${status}. ${notes ? `Notes: ${notes}` : ""}`
      });
      
      res.json(processedRequest);
    } catch (error) {
      console.error("Error processing data deletion request:", error);
      res.status(500).json({ message: "Failed to process data deletion request" });
    }
  });

  /**
   * Contact Form Submissions
   */
  app.post("/api/contact", async (req: Request, res: Response) => {
    try {
      console.log("Contact form submission received:", req.body);
      
      // Validate the submission data
      const contactData = insertContactSubmissionSchema.parse(req.body);
      console.log("Contact data parsed successfully:", contactData);
      
      // Create the contact submission record
      const submission = await storage.createContactSubmission(contactData);
      console.log("Contact submission created:", submission);
      
      if (!submission) {
        console.error("Failed to create contact submission - no submission returned");
        return res.status(500).json({ message: "Failed to create contact submission" });
      }
      
      // Send email notification
      let notificationSent = false;
      try {
        notificationSent = await sendContactFormNotification(submission);
        console.log(`Email notification ${notificationSent ? 'sent' : 'failed'}`);
      } catch (emailError) {
        console.error("Error sending email notification:", emailError);
      }
      
      // Create a notification for admin users
      try {
        // Get all admin users
        const adminUsers = await storage.getUsersByRole('admin');
        console.log(`Found ${adminUsers.length} admin users for notifications`);
        
        // Create a notification for each admin
        for (const adminUser of adminUsers) {
          const notification = await storage.createAdminNotification({
            toUserId: adminUser.id,
            title: "New Contact Form Submission",
            message: `${submission.name} has submitted a contact form about: ${submission.subject}`,
            type: "contact_submission",
            actionLink: "/admin/contact-submissions",
            actionText: "View Submission"
          });
          console.log(`Created notification for admin ${adminUser.id}:`, notification);
        }
        
        console.log(`Sent notifications to ${adminUsers.length} admins`);
      } catch (notifyError) {
        console.error("Error creating admin notifications:", notifyError);
        // Continue even if notification creation fails
      }
      
      // Return success response with submission and notification status
      res.status(201).json({ 
        submission, 
        emailSent: notificationSent,
        message: "Contact form submitted successfully" 
      });
    } catch (error) {
      console.error("Error processing contact form submission:", error);
      
      if (error instanceof z.ZodError) {
        return res.status(400).json({ 
          message: "Invalid contact form data", 
          errors: error.errors 
        });
      }
      
      res.status(500).json({ message: "Failed to process contact form submission" });
    }
  });
  
