  app.patch("/api/admin/contact-submissions/:id", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const updateData = req.body;
      
      // Get the current submission to check if it exists
      const currentSubmission = await storage.getContactSubmission(id);
      if (!currentSubmission) {
        return res.status(404).json({ message: "Contact submission not found" });
      }
      
      // Update the submission
      const updatedSubmission = await storage.updateContactSubmission(id, updateData);
      
      if (!updatedSubmission) {
        return res.status(500).json({ message: "Failed to update contact submission" });
      }
      
      res.json(updatedSubmission);
    } catch (error) {
      console.error("Error updating contact submission:", error);
      res.status(500).json({ message: "Failed to update contact submission" });
    }
  });
  
  /**
   * Resolve a contact form submission (admin only)
   */
  app.post("/api/admin/contact-submissions/:id/resolve", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const adminId = Number(req.query.adminId || 1);
      const { notes } = req.body;
      
      // Get the current submission to check if it exists
      const currentSubmission = await storage.getContactSubmission(id);
      if (!currentSubmission) {
        return res.status(404).json({ message: "Contact submission not found" });
      }
      
      if (currentSubmission.isResolved) {
        return res.status(400).json({ message: "Contact submission is already resolved" });
      }
      
      // Resolve the submission
      const resolvedSubmission = await storage.resolveContactSubmission(id, adminId, notes);
      
      if (!resolvedSubmission) {
        return res.status(500).json({ message: "Failed to resolve contact submission" });
      }
      
      // Record admin action
      await storage.createAdminAction({
        adminId,
        actionType: "contact_submission_resolved",
        targetId: id,
        targetType: "contact_submission",
        details: `Contact submission resolved. ${notes ? `Notes: ${notes}` : ""}`
      });
      
      res.json(resolvedSubmission);
    } catch (error) {
      console.error("Error resolving contact submission:", error);
      res.status(500).json({ message: "Failed to resolve contact submission" });
    }
  });

