  app.get("/api/legal/user-consent", async (req: Request, res: Response) => {
    try {
      // Get user ID from multiple sources
      let userId: number | undefined;
      
      // Try to get from session
      if (req.session && req.session.userId) {
        userId = req.session.userId;
      } 
      // Try to get from Firebase auth
      else if (req.user && req.user.id) {
        userId = req.user.id;
      }
      // Try to get from authorization header (Firebase token)
      else if (req.headers.authorization) {
        try {
          const authHeader = req.headers.authorization;
          if (authHeader.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            
            // Check if this is a Firebase token
            if (token.length > 100) {
              console.log(`Processing Firebase token for user consent (length: ${token.length})`);
              try {
                // Try to decode base64 sections of the JWT to extract the payload
                const tokenParts = token.split('.');
                if (tokenParts.length === 3) {
                  // Try to decode the payload (middle part)
                  const payloadBase64 = tokenParts[1];
                  // Make base64 URL safe by replacing chars and adding padding
                  const base64 = payloadBase64.replace(/-/g, '+').replace(/_/g, '/');
                  const padding = '='.repeat((4 - base64.length % 4) % 4);
                  const paddedBase64 = base64 + padding;
                  
                  try {
                    // Decode the payload
                    const decodedPayload = Buffer.from(paddedBase64, 'base64').toString('utf8');
                    const payload = JSON.parse(decodedPayload);
                    
                    // Extract the sub (subject) field which contains the Firebase UID
                    if (payload && payload.sub) {
                      console.log("Found Firebase UID in token:", payload.sub);
                      
                      // Look up the user by Firebase UID
                      const user = await storage.getUserByFirebaseUid(payload.sub);
                      if (user) {
                        console.log("Authenticated user via Firebase token:", user.id);
                        userId = user.id;
                      }
                    } else if (payload && payload.user_id) {
                      // Some Firebase tokens might use user_id instead of sub
                      console.log("Found Firebase UID in token (user_id):", payload.user_id);
                      
                      // Look up the user by Firebase UID
                      const user = await storage.getUserByFirebaseUid(payload.user_id);
                      if (user) {
                        console.log("Authenticated user via Firebase token:", user.id);
                        userId = user.id;
                      }
                    }
                  } catch (decodeError) {
                    console.error("Error decoding token payload:", decodeError);
                  }
                }
              } catch (tokenError) {
                console.error("Error processing Firebase token for consent:", tokenError);
              }
            }
          }
        } catch (error) {
          console.error("Error parsing authorization header for consent:", error);
        }
      }
      
      // Try to get from query parameters
      if (!userId && req.query.userId) {
        const queryUserId = parseInt(req.query.userId as string, 10);
        if (!isNaN(queryUserId)) {
          userId = queryUserId;
        }
      }
      
      // Try to get from localStorage via custom header
      if (!userId && req.headers['x-user-id']) {
        const headerUserId = parseInt(req.headers['x-user-id'] as string, 10);
        if (!isNaN(headerUserId)) {
          userId = headerUserId;
        }
      }
      
      if (!userId) {
        console.log("No userId found for consent check - headers:", Object.keys(req.headers));
        return res.status(401).json({ 
          message: "User not authenticated",
          details: {
            sessionExists: !!req.session,
            hasAuthorization: !!req.headers.authorization,
            headerUserId: req.headers['x-user-id'],
            queryUserId: req.query.userId
          } 
        });
      }
      
      const consent = await storage.getUserConsent(userId);
      
      if (!consent) {
        // Return a default state if no consent record exists
        return res.json({
          userId,
          termsAccepted: false,
          privacyAccepted: false,
          termsAcceptedAt: null,
          privacyAcceptedAt: null
        });
      }
      
      res.json(consent);
    } catch (error) {
      console.error("Error fetching user consent:", error);
      res.status(500).json({ message: "Failed to fetch user consent" });
    }
  });
  
