  app.post("/api/legal/accept-privacy", async (req: Request, res: Response) => {
    try {
      // Get user ID from multiple sources (session, headers, query params, request body)
      let userId: number | undefined;
      
      // Try to get from session (primary source)
      if (req.session && (req.session as any).userId) {
        userId = (req.session as any).userId;
      }
      
      // Try to get from Firebase auth user object
      if (!userId && (req as any).user && (req as any).user.id) {
        userId = (req as any).user.id;
      }
      
      // Try to get from authorization header (Firebase token)
      if (!userId && req.headers.authorization) {
        try {
          const authHeader = req.headers.authorization;
          if (authHeader.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            
            // Check if this is a Firebase token
            if (token.length > 100) {
              console.log(`Processing Firebase token for privacy policy acceptance (length: ${token.length})`);
              try {
                // Try to decode base64 sections of the JWT to extract the payload
                const tokenParts = token.split('.');
                if (tokenParts.length === 3) {
                  // Try to decode the payload (middle part)
                  const payloadBase64 = tokenParts[1];
                  // Make base64 URL safe by replacing chars and adding padding
                  const base64 = payloadBase64.replace(/-/g, '+').replace(/_/g, '/');
                  const padding = '='.repeat((4 - base64.length % 4) % 4);
                  const paddedBase64 = base64 + padding;
                  
                  try {
                    // Decode the payload
                    const decodedPayload = Buffer.from(paddedBase64, 'base64').toString('utf8');
                    const payload = JSON.parse(decodedPayload);
                    
                    // Extract the sub (subject) field which contains the Firebase UID
                    if (payload && payload.sub) {
                      console.log("Found Firebase UID in token for privacy policy acceptance:", payload.sub);
                      
                      // Look up the user by Firebase UID
                      const user = await storage.getUserByFirebaseUid(payload.sub);
                      if (user) {
                        console.log("Authenticated user via Firebase token for privacy policy acceptance:", user.id);
                        userId = user.id;
                      }
                    } else if (payload && payload.user_id) {
                      // Some Firebase tokens might use user_id instead of sub
                      console.log("Found Firebase UID in token (user_id) for privacy policy acceptance:", payload.user_id);
                      
                      // Look up the user by Firebase UID
                      const user = await storage.getUserByFirebaseUid(payload.user_id);
                      if (user) {
                        console.log("Authenticated user via Firebase token for privacy policy acceptance:", user.id);
                        userId = user.id;
                      }
                    }
                  } catch (decodeError) {
                    console.error("Error decoding token payload for privacy policy acceptance:", decodeError);
                  }
                }
              } catch (tokenError) {
                console.error("Error processing Firebase token for privacy policy acceptance:", tokenError);
              }
            }
          }
        } catch (error) {
          console.error("Error parsing authorization header for privacy policy acceptance:", error);
        }
      }
      
      // Try to get from headers (sent by client for auth)
      if (!userId && req.headers['x-user-id']) {
        userId = parseInt(req.headers['x-user-id'] as string);
      }
      
      // Try to get from request body (explicit inclusion)
      if (!userId && req.body && req.body.userId) {
        userId = parseInt(req.body.userId.toString());
      }
      
      // If still no userId, authentication has failed
      if (!userId) {
        return res.status(401).json({ 
          message: "User not authenticated",
          details: {
            sessionExists: !!req.session,
            headerUserId: req.headers['x-user-id'],
            bodyUserId: req.body?.userId
          }
        });
      }
      
      console.log(`Processing privacy policy acceptance for user ID: ${userId}`);
      
      // Get the IP and user agent for audit purposes
      const ipAddress = req.headers['x-forwarded-for'] || req.socket.remoteAddress;
      const userAgent = req.headers['user-agent'];
      
      // Fetch user data for email notification
      const user = await storage.getUser(userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }
      
      // Check if consent already exists
      const existingConsent = await storage.getUserConsent(userId);
      
      let consentRecord;
      
      if (existingConsent) {
        // Update existing consent record
        consentRecord = await storage.updateUserConsent(userId, {
          privacyAccepted: true,
          privacyAcceptedAt: new Date(),
          ipAddress: ipAddress as string,
          userAgent: userAgent as string,
          updatedAt: new Date()
        });
      } else {
        // Create new consent record
        consentRecord = await storage.recordUserConsent({
          userId,
          termsAccepted: false,  // Default for new record
          privacyAccepted: true,
          privacyAcceptedAt: new Date(),
          ipAddress: ipAddress as string,
          userAgent: userAgent as string
        });
      }
      
      // Send notification email to admin with user acceptance details
      try {
        const emailSent = await sendPrivacyPolicyAcceptanceNotification(
          user,
          ipAddress as string, 
          userAgent as string
        );
        
        if (emailSent) {
          console.log(`Privacy policy acceptance notification email sent for user ${userId}`);
        } else {
          console.warn(`Failed to send privacy policy acceptance notification email for user ${userId}`);
        }
      } catch (emailError) {
        console.error("Error sending privacy policy acceptance notification:", emailError);
        // Continue despite email error (don't block the consent recording)
      }
      
      return res.json({
        ...consentRecord,
        notificationSent: true
      });
    } catch (error) {
      console.error("Error recording privacy acceptance:", error);
      res.status(500).json({ message: "Failed to record privacy acceptance", error });
    }
  });

