  // Add a dedicated endpoint for direct unblocking without authentication middleware complexity
  app.delete("/api/users/direct-unblock/:blockedId", async (req: Request, res: Response) => {
    try {
      // Force content type to ensure client receives JSON
      res.setHeader('Content-Type', 'application/json');
      
      const blockedId = parseInt(req.params.blockedId);
      if (isNaN(blockedId)) {
        return res.status(400).json({ message: "Invalid user ID" });
      }
      
      // Authorization should ideally still be checked, but this is a direct bypass endpoint
      // In a production environment, you would want to ensure proper authentication
      // For this direct endpoint, we'll extract the user ID from tokens if present
      let blockerId = null;
      const authHeader = req.headers.authorization;
      
      if (authHeader && authHeader.startsWith('Bearer ')) {
        const token = authHeader.substring(7);
        try {
          const decoded = await auth.verifyIdToken(token);
          if (decoded.uid) {
            const user = await storage.getUserByFirebaseUid(decoded.uid);
            if (user) {
              blockerId = user.id;
            }
          }
        } catch (tokenError) {
          console.error("Token verification failed:", tokenError);
          // Continue with null blockerId if token verification fails
        }
      }
      
      if (!blockerId) {
        return res.status(401).json({ message: "Authentication required to unblock users" });
      }
      
      console.log(`Direct unblock: User ${blockerId} attempting to unblock user ${blockedId}`);
      
      // Find the user block to delete
      const blocks = await storage.getUserBlocksByBlocker(blockerId);
      const blockToDelete = blocks.find(block => block.blockedId === blockedId);
      
      if (!blockToDelete) {
        return res.status(404).json({ message: "User block not found" });
      }
      
      // Actually delete the block
      const success = await storage.deleteUserBlock(blockToDelete.id);
      
      if (success) {
        console.log(`Direct unblock: Successfully unblocked user ${blockedId}`);
        return res.status(200).json({ message: "User unblocked successfully" });
      } else {
        console.error(`Direct unblock: Failed to unblock user ${blockedId}`);
        return res.status(500).json({ message: "Failed to unblock user" });
      }
    } catch (error) {
      console.error("Error in direct user unblock:", error);
      res.status(500).json({ message: "Server error while trying to unblock user" });
    }
  });
  
