  app.get("/api/admin/moderation/flags", authenticateJWT2, isAdmin, async (req: Request, res: Response) => {
    try {
      const status = req.query.status as string || 'pending';
      const flags = await storage.getContentFlagsByStatus(status);
      
      // Enrich the flags with content details
      const enrichedFlags = await Promise.all(
        flags.map(async (flag) => {
          let contentDetails = null;
          let reporterDetails = null;
          
          // Get content details based on type
          if (flag.contentType === 'post') {
            const post = await storage.getPost(flag.contentId);
            if (post) {
              contentDetails = {
                title: `Post #${post.id}`,
                content: post.content,
                createdAt: post.createdAt
              };
            }
          } else if (flag.contentType === 'comment') {
            const comment = await storage.getComment(flag.contentId);
            if (comment) {
              contentDetails = {
                title: `Comment #${comment.id}`,
                content: comment.content,
                createdAt: comment.createdAt
              };
            }
          } else if (flag.contentType === 'user') {
            const user = await storage.getUser(flag.contentId);
            if (user) {
              contentDetails = {
                title: `User ${user.displayName}`,
                content: user.bio || '',
                createdAt: user.createdAt
              };
            }
          }
          
          // Get reporter details
          if (flag.reporterId) {
            const reporter = await storage.getUser(flag.reporterId);
            if (reporter) {
              reporterDetails = {
                id: reporter.id,
                name: reporter.displayName
              };
            }
          }
          
          return {
            ...flag,
            contentDetails,
            reporterDetails
          };
        })
      );
      
      res.json(enrichedFlags);
    } catch (error) {
      console.error("Error fetching content flags:", error);
      res.status(500).json({ message: "Failed to fetch content flags" });
    }
  });
  
  app.post("/api/admin/moderation/flags/:id/review", authenticateJWT2, isAdmin, async (req: Request, res: Response) => {
    try {
      const flagId = parseInt(req.params.id);
      const adminId = req.user?.id;
      const { status, notes } = req.body;
      
      if (!adminId) {
        return res.status(401).json({ message: "Authentication required" });
      }
      
      if (!status || !['approved', 'rejected'].includes(status)) {
        return res.status(400).json({ message: "Valid status (approved or rejected) is required" });
      }
      
      const updatedFlag = await storage.reviewContentFlag(flagId, adminId, status, notes);
      
      if (!updatedFlag) {
        return res.status(404).json({ message: "Content flag not found" });
      }
      
      // If approved, take action on the reported content - for posts, automatic deletion
      if (status === 'approved') {
        // Get the content based on type and ID
        if (updatedFlag.contentType === 'post') {
          try {
            // Always delete the post automatically when report is approved
            console.log(`Admin approved report: Automatically deleting post #${updatedFlag.contentId}`);
            const result = await storage.deletePost(updatedFlag.contentId);
            console.log(`Post deletion result:`, result);
          } catch (deleteError) {
            console.error(`Error automatically deleting post #${updatedFlag.contentId}:`, deleteError);
            // Continue with the process even if deletion fails
          }
        } else if (updatedFlag.contentType === 'comment') {
          // Delete or hide the comment
          const comment = await storage.getComment(updatedFlag.contentId);
          if (comment) {
            // You might need to implement a deleteComment method
            // await storage.deleteComment(updatedFlag.contentId);
          }
        } else if (updatedFlag.contentType === 'user') {
          // Flag the user or take appropriate action
          const user = await storage.getUser(updatedFlag.contentId);
          if (user) {
            await storage.updateUser(user.id, { 
              status: 'flagged'
            });
          }
        }
        
        // Notify the reporter if available
        if (updatedFlag.reporterId) {
          await storage.createUserNotification({
            userId: updatedFlag.reporterId,
            type: NotificationType.CONTENT_MODERATION,
            title: "Report Action Taken",
            message: `Your report about ${updatedFlag.contentType} #${updatedFlag.contentId} has been reviewed and approved. The reported content has been removed.`,
          });
        }
      } else if (status === 'rejected') {
        // If rejected, still notify the reporter
        if (updatedFlag.reporterId) {
          await storage.createUserNotification({
            userId: updatedFlag.reporterId,
            type: NotificationType.CONTENT_MODERATION,
            title: "Report Decision",
            message: `Your report about ${updatedFlag.contentType} #${updatedFlag.contentId} has been reviewed but did not require action at this time.`,
          });
        }
      }
      
      res.json({
        message: `Flag ${status === 'approved' ? 'approved' : 'rejected'} successfully`,
        flag: updatedFlag
      });
    } catch (error) {
      console.error("Error reviewing content flag:", error);
      res.status(500).json({ message: "Failed to review content flag" });
    }
  });
  
