  // Admin endpoint to send system messages and terms prompts to users
  app.post("/api/admin/system-message", requireAdmin, async (req: Request, res: Response) => {
    try {
      const currentUser = await getCurrentUser(req);
      if (!currentUser) {
        return res.status(401).json({ message: "Unauthorized" });
      }
      
      const { type, title, message, requireAction, recipientType, termsVersion } = req.body;
      const adminId = currentUser.id;
      
      // Check that we have the minimum required fields
      if (!type || !title || !message || !recipientType) {
        return res.status(400).json({ 
          message: "Missing required fields: type, title, message, and recipientType are required" 
        });
      }
      
      // Handle different types of messages
      if (type === "terms-prompt") {
        // Send terms of service prompt
        const requireActionBool = typeof requireAction === 'string' 
          ? requireAction === 'true'
          : !!requireAction;
          
        notifyTermsOfServicePrompt(
          recipientType,
          title,
          message,
          requireActionBool,
          adminId,
          termsVersion || 'current'
        );
        
        // Log the admin action
        await storage.createAdminAction({
          adminId,
          actionType: "send_terms_prompt",
          targetType: "users",
          details: JSON.stringify({
            recipientType,
            title,
            message,
            requireAction: requireActionBool,
            termsVersion
          })
        });
        
        return res.json({ 
          success: true, 
          message: `Terms of service prompt sent to ${recipientType} users`
        });
      } 
      else if (type === "notification") {
        // Send system notification
        // Here we could implement sending a general notification
        // to users without requiring action
        
        // Log the admin action
        await storage.createAdminAction({
          adminId,
          actionType: "send_system_notification",
          targetType: "users",
          details: JSON.stringify({
            recipientType,
            title,
            message
          })
        });
        
        return res.json({ 
          success: true, 
          message: `System notification sent to ${recipientType} users` 
        });
      } 
      else {
        return res.status(400).json({ 
          message: `Unsupported message type: ${type}` 
        });
      }
    } catch (error) {
      console.error("Error sending system message:", error);
      res.status(500).json({ message: "Failed to send system message" });
    }
  });

