  // ── Admin: global message search across ALL conversations ─────────────────
  // Use cases: investigate reports, look up keywords for moderation, find
  // messages by a specific user. Read-only. Returns at most 100 rows.
  app.get("/api/admin/chat-control/messages/search", requireAdmin, async (req: Request, res: Response) => {
    try {
      const q = String(req.query.q || "").trim();
      const userIdFilter = req.query.userId ? parseInt(String(req.query.userId), 10) : null;
      const convFilter = req.query.conversationId ? parseInt(String(req.query.conversationId), 10) : null;
      const includeDeleted = String(req.query.includeDeleted || "false") === "true";
      if (!q && !userIdFilter && !convFilter) {
        return res.json({ rows: [], message: "Provide q, userId, or conversationId" });
      }
      const where: string[] = [];
      const params: any[] = [];
      if (q) { params.push(`%${q}%`); where.push(`content ILIKE $${params.length}`); }
      if (userIdFilter) { params.push(userIdFilter); where.push(`sender_id = $${params.length}`); }
      if (convFilter) { params.push(convFilter); where.push(`conversation_id = $${params.length}`); }
      if (!includeDeleted) where.push(`deleted_at IS NULL`);
      const sqlStr = `
        SELECT id, conversation_id, sender_id, content, content_type, created_at, deleted_at,
               metadata->>'originalContent' AS original_content
          FROM chat_messages
          ${where.length ? "WHERE " + where.join(" AND ") : ""}
          ORDER BY created_at DESC
          LIMIT 100`;
      const rows = await (storage as any).db?.execute(sqlStr, params).catch(() => ({ rows: [] }));
      res.json({ rows: rows?.rows || [], count: (rows?.rows || []).length });
    } catch (error) {
      console.error("[Admin Chat Search] Error:", error);
      res.status(500).json({ message: "Search failed" });
    }
  });

