  // ── Soft delete a message ─────────────────────────────────────────────────────
  app.delete("/api/chat/messages/:id", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      const messageId = parseInt(req.params.id);
      if (!userId || isNaN(messageId)) return res.status(400).json({ message: "Invalid request" });
      const { deleteForEveryone } = req.body;
      // Preserve the ORIGINAL content in metadata->>originalContent for moderation
      // audit BEFORE we overwrite. This way admins can still investigate
      // reports about deleted messages. Only sender can delete-for-everyone.
      await (storage as any).db?.execute(
        `UPDATE chat_messages
           SET deleted_at = now(),
               metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
                 'originalContent', content,
                 'deletedBy', $3::int,
                 'deletedAt', now()
               ),
               content = $1
         WHERE id = $2 AND sender_id = $3`,
        [deleteForEveryone ? 'This message was deleted' : '[deleted]', messageId, userId]
      ).catch(() => {});
      res.json({ success: true });
    } catch { res.status(500).json({ message: "Failed to delete message" }); }
  });

  // ── Forward a message to another conversation ─────────────────────────────────
  app.post("/api/chat/messages/:id/forward", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      const messageId = parseInt(req.params.id);
      if (!userId || isNaN(messageId)) return res.status(400).json({ message: "Invalid request" });
      const { targetConversationId } = req.body;
      if (!targetConversationId) return res.status(400).json({ message: "Target conversation required" });
      // Fetch original message
      const orig = await (storage as any).db?.execute(
        `SELECT * FROM chat_messages WHERE id = $1`, [messageId]
      ).catch(() => null);
      const row = orig?.rows?.[0];
      if (!row) return res.status(404).json({ message: "Message not found" });
      // Check target participation
      const isParticipant = await storage.isConversationParticipant(targetConversationId, userId);
      if (!isParticipant) return res.status(403).json({ message: "Not a participant" });
      // Create forwarded message
      const fwd = await storage.createChatMessage({
        conversationId: targetConversationId,
        senderId: userId,
        content: row.content,
        contentType: row.content_type || row.type || 'text',
        metadata: { forwarded: true, originalMessageId: messageId } as any,
      });
      res.status(201).json(fwd);
    } catch { res.status(500).json({ message: "Failed to forward message" }); }
  });

