  // ==================== Admin Chat Broadcast Routes ====================
  
  // Admin broadcast message to all users or event organizers
  app.post("/api/admin/chat/broadcast", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      const userRole = (req as any).user?.role;
      
      if (!userId) {
        return res.status(401).json({ message: "Authentication required" });
      }
      
      // Only admins can broadcast
      if (userRole !== 'admin' && userRole !== 'super_admin') {
        return res.status(403).json({ message: "Admin access required" });
      }
      
      const { type, message } = req.body;
      
      if (!message || !message.trim()) {
        return res.status(400).json({ message: "Message content is required" });
      }
      
      if (!type || !['all', 'organizers'].includes(type)) {
        return res.status(400).json({ message: "Invalid broadcast type. Must be 'all' or 'organizers'" });
      }
      
      let targetUsers: any[] = [];
      
      if (type === 'all') {
        // Get all active users
        targetUsers = await storage.getActiveUsers();
      } else if (type === 'organizers') {
        // Get users who have created events (event organizers)
        targetUsers = await storage.getEventOrganizers();
      }
      
      // Filter out the admin themselves
      targetUsers = targetUsers.filter((u: any) => u.id !== userId);
      
      if (targetUsers.length === 0) {
        return res.status(200).json({ 
          message: "No target users found",
          sentTo: 0 
        });
      }
      
      // Create conversations and send messages to each user
      let sentCount = 0;
      
      for (const targetUser of targetUsers) {
        try {
          // Get or create conversation with this user
          let conversation = await storage.getChatConversationByParticipants(userId, targetUser.id);
          
          if (!conversation) {
            conversation = await storage.createChatConversation(userId, targetUser.id);
          }
          
          if (conversation) {
            // Send the broadcast message
            await storage.createChatMessage({
              conversationId: conversation.id,
              senderId: userId,
              content: `[Admin Broadcast] ${message.trim()}`,
              type: 'text'
            });
            
            // Notify via WebSocket if available
            if (notifyUser) {
              notifyUser(targetUser.id, NotificationType.CHAT_MESSAGE, {
                conversationId: conversation.id,
                senderId: userId,
                content: `[Admin Broadcast] ${message.trim()}`,
                type: 'admin_broadcast'
              });
            }
            
            sentCount++;
          }
        } catch (err) {
          console.error(`Failed to send broadcast to user ${targetUser.id}:`, err);
        }
      }
      
      res.json({ 
        success: true,
        message: `Broadcast sent successfully`,
        sentTo: sentCount,
        targetType: type
      });
      
    } catch (error) {
      console.error("Error sending admin broadcast:", error);
      res.status(500).json({ message: "Failed to send broadcast" });
    }
  });

