  // Create a new marketing campaign
  app.post("/api/admin/marketing/campaigns", requireAdmin, async (req: Request, res: Response) => {
    try {
      const adminId = (req as any).admin?.id;
      const { 
        scheduledAt, 
        content, 
        targetAudience, 
        scheduleType,
        ...rest 
      } = req.body;
      
      // Transform frontend field names to schema field names
      const campaignData: any = {
        ...rest,
        body: content, // Frontend sends 'content', schema uses 'body'
        audienceType: targetAudience, // Frontend sends 'targetAudience', schema uses 'audienceType'
        createdBy: adminId
      };
      
      // Convert scheduledAt to Date if provided as string
      if (scheduledAt && scheduledAt.trim() !== '') {
        campaignData.scheduledAt = new Date(scheduledAt);
        campaignData.status = 'scheduled';
      } else {
        campaignData.status = 'draft';
      }
      
      const campaign = await storage.createMarketingCampaign(campaignData);
      campaignsCache.del("all");
      res.status(201).json(campaign);
    } catch (error) {
      console.error("Error creating marketing campaign:", error);
      res.status(500).json({ message: "Failed to create campaign" });
    }
  });

  // Update a marketing campaign
  app.put("/api/admin/marketing/campaigns/:id", requireAdmin, async (req: Request, res: Response) => {
    try {
      const campaignId = parseInt(req.params.id);
      if (isNaN(campaignId)) {
        return res.status(400).json({ message: "Invalid campaign ID" });
      }

      const { 
        scheduledAt, 
        sentAt, 
        content, 
        targetAudience, 
        scheduleType,
        ...rest 
      } = req.body;
      
      const updateData: any = { ...rest };
      
      // Transform frontend field names to schema field names
      if (content !== undefined) {
        updateData.body = content;
      }
      if (targetAudience !== undefined) {
        updateData.audienceType = targetAudience;
      }
      
      // Convert date fields if provided as strings
      if (scheduledAt && scheduledAt.trim() !== '') {
        updateData.scheduledAt = new Date(scheduledAt);
      }
      if (sentAt) {
        updateData.sentAt = new Date(sentAt);
      }

      const updated = await storage.updateMarketingCampaign(campaignId, updateData);
      if (!updated) {
        return res.status(404).json({ message: "Campaign not found" });
      }

      campaignsCache.del("all");
      res.json(updated);
    } catch (error) {
      console.error("Error updating marketing campaign:", error);
      res.status(500).json({ message: "Failed to update campaign" });
    }
  });

