  // ── Recipient count preview (before sending) ────────────────────────────────
  app.get("/api/admin/marketing/campaigns/:id/recipient-count", requireAdmin, async (req: Request, res: Response) => {
    try {
      const campaignId = parseInt(req.params.id);
      if (isNaN(campaignId)) return res.status(400).json({ message: "Invalid campaign ID" });
      const campaign = await storage.getMarketingCampaign(campaignId);
      if (!campaign) return res.status(404).json({ message: "Campaign not found" });

      let users = await storage.getAllUsers();
      const audienceType = campaign.audienceType || 'all';
      switch (audienceType) {
        case 'artists': users = users.filter(u => u.role === 'artist'); break;
        case 'enthusiasts': users = users.filter(u => u.role === 'enthusiast'); break;
        case 'active': { const d = new Date(); d.setDate(d.getDate() - 30); users = users.filter(u => u.updatedAt && new Date(u.updatedAt) >= d); break; }
        case 'inactive': { const d = new Date(); d.setDate(d.getDate() - 30); users = users.filter(u => !u.updatedAt || new Date(u.updatedAt) < d); break; }
        case 'new': { const d = new Date(); d.setDate(d.getDate() - 7); users = users.filter(u => u.createdAt && new Date(u.createdAt) >= d); break; }
        case 'verified': users = users.filter(u => u.isVerified); break;
      }

      let eligible = 0;
      let total = users.filter(u => !!u.email).length;
      for (const user of users) {
        if (!user.email) continue;
        const prefs = await storage.getNotificationPreferences(user.id);
        if (!prefs || prefs.emailMarketing !== false) eligible++;
      }

      res.json({ eligible, total, audienceType });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/admin/marketing/campaigns/:id/send", requireAdmin, async (req: Request, res: Response) => {
    try {
      const campaignId = parseInt(req.params.id);
      if (isNaN(campaignId)) {
        return res.status(400).json({ message: "Invalid campaign ID" });
      }

      const campaign = await storage.getMarketingCampaign(campaignId);
      if (!campaign) {
        return res.status(404).json({ message: "Campaign not found" });
      }

      if (campaign.status === 'sent') {
        return res.status(400).json({ message: "Campaign has already been sent" });
      }
      if (campaign.status === 'cancelled') {
        return res.status(400).json({ message: "Cancelled campaigns cannot be sent" });
      }

      // Get target audience based on audienceType (schema field name)
      let users = await storage.getAllUsers();
      const audienceType = campaign.audienceType || 'all';
      
      switch (audienceType) {
        case 'artists':
          users = users.filter(u => u.role === 'artist');
          break;
        case 'enthusiasts':
          users = users.filter(u => u.role === 'enthusiast');
          break;
        case 'active':
          const thirtyDaysAgo = new Date();
          thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
          users = users.filter(u => u.updatedAt && new Date(u.updatedAt) >= thirtyDaysAgo);
          break;
        case 'inactive':
          const inactiveThreshold = new Date();
          inactiveThreshold.setDate(inactiveThreshold.getDate() - 30);
          users = users.filter(u => !u.updatedAt || new Date(u.updatedAt) < inactiveThreshold);
          break;
        case 'new':
          const sevenDaysAgo = new Date();
          sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
          users = users.filter(u => u.createdAt && new Date(u.createdAt) >= sevenDaysAgo);
          break;
        case 'verified':
          users = users.filter(u => u.isVerified);
          break;
        case 'all':
        default:
          // No filtering, send to all users
          break;
      }

      // forceSend=true bypasses email marketing preference (admin override)
      const forceSend = req.body?.forceSend === true;

      // Filter users who have email marketing enabled (unless forceSend)
      const eligibleUsers = [];
      for (const user of users) {
        if (forceSend) {
          eligibleUsers.push(user);
        } else {
          const prefs = await storage.getNotificationPreferences(user.id);
          if (!prefs || prefs.emailMarketing !== false) {
            eligibleUsers.push(user);
          }
        }
      }

      // Send emails via Mailgun
      let successCount = 0;
      let failedCount = 0;
      const emailErrors: string[] = [];

      // Import the email function
      const { sendGenericEmail } = await import('./email');
      
      // Domain for the app - use the correct URL without www
      const APP_DOMAIN = "https://urbanculturehub.nl";
      // Always use production domain for email links - users clicking emails 
      // should go to the live website, not the development server
      const API_BASE_URL = "https://urbanculturehub.nl";

      for (const user of eligibleUsers) {
        if (!user.email) continue;
        
        try {
          // Create a recipient record for tracking
          const recipient = await storage.createCampaignRecipient({
            campaignId: campaignId,
            userId: user.id,
            email: user.email,
            status: 'pending'
          });
          
          // Generate tracking token (base64 encoded campaignId:recipientId)
          const trackingToken = Buffer.from(`${campaignId}:${recipient.id}`).toString('base64url');
          
          // Build personalized email using the branded template helper
          const personalizedHtml = buildMarketingEmail({
            campaignBody: campaign.body,
            imageUrl: campaign.imageUrl || undefined,
            ctaUrl: `${API_BASE_URL}/api/track/click/${trackingToken}?url=${encodeURIComponent(APP_DOMAIN)}`,
            trackingPixelUrl: `${API_BASE_URL}/api/track/open/${trackingToken}`,
            recipientName: user.displayName || undefined,
            appDomain: APP_DOMAIN,
            preferencesUrl: `${APP_DOMAIN}/settings`,
          });

          const success = await sendGenericEmail({
            to: user.email,
            subject: campaign.subject,
            html: personalizedHtml
          });

          if (success) {
            successCount++;
            await storage.updateCampaignRecipientStatus(recipient.id, 'sent');
            console.log(`Marketing email sent to ${user.email}`);
          } else {
            failedCount++;
            await storage.updateCampaignRecipientStatus(recipient.id, 'bounced', 'Failed to send');
            emailErrors.push(`Failed to send to ${user.email}`);
          }
        } catch (emailError: any) {
          failedCount++;
          emailErrors.push(`Error sending to ${user.email}: ${emailError.message}`);
          console.error(`Failed to send marketing email to ${user.email}:`, emailError);
        }
      }

      // Update campaign with results
      await storage.updateMarketingCampaign(campaignId, {
        status: 'sent',
        sentAt: new Date(),
        totalSent: successCount,
        totalBounced: failedCount,
        estimatedRecipients: eligibleUsers.length,
      });

      console.log(`Campaign ${campaignId} completed: ${successCount} sent, ${failedCount} failed out of ${eligibleUsers.length} recipients`);

      res.json({ 
        message: "Campaign sent successfully",
        recipientCount: eligibleUsers.length,
        successCount,
        failedCount,
        errors: emailErrors.length > 0 ? emailErrors.slice(0, 5) : undefined
      });
    } catch (error) {
      console.error("Error sending campaign:", error);
      res.status(500).json({ message: "Failed to send campaign" });
    }
  });

  // AI-powered marketing content generation
  app.post("/api/admin/marketing/ai-assist", requireAdmin, async (req: Request, res: Response) => {
    try {
      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const client = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY,
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL,
      });
      const { prompt, campaignName, targetAudience, type } = req.body;

      const systemPrompt = `You are an expert email marketing copywriter for Urban Culture Hub, a community platform based in Amsterdam that connects people around the full spectrum of urban culture and lifestyle.

The platform covers:
- Street art, graffiti, murals — including STRAAT Museum (Amsterdam's world-class street art museum)
- Dance: breakdancing (bboys/bgirls), hip-hop, house, popping, locking, waacking
- Music: DJs, producers, rap, beatbox, open mics, live performances
- Urban sports (outdoor): Padel, basketball/streetball, table tennis, skateboarding, BMX, parkour, calisthenics
- Urban sports (indoor): bouldering/climbing, fitness, martial arts
- Cultural venues: museums, galleries, workshops, cultural hubs
- Lifestyle: nightlife, DJ nights, club culture, specialty cafés, restaurants, rooftop bars
- Community: connecting artists, athletes, creators, lifestyle enthusiasts, venue owners, and visitors
- Events: battles (dance, rap, DJ), jams, festivals, sports competitions, community meetups
- Cities: Amsterdam, Den Haag, Rotterdam, Utrecht, Haarlem, Almere, Alkmaar, Baarn, Zaanstad, Zandvoort

Your job is to write compelling, authentic email campaigns that resonate with the Urban Culture Hub community.
Write in a genuine, energetic, community-focused voice — real and direct. Avoid corporate language.
Use HTML formatting with <h2>, <p>, <ul>, <li>, <strong> tags.
Keep emails scannable: short paragraphs, bullet points, clear CTA.
Target audience segments: all users, artists, athletes, enthusiasts, active users, inactive/re-engage, new users, verified users.
Always write in Dutch by default unless specifically asked in English.`;

      const userMsg = type === 'subject'
        ? `Generate 5 compelling email subject lines for a campaign called "${campaignName}" targeting "${targetAudience}" users. Just list the subject lines, numbered.`
        : `${prompt || `Write a complete marketing email for a campaign called "${campaignName}" targeting "${targetAudience}" users. Include a compelling intro, key benefits or features, and a strong call to action to visit the app.`}`;

      const message = await client.messages.create({
        model: "claude-sonnet-4-6",
        max_tokens: 1500,
        system: systemPrompt,
        messages: [{ role: "user", content: userMsg }],
      });

      const content = message.content[0];
      res.json({ text: content.type === "text" ? content.text : "" });
    } catch (err: any) {
      console.error("Marketing AI error:", err);
      res.status(500).json({ message: err.message || "AI service unavailable" });
    }
  });

