  // In-memory cache for proximity settings (60s TTL per user) — avoids extra DB round-trip on every presence update
  const _proximitySettingsCache = new Map<number, { data: any; expiresAt: number }>();
  async function getCachedProximitySettings(userId: number) {
    const cached = _proximitySettingsCache.get(userId);
    if (cached && cached.expiresAt > Date.now()) return cached.data;
    const data = await storage.getProximitySettings(userId);
    _proximitySettingsCache.set(userId, { data, expiresAt: Date.now() + 60_000 });
    return data;
  }

  app.post("/api/proximity/presence", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const { lat, lng, city } = req.body;
      if (!lat || !lng) return res.status(400).json({ message: "lat and lng required" });

      // Fetch settings from cache (avoids a DB round-trip on every call)
      const settings = await getCachedProximitySettings(userId);
      if (!settings?.discoveryEnabled || !settings?.consentGiven || settings?.visibilityMode === 'ghost') {
        return res.status(403).json({ message: "Proximity discovery not enabled or in ghost mode" });
      }

      // Single-query upsert — replaces SELECT + UPDATE pattern
      const presence = await storage.updateUserPresence(userId, parseFloat(lat), parseFloat(lng), city);

      // Respond immediately — client doesn't need nearby-users result
      res.json({ success: true, coarseLat: presence.coarseLat, coarseLng: presence.coarseLng });

      // Notify nearby users in the background (fire-and-forget)
      setImmediate(async () => {
        try {
          const nearbyUsers = await storage.getNearbyUsers(userId, presence.coarseLat, presence.coarseLng, settings.radiusKm || 2);
          for (const nearbyUser of nearbyUsers) {
            notifyUserWithData(nearbyUser.userId, 'NEARBY_PRESENCE_UPDATE' as any, { userId, action: 'joined' });
          }
        } catch (_) {}
      });
    } catch (error) {
      res.status(500).json({ message: "Failed to update presence" });
    }
  });

