  // Discovery - record swipe action
  app.post("/api/discovery/action", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const { discoveredUserId, action } = req.body;
      if (!discoveredUserId || !action || !['skip', 'connect'].includes(action)) {
        return res.status(400).json({ message: "discoveredUserId and action (skip/connect) required" });
      }
      const record = await storage.recordDiscoveryAction(userId, discoveredUserId, action);

      if (action === 'connect') {
        const existingFollow = await storage.getFollowStatus(userId, discoveredUserId);
        if (!existingFollow) {
          await storage.followUser({ followerId: userId, followedId: discoveredUserId, status: 'active' });
        }
        try {
          const connectorUser = await storage.getUser(userId);
          const connectorName = connectorUser?.displayName || 'Someone';
          notifyUserWithData(discoveredUserId, 'DISCOVERY_CONNECTION' as any, {
            fromUserId: userId,
            fromUserName: connectorName,
            message: `${connectorName} connected with you nearby!`
          });
          await storage.createUserNotification({
            userId: discoveredUserId,
            type: 'FOLLOW_REQUEST',
            title: 'New Connection',
            message: `${connectorName} connected with you via Discovery and is now following you.`,
            actionLink: `/profile/${userId}`,
            actionText: 'View Profile'
          });
        } catch (notifyErr) {
          console.error("Error sending discovery notification:", notifyErr);
        }
      }

      res.json(record);
    } catch (error) {
      console.error("Discovery action error:", error);
      res.status(500).json({ message: "Failed to record action" });
    }
  });

  // Users on map - get users with active presence for map display
  app.get("/api/proximity/map-users", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const settings = await storage.getProximitySettings(userId);
      if (!settings?.discoveryEnabled || !settings?.consentGiven) {
        return res.json([]);
      }
      const { lat, lng, radius } = req.query;
      if (!lat || !lng) return res.status(400).json({ message: "lat and lng required" });
      const coarseLat = parseFloat(lat as string).toFixed(2);
      const coarseLng = parseFloat(lng as string).toFixed(2);
      const radiusKm = parseInt(radius as string) || settings.radiusKm || 10;
      const nearbyUsers = await storage.getNearbyUsers(userId, coarseLat, coarseLng, radiusKm);
      res.json(nearbyUsers);
    } catch (error) {
      console.error("Map users error:", error);
      res.status(500).json({ message: "Failed to get map users" });
    }
  });

  // Trusted Contacts
  app.get("/api/safety/contacts", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const contacts = await storage.getTrustedContacts(userId);
      res.json(contacts);
    } catch (error) {
      res.status(500).json({ message: "Failed to get trusted contacts" });
    }
  });

  app.post("/api/safety/contacts", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const { contactUserId } = req.body;
      if (!contactUserId) return res.status(400).json({ message: "contactUserId required" });
      if (contactUserId === userId) return res.status(400).json({ message: "Cannot add yourself" });
      const contact = await storage.addTrustedContact(userId, parseInt(contactUserId));
      res.json(contact);
    } catch (error) {
      res.status(500).json({ message: "Failed to add trusted contact" });
    }
  });

  app.delete("/api/safety/contacts/:id", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const contactId = parseInt(req.params.id);
      const success = await storage.removeTrustedContact(contactId, userId);
      res.json({ success });
    } catch (error) {
      res.status(500).json({ message: "Failed to remove trusted contact" });
    }
  });

  // Safety Broadcasts
  app.post("/api/safety/broadcast", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const { message, lat, lng, city, broadcastScope } = req.body;
      const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000);
      const coarseLat = lat ? parseFloat(lat).toFixed(2) : undefined;
      const coarseLng = lng ? parseFloat(lng).toFixed(2) : undefined;
      const broadcast = await storage.createSafetyBroadcast({
        userId,
        message: message || "I need help",
        coarseLat,
        coarseLng,
        city,
        broadcastScope: broadcastScope || "trusted_contacts",
        isActive: true,
        expiresAt,
      });
      res.json(broadcast);
    } catch (error) {
      res.status(500).json({ message: "Failed to create safety broadcast" });
    }
  });

  app.get("/api/safety/broadcasts", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const broadcasts = await storage.getActiveSafetyBroadcasts(userId);
      res.json(broadcasts);
    } catch (error) {
      res.status(500).json({ message: "Failed to get safety broadcasts" });
    }
  });

  app.delete("/api/safety/broadcasts/:id", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const broadcastId = parseInt(req.params.id);
      const success = await storage.deactivateSafetyBroadcast(broadcastId, userId);
      res.json({ success });
    } catch (error) {
      res.status(500).json({ message: "Failed to deactivate broadcast" });
    }
  });

