  // POST /api/spots/enrich — generate AI description for a spot via Claude
  app.post("/api/spots/enrich", async (req: Request, res: Response) => {
    try {
      const { name, category, address, opening_hours, website, sport, leisure, amenity, spotType } = req.body;
      if (!name) return res.status(400).json({ message: "name required" });
      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
      const details = [
        category && `Category: ${category}`,
        sport && `Sport/Activity: ${sport}`,
        leisure && `Venue type: ${leisure}`,
        amenity && `Amenity: ${amenity}`,
        spotType && `Spot type: ${spotType}`,
        address && `Location: ${address}`,
        opening_hours && `Opening hours: ${opening_hours}`,
        website && `Website: ${website}`,
      ].filter(Boolean).join('\n');
      const response = await anthropic.messages.create({
        model: "claude-haiku-4-5",
        max_tokens: 180,
        messages: [{
          role: "user",
          content: `Write a 2-sentence description for this urban culture spot in the Netherlands called "${name}". Make it engaging and informative for the street/urban culture community (skateboarding, graffiti, breaking, hip-hop, parkour, BMX, street art). Do NOT repeat the name in the description. Be concise and specific.\n\n${details}`
        }]
      });
      const description = ((response.content[0] as any).text || "").trim();
      return res.json({ description });
    } catch (err) {
      console.error("Spot enrich error:", err);
      return res.status(500).json({ message: "Failed to generate description" });
    }
  });

  // Public: look up sessions for a city spot via its linked spotlight location
