      const updates: Record<string, any> = {};
      if (req.body.name !== undefined) updates.name = req.body.name;
      if (req.body.lat !== undefined) updates.lat = parseFloat(req.body.lat);
      if (req.body.lon !== undefined) updates.lon = parseFloat(req.body.lon);
      if (req.body.category !== undefined) updates.category = req.body.category;
      if (req.body.address !== undefined) updates.address = req.body.address;
      if (req.body.website !== undefined) updates.website = req.body.website;
      if (req.body.adminNote !== undefined) updates.adminNote = req.body.adminNote;
      if (req.body.active !== undefined) updates.active = req.body.active;
      if (req.body.isSuperFeatured !== undefined) updates.isSuperFeatured = req.body.isSuperFeatured;
      if (req.body.osmId !== undefined) updates.osmId = req.body.osmId ? parseInt(req.body.osmId) : null;
      const [row] = await db.update(spotlightedPlaces).set(updates)
