  // ─── Spot Ownership / Assignment ─────────────────────────────────────────────

  // GET /api/admin/spot-assignments — paginated list of ALL spots (spotlights + unspotlighted OSM city spots)
  app.get("/api/admin/spot-assignments", requireAdmin, async (req: Request, res: Response) => {
    try {
      const search = (req.query.search as string || "").trim().toLowerCase();
      const page = Math.max(1, parseInt(req.query.page as string || "1"));
      const filterType = (req.query.filter as string || "all"); // "all" | "spotlighted" | "osm_only"
      const limit = 50;
      const offset = (page - 1) * limit;

      // 1. Fetch all spotlights with owner info
      const spotRows = await db.select({
        id: spotlightedPlaces.id,
        osmId: spotlightedPlaces.osmId,
        name: spotlightedPlaces.name,
        lat: spotlightedPlaces.lat,
        lon: spotlightedPlaces.lon,
        category: spotlightedPlaces.category,
        address: spotlightedPlaces.address,
        active: spotlightedPlaces.active,
        isSuperFeatured: spotlightedPlaces.isSuperFeatured,
        ownedByUserId: spotlightedPlaces.ownedByUserId,
        linkedLocationId: spotlightedPlaces.linkedLocationId,
        ownerDisplayName: users.displayName,
        ownerEmail: users.email,
      }).from(spotlightedPlaces)
        .leftJoin(users, eq(spotlightedPlaces.ownedByUserId, users.id))
        .orderBy(spotlightedPlaces.name);

      // Build set of spotlighted OSM IDs (to avoid showing OSM spot twice)
      const spotlightedOsmIds = new Set<number>(
        spotRows.filter(s => s.osmId != null).map(s => s.osmId as number)
      );

      // 2. Build OSM-only spots from city spots cache (those not yet spotlighted)
      const osmOnlySpots: any[] = filterType === "spotlighted" ? [] : (citySpotsCacheData || [])
        .filter((s: any) => s.osmId != null && !spotlightedOsmIds.has(Number(s.osmId)))
        .map((s: any) => ({
          id: null,
          osmId: Number(s.osmId),
          name: s.name || "Unnamed Spot",
          lat: s.lat ?? null,
          lon: s.lon ?? null,
          category: s.category || "other",
          address: s.address || null,
          active: true,
          isSuperFeatured: false,
          ownedByUserId: null,
          linkedLocationId: null,
          ownerDisplayName: null,
          ownerEmail: null,
          isSpotlighted: false,
        }));

      // Tag spotlights
      const spotlightedRows = filterType === "osm_only" ? [] :
        spotRows.map(s => ({ ...s, isSpotlighted: true }));

      // 3. Merge: spotlights first (sorted), then OSM-only (sorted by name)
      const osmSorted = osmOnlySpots.sort((a: any, b: any) => a.name.localeCompare(b.name));
      const allSpots: any[] = [...spotlightedRows, ...osmSorted];

      // 4. Apply search filter
      const filtered = search
        ? allSpots.filter(r =>
            (r.name || "").toLowerCase().includes(search) ||
            (r.category || "").toLowerCase().includes(search) ||
            (r.address || "").toLowerCase().includes(search)
          )
        : allSpots;

      const total = filtered.length;
      const paginated = filtered.slice(offset, offset + limit);

      res.json({ spots: paginated, total, page, limit, pages: Math.ceil(total / limit) });
    } catch (err: any) {
      res.status(500).json({ message: "Failed to fetch spot assignments", error: err.message });
    }
  });

  // POST /api/admin/spot-assignments/:id/link — ensure a spotlight has a linked location (for session management)
  app.post("/api/admin/spot-assignments/:id/link", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const [spot] = await db.select().from(spotlightedPlaces).where(eq(spotlightedPlaces.id, id)).limit(1);
      if (!spot) return res.status(404).json({ message: "Spotlight not found" });

      if (spot.linkedLocationId) {
        return res.json({ locationId: spot.linkedLocationId, created: false });
      }

      // Create a corresponding location entry (not visible on community map to avoid duplicates)
      const adminId = (req as any).user?.id;
      const [loc] = await db.insert(locations).values({
        name: spot.name,
        description: spot.adminNote || `${spot.category} spot managed via Urban Culture Hub`,
        address: spot.address || null,
        latitude: String(spot.lat),
        longitude: String(spot.lon),
        type: spot.category,
        isFree: true,
        website: spot.website || null,
        createdBy: spot.ownedByUserId || adminId,
        isVisible: false,
        approvalStatus: "approved",
        approvedBy: adminId,
        approvedAt: new Date(),
      }).returning();

      await db.update(spotlightedPlaces)
        .set({ linkedLocationId: loc.id })
        .where(eq(spotlightedPlaces.id, id));

      spotlightsCache.del("public");
      adminSpotlightsCache.del("all");

      res.json({ locationId: loc.id, created: true });
    } catch (err: any) {
      res.status(500).json({ message: "Failed to link spotlight to location", error: err.message });
    }
  });

  // POST /api/admin/spot-assignments/:id/assign-owner — assign a user as owner + create linked location
  app.post("/api/admin/spot-assignments/:id/assign-owner", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const { userId } = req.body;
      if (!userId) return res.status(400).json({ message: "userId is required" });

      const targetUserId = parseInt(userId);
      const [spot] = await db.select().from(spotlightedPlaces).where(eq(spotlightedPlaces.id, id)).limit(1);
      if (!spot) return res.status(404).json({ message: "Spotlight not found" });

      const [targetUser] = await db.select().from(users).where(eq(users.id, targetUserId)).limit(1);
      if (!targetUser) return res.status(404).json({ message: "User not found" });

      const adminId = (req as any).user?.id;

      // Create or update linked location
      let linkedLocationId = spot.linkedLocationId;
      if (!linkedLocationId) {
        const [loc] = await db.insert(locations).values({
          name: spot.name,
          description: spot.adminNote || `${spot.category} spot managed via Urban Culture Hub`,
          address: spot.address || null,
          latitude: String(spot.lat),
          longitude: String(spot.lon),
          type: spot.category,
          isFree: true,
          website: spot.website || null,
          createdBy: targetUserId,
          isVisible: false,
          approvalStatus: "approved",
          approvedBy: adminId,
          approvedAt: new Date(),
        }).returning();
        linkedLocationId = loc.id;
      } else {
        // Update existing location ownership
        await db.update(locations)
          .set({ createdBy: targetUserId })
          .where(eq(locations.id, linkedLocationId));
      }

      // Update spotlight
      await db.update(spotlightedPlaces)
        .set({ ownedByUserId: targetUserId, linkedLocationId })
        .where(eq(spotlightedPlaces.id, id));

      // Grant spot_owner role if not already admin/super_admin
      if (targetUser.role !== "admin" && targetUser.role !== "super_admin" && targetUser.role !== "spot_owner") {
        await db.update(users).set({ role: "spot_owner", canAddSpots: true }).where(eq(users.id, targetUserId));
      } else if (!targetUser.canAddSpots) {
        await db.update(users).set({ canAddSpots: true }).where(eq(users.id, targetUserId));
      }

      spotlightsCache.del("public");
      adminSpotlightsCache.del("all");

      res.json({ success: true, locationId: linkedLocationId });
    } catch (err: any) {
      res.status(500).json({ message: "Failed to assign owner", error: err.message });
    }
  });

  // DELETE /api/admin/spot-assignments/:id/owner — remove owner from spotlight
  app.delete("/api/admin/spot-assignments/:id/owner", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      await db.update(spotlightedPlaces)
        .set({ ownedByUserId: null })
        .where(eq(spotlightedPlaces.id, id));
      spotlightsCache.del("public");
      adminSpotlightsCache.del("all");
      res.json({ success: true });
    } catch (err: any) {
      res.status(500).json({ message: "Failed to remove owner", error: err.message });
    }
  });

  // GET /api/admin/users-list — minimal user list for owner picker
  app.get("/api/admin/users-list", requireAdmin, async (req: Request, res: Response) => {
    try {
      const search = (req.query.search as string || "").trim().toLowerCase();
      const rows = await db.select({
        id: users.id,
        displayName: users.displayName,
        email: users.email,
        role: users.role,
      }).from(users)
        .where(eq(users.status, "active"))
        .orderBy(users.displayName)
        .limit(200);
      const filtered = search
        ? rows.filter(u => u.displayName.toLowerCase().includes(search) || u.email.toLowerCase().includes(search))
        : rows;
      res.json(filtered);
    } catch (err: any) {
      res.status(500).json({ message: "Failed to fetch users", error: err.message });
    }
  });

  // ─── Safety Monitor ───────────────────────────────────────────────────────────
  app.get("/api/admin/safety/report", requireAdmin, async (req: Request, res: Response) => {
    try {
      const cachedSafety = safetyReportCache.get("report");
      if (cachedSafety) return res.json(cachedSafety);
      const issues: Array<{
        id: string;
        severity: "critical" | "warning" | "info";
        category: string;
        title: string;
        description: string;
        count?: number;
        action?: string;
        actionLabel?: string;
      }> = [];

      // ── Pending events ──────────────────────────────────────────────────────
      try {
        const pendingEvents = await db.select({ id: events.id }).from(events)
          .where(eq(events.status, "pending"));
        if (pendingEvents.length > 5) {
          issues.push({
            id: "pending_events_high",
            severity: "critical",
            category: "Events",
            title: `${pendingEvents.length} Events Awaiting Approval`,
            description: "Large backlog of pending events. Organizers may be waiting.",
            count: pendingEvents.length,
            action: "events",
            actionLabel: "Review Events",
          });
        } else if (pendingEvents.length > 0) {
          issues.push({
            id: "pending_events",
            severity: "warning",
            category: "Events",
            title: `${pendingEvents.length} Event${pendingEvents.length > 1 ? "s" : ""} Pending Approval`,
            description: "Events are waiting for admin review before going live.",
            count: pendingEvents.length,
            action: "events",
            actionLabel: "Review Events",
          });
        }
      } catch (_) {}

      // ── Content flags ───────────────────────────────────────────────────────
      try {
        const flags = await db.select({ id: contentFlags.id }).from(contentFlags)
          .where(eq(contentFlags.status, "pending"));
        if (flags.length > 0) {
          issues.push({
            id: "content_flags",
            severity: flags.length > 3 ? "critical" : "warning",
            category: "Content",
            title: `${flags.length} Flagged Content Item${flags.length > 1 ? "s" : ""}`,
            description: "User-reported content needs moderation review.",
            count: flags.length,
            action: "content",
            actionLabel: "Review Flags",
          });
        }
      } catch (_) {}

      // ── Data deletion requests ──────────────────────────────────────────────
      try {
        const deletionReqs = await db.execute(
          sql`SELECT id FROM data_deletion_requests WHERE status = 'pending' LIMIT 50`
        );
        const count = (deletionReqs.rows ?? []).length;
        if (count > 0) {
          issues.push({
            id: "data_deletion",
            severity: "critical",
            category: "Privacy / AVG",
            title: `${count} Data Deletion Request${count > 1 ? "s" : ""} Pending`,
            description: "GDPR/AVG: Users have requested data deletion. Legal deadline may apply.",
            count,
            action: "users",
            actionLabel: "Handle Requests",
          });
        }
      } catch (_) {}

      // ── Unresolved contact submissions ─────────────────────────────────────
      try {
        const unresolved = await db.execute(
          sql`SELECT id FROM contact_submissions WHERE resolved = false LIMIT 50`
        );
        const count = (unresolved.rows ?? []).length;
        if (count > 2) {
          issues.push({
            id: "contact_unresolved",
            severity: "warning",
            category: "Support",
            title: `${count} Unresolved Contact Messages`,
            description: "User inquiries or support requests have not been resolved.",
            count,
            action: "notifications",
            actionLabel: "View Messages",
          });
        } else if (count > 0) {
          issues.push({
            id: "contact_unresolved_low",
            severity: "info",
            category: "Support",
            title: `${count} Contact Message${count > 1 ? "s" : ""} Need Response`,
            description: "Pending support message from a user.",
            count,
            action: "notifications",
            actionLabel: "View Messages",
          });
        }
      } catch (_) {}

      // ── No admin activity in 7 days ─────────────────────────────────────────
      try {
        const recentAction = await db.execute(
          sql`SELECT id FROM admin_actions ORDER BY created_at DESC LIMIT 1`
        );
        if ((recentAction.rows ?? []).length === 0) {
          issues.push({
            id: "no_admin_activity",
            severity: "info",
            category: "Security",
            title: "No Recent Admin Activity",
            description: "No admin actions logged recently. Verify the admin activity log is working.",
            action: "activity",
            actionLabel: "View Activity",
          });
        }
      } catch (_) {}

      // ── Check if any events have no organizer ───────────────────────────────
      try {
        const orphaned = await db.execute(
          sql`SELECT COUNT(*) as cnt FROM events e LEFT JOIN users u ON e.organizer_id = u.id WHERE u.id IS NULL`
        );
        const cnt = parseInt((orphaned.rows?.[0] as any)?.cnt ?? "0");
        if (cnt > 0) {
          issues.push({
            id: "orphaned_events",
            severity: "warning",
            category: "Data Integrity",
            title: `${cnt} Event${cnt > 1 ? "s" : ""} with Missing Organizer`,
            description: "Events reference users that no longer exist in the database.",
            count: cnt,
            action: "events",
            actionLabel: "Review Events",
          });
        }
      } catch (_) {}

      // ── Traffic spike detection (vs 24h ago) ───────────────────────────────
      try {
        const now = new Date();
        const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
        const twoHoursAgo = new Date(now.getTime() - 2 * 60 * 60 * 1000);
        const recent = await db.execute(
          sql`SELECT COUNT(*) as cnt FROM page_views WHERE created_at >= ${oneHourAgo.toISOString()}`
        );
        const prior = await db.execute(
          sql`SELECT COUNT(*) as cnt FROM page_views WHERE created_at >= ${twoHoursAgo.toISOString()} AND created_at < ${oneHourAgo.toISOString()}`
        );
        const recentCnt = parseInt((recent.rows?.[0] as any)?.cnt ?? "0");
        const priorCnt = parseInt((prior.rows?.[0] as any)?.cnt ?? "0");
        if (priorCnt > 10 && recentCnt > priorCnt * 3) {
          issues.push({
            id: "traffic_spike",
            severity: "warning",
            category: "Traffic",
            title: "Unusual Traffic Spike Detected",
            description: `Page views in the last hour (${recentCnt}) are 3x higher than the previous hour (${priorCnt}). Monitor for abuse.`,
            count: recentCnt,
            action: "analytics",
            actionLabel: "View Analytics",
          });
        } else if (priorCnt > 20 && recentCnt === 0) {
          issues.push({
            id: "traffic_drop",
            severity: "critical",
            category: "Traffic",
            title: "Traffic Dropped to Zero",
            description: "No page views recorded in the last hour, but had traffic before. The app may be down or unreachable.",
            action: "analytics",
            actionLabel: "View Analytics",
          });
        }
      } catch (_) {}

      // ── Compute health score ────────────────────────────────────────────────
      const criticals = issues.filter(i => i.severity === "critical").length;
      const warnings = issues.filter(i => i.severity === "warning").length;
      let score = 100 - (criticals * 25) - (warnings * 10);
      score = Math.max(0, Math.min(100, score));

      const safetyResult = { score, issues, generatedAt: new Date().toISOString() };
      safetyReportCache.set("report", safetyResult);
      res.json(safetyResult);
    } catch (error) {
      console.error("Safety report error:", error);
      res.status(500).json({ message: "Failed to generate safety report" });
    }
  });

  // ─── Safety Monitor: AI Analyze ───────────────────────────────────────────────
  app.post("/api/admin/safety/analyze", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { issues, score } = req.body as {
        issues: Array<{ id: string; severity: string; category: string; title: string; description: string; count?: number }>;
        score: number;
      };

      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const client = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY || "",
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL || undefined,
      });

      const issuesSummary = issues.length === 0
        ? "No issues detected. The app is currently healthy."
        : issues.map(i => `- [${i.severity.toUpperCase()}] ${i.category} — ${i.title}: ${i.description}${i.count !== undefined ? ` (count: ${i.count})` : ""}`).join("\n");

      const prompt = `You are a security and operations advisor for Urban Culture Connect, a Dutch hip-hop/street culture community platform built with Node.js/Express, PostgreSQL, React, and Firebase Auth.

Current app health score: ${score}/100
${issues.length > 0 ? `\nDetected issues:\n${issuesSummary}` : "\nNo issues detected."}

Please provide:
1. **Overall Security Posture** (2-3 sentences about the current state)
2. **Issue Analysis** — for each issue above, give:
   - Root cause (1 sentence)
   - Risk if ignored (1 sentence)  
   - Exact steps to resolve (numbered list, be specific)
3. **Top 3 Priorities** — what to fix first and why
4. **Preventive Measures** — 3 proactive steps to prevent future issues

Be specific, practical, and actionable. Use Dutch/EU compliance language where relevant (AVG = GDPR).`;

      const response = await client.messages.create({
        model: "claude-sonnet-4-6",
        max_tokens: 1500,
        messages: [{ role: "user", content: prompt }],
      });

      const analysis = (response.content[0] as any).text || "";
      res.json({ analysis, inputTokens: response.usage.input_tokens, outputTokens: response.usage.output_tokens });
    } catch (error: any) {
      console.error("Safety AI analyze error:", error);
      res.status(500).json({ message: "Failed to analyze with AI", detail: error?.message });
    }
  });

  // ─── Safety Monitor: Protection Status ────────────────────────────────────────
  app.get("/api/admin/protection/status", requireAdmin, async (req: Request, res: Response) => {
    try {
      const cachedProtection = protectionStatusCache.get("status");
      if (cachedProtection) return res.json(cachedProtection);
      const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
      const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

      // ── Security Headers (from Helmet config in index.ts) ───────────────────
      const headers = [
        { name: "X-Powered-By", status: "removed" as const, detail: "Technology stack hidden from attackers" },
        { name: "X-Frame-Options", status: "active" as const, detail: "Clickjacking protection via SAMEORIGIN" },
        { name: "X-Content-Type-Options", status: "active" as const, detail: "MIME sniffing attack prevention" },
        { name: "Referrer-Policy", status: "active" as const, detail: "Referrer data limited to same origin" },
        { name: "X-DNS-Prefetch-Control", status: "active" as const, detail: "DNS prefetch disabled" },
        { name: "X-XSS-Protection", status: "active" as const, detail: "Legacy XSS filter enabled (0 = block mode)" },
        { name: "X-Download-Options", status: "active" as const, detail: "IE download sniffing prevented" },
        { name: "X-Permitted-Cross-Domain-Policies", status: "active" as const, detail: "Flash/PDF cross-domain access blocked" },
        { name: "Content-Security-Policy", status: "active" as const, detail: "Strict CSP: default-src 'self'; script/img/connect allowlist enforced" },
        { name: "HSTS (Strict-Transport-Security)", status: "active" as const, detail: "HTTPS enforced — max-age=31536000; includeSubDomains" },
        { name: "CORS", status: "active" as const, detail: "Same-origin policy — no external domain access" },
      ];

      // ── Firewall / Rate Limiting ─────────────────────────────────────────────
      const firewallRules = [
        { name: "Global API Rate Limit", limit: "200 req / 15 min", scope: "All /api endpoints", status: "active" as const },
        { name: "Auth Rate Limit", limit: "100 req / 15 min (session skip)", scope: "/api/auth/login, /api/auth/register", status: "active" as const },
        { name: "Account Lockout", limit: `${5} failures → 15 min lock`, scope: "/api/auth/login per IP", status: "active" as const },
        { name: "CSRF Origin Check", limit: "Own domain only", scope: "All state-changing requests (POST/PUT/PATCH/DELETE)", status: "active" as const },
        { name: "Webhook Bypass", limit: "Unlimited", scope: "/api/stripe/webhook only", status: "active" as const },
        { name: "Request Body Limit", limit: "10 MB", scope: "JSON + form data payloads", status: "active" as const },
        { name: "Proxy Trust", limit: "Level 1", scope: "Replit proxy layer for correct IP detection", status: "active" as const },
        { name: "File Upload Validation", limit: "MIME + magic bytes", scope: "All image/audio upload endpoints", status: "active" as const },
      ];

      // ── Session Security ─────────────────────────────────────────────────────
      const sessionSecurity = {
        httpOnly: true,
        sameSite: "lax",
        secure: process.env.NODE_ENV === "production",
        maxAgeHours: 24,
        rolling: true,
      };

      // ── Authentication ───────────────────────────────────────────────────────
      const authentication = {
        provider: "Firebase Authentication (Google)",
        localPasswordStorage: false,
        tokenExpiry: "1 hour (Firebase JWT)",
        sessionBacked: true,
        adminRoleCheck: true,
        firebaseJwtVerification: true,
        doubleAuthCheck: true,
      };

      // ── Environment Secrets Checklist ────────────────────────────────────────
      const requiredSecrets = [
        { name: "DATABASE_URL", key: "DATABASE_URL", critical: true },
        { name: "Firebase Service Account", key: "FIREBASE_SERVICE_ACCOUNT", critical: true },
        { name: "Session Secret", key: "SESSION_SECRET", critical: true },
        { name: "Stripe Secret Key", key: "STRIPE_SECRET_KEY", critical: true },
        { name: "Cloudinary Cloud Name", key: "CLOUDINARY_CLOUD_NAME", critical: false },
        { name: "Mailgun API Key", key: "MAILGUN_API_KEY", critical: false },
        { name: "Anthropic AI Key", key: "AI_INTEGRATIONS_ANTHROPIC_API_KEY", critical: false },
        { name: "KVK API Key", key: "KVK_API_KEY", critical: false },
      ];
      const environmentChecklist = requiredSecrets.map(s => ({
        name: s.name,
        present: !!(process.env[s.key] && process.env[s.key] !== ""),
        critical: s.critical,
      }));

      // ── Data Protection ──────────────────────────────────────────────────────
      const dataProtection = [
        { item: "Password storage", status: "safe" as const, detail: "Firebase handles auth — no passwords stored locally" },
        { item: "Payment data", status: "safe" as const, detail: "PCI-DSS compliant via Stripe — no card data stored in DB" },
        { item: "Personal data (AVG/GDPR)", status: "active" as const, detail: "Data deletion requests, consent records, and legal hub implemented" },
        { item: "Database encryption", status: "active" as const, detail: "PostgreSQL at rest — managed by Replit infrastructure" },
        { item: "Transport encryption", status: "active" as const, detail: "HTTPS enforced on all connections" },
        { item: "File uploads", status: "active" as const, detail: "Cloudinary CDN with signed uploads, 10MB limit, type validation" },
        { item: "API secrets", status: "active" as const, detail: "All secrets in Replit Secrets — never in source code" },
        { item: "SQL injection", status: "active" as const, detail: "Drizzle ORM parameterized queries on all database operations" },
        { item: "XSS prevention", status: "active" as const, detail: "React JSX escaping + X-Content-Type-Options header" },
        { item: "Input validation", status: "active" as const, detail: "Zod schemas validate all POST/PATCH request bodies" },
      ];

      // ── Suspicious Activity (high-traffic visitors) ─────────────────────────
      let suspiciousVisitors: Array<{ visitorId: string; requestCount: number; paths: string[] }> = [];
      try {
        const highTraffic = await db.execute(
          sql`SELECT visitor_id, COUNT(*) as cnt, array_agg(DISTINCT path ORDER BY path) as paths
              FROM page_views
              WHERE viewed_at >= ${oneHourAgo.toISOString()}
              GROUP BY visitor_id
              HAVING COUNT(*) > 50
              ORDER BY cnt DESC
              LIMIT 10`
        );
        suspiciousVisitors = (highTraffic.rows ?? []).map((r: any) => ({
          visitorId: String(r.visitor_id).substring(0, 16) + "…",
          requestCount: parseInt(r.cnt),
          paths: Array.isArray(r.paths) ? r.paths.slice(0, 5) : [],
        }));
      } catch (_) {}

      // ── Traffic Stats ────────────────────────────────────────────────────────
      let totalRequestsLastHour = 0;
      let uniqueVisitorsLastHour = 0;
      let totalRequestsLast24h = 0;
      try {
        const hourResult = await db.execute(
          sql`SELECT COUNT(*) as cnt, COUNT(DISTINCT visitor_id) as unique_cnt
              FROM page_views WHERE viewed_at >= ${oneHourAgo.toISOString()}`
        );
        totalRequestsLastHour = parseInt((hourResult.rows?.[0] as any)?.cnt ?? "0");
        uniqueVisitorsLastHour = parseInt((hourResult.rows?.[0] as any)?.unique_cnt ?? "0");
        const dayResult = await db.execute(
          sql`SELECT COUNT(*) as cnt FROM page_views WHERE viewed_at >= ${oneDayAgo.toISOString()}`
        );
        totalRequestsLast24h = parseInt((dayResult.rows?.[0] as any)?.cnt ?? "0");
      } catch (_) {}

      // ── Recent Admin Activity Audit ──────────────────────────────────────────
      let recentAdminActivity: Array<{ adminName: string; actionType: string; targetType: string; details: string; createdAt: string }> = [];
      try {
        const auditResult = await db.execute(
          sql`SELECT aa.action_type, aa.target_type, aa.details, aa.created_at,
                     COALESCE(u.display_name, u.email, 'Unknown') as admin_name
              FROM admin_actions aa
              LEFT JOIN users u ON aa.admin_id = u.id
              WHERE aa.created_at >= ${oneDayAgo.toISOString()}
              ORDER BY aa.created_at DESC
              LIMIT 15`
        );
        recentAdminActivity = (auditResult.rows ?? []).map((r: any) => ({
          adminName: String(r.admin_name),
          actionType: String(r.action_type),
          targetType: String(r.target_type),
          details: r.details ? String(r.details).substring(0, 80) : "",
          createdAt: String(r.created_at),
        }));
      } catch (_) {}

      // ── Pending Security Incidents (content flags + deletion requests) ────────
      let pendingIncidents = { contentFlags: 0, deletionRequests: 0, contactMessages: 0 };
      try {
        const [flags, deletions, contacts] = await Promise.all([
          db.execute(sql`SELECT COUNT(*) as cnt FROM content_flags WHERE status = 'pending'`),
          db.execute(sql`SELECT COUNT(*) as cnt FROM deletion_requests WHERE status = 'pending'`).catch(() => ({ rows: [{ cnt: 0 }] })),
          db.execute(sql`SELECT COUNT(*) as cnt FROM contact_messages WHERE status = 'unread'`).catch(() => ({ rows: [{ cnt: 0 }] })),
        ]);
        pendingIncidents = {
          contentFlags: parseInt((flags.rows?.[0] as any)?.cnt ?? "0"),
          deletionRequests: parseInt((deletions.rows?.[0] as any)?.cnt ?? "0"),
          contactMessages: parseInt((contacts.rows?.[0] as any)?.cnt ?? "0"),
        };
      } catch (_) {}

      // ── Database Health ──────────────────────────────────────────────────────
      let databaseHealth = { connected: false, responseMs: 0, activeConnections: 0 };
      try {
        const start = Date.now();
        await db.execute(sql`SELECT 1`);
        databaseHealth.connected = true;
        databaseHealth.responseMs = Date.now() - start;
        const connResult = await db.execute(sql`SELECT COUNT(*) as cnt FROM pg_stat_activity WHERE state = 'active'`).catch(() => null);
        databaseHealth.activeConnections = parseInt((connResult?.rows?.[0] as any)?.cnt ?? "0");
      } catch (_) {}

      // ── Compute protection score ─────────────────────────────────────────────
      const missingCriticalSecrets = environmentChecklist.filter(s => s.critical && !s.present).length;
      let protectionScore = 100;
      if (!sessionSecurity.secure) protectionScore -= 5;
      if (!databaseHealth.connected) protectionScore -= 20;
      protectionScore -= suspiciousVisitors.length * 4;
      protectionScore -= missingCriticalSecrets * 10;
      protectionScore -= pendingIncidents.contentFlags > 5 ? 5 : 0;
      protectionScore = Math.max(0, Math.min(100, protectionScore));

      const protectionResult = {
        score: protectionScore,
        headers, firewallRules, sessionSecurity, authentication,
        environmentChecklist, dataProtection,
        suspiciousActivity: suspiciousVisitors,
        trafficStats: { totalRequestsLastHour, uniqueVisitorsLastHour, totalRequestsLast24h },
        recentAdminActivity, pendingIncidents, databaseHealth,
        generatedAt: new Date().toISOString(),
      };
      protectionStatusCache.set("status", protectionResult);
      res.json(protectionResult);
    } catch (error) {
      console.error("Protection status error:", error);
      res.status(500).json({ message: "Failed to get protection status" });
    }
  });

  // ─── Security: Live Feed (no cache, fast, polls every 5s) ────────────────────

  app.get("/api/admin/security/live", requireAdmin, async (req: Request, res: Response) => {
    try {
      const fiveMinAgo = new Date(Date.now() - 5 * 60 * 1000);
      const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);

      // Recent security events
      let recentEvents: Array<{
        id: number; type: string; severity: string; ip: string | null;
        path: string | null; message: string; createdAt: string; resolved: boolean;
      }> = [];
      try {
        const evts = await db.select({
          id: securityEvents.id,
          type: securityEvents.type,
          severity: securityEvents.severity,
          ip: securityEvents.ip,
          path: securityEvents.path,
          message: securityEvents.message,
          createdAt: securityEvents.createdAt,
          resolved: securityEvents.resolved,
        }).from(securityEvents)
          .orderBy(desc(securityEvents.createdAt))
          .limit(30);
        recentEvents = evts.map(e => ({
          ...e,
          createdAt: e.createdAt.toISOString(),
        }));
      } catch (_) {}

      // Traffic last 5 min
      let trafficLast5Min = 0;
      let trafficLastMinute = 0;
      try {
        const oneMinAgo = new Date(Date.now() - 60 * 1000);
        const [r5, r1] = await Promise.all([
          db.execute(sql`SELECT COUNT(*) as cnt FROM page_views WHERE viewed_at >= ${fiveMinAgo.toISOString()}`),
          db.execute(sql`SELECT COUNT(*) as cnt FROM page_views WHERE viewed_at >= ${oneMinAgo.toISOString()}`),
        ]);
        trafficLast5Min = parseInt((r5.rows?.[0] as any)?.cnt ?? "0");
        trafficLastMinute = parseInt((r1.rows?.[0] as any)?.cnt ?? "0");
      } catch (_) {}

      // Active sessions (users with page views in last 5 min)
      let activeSessions = 0;
      try {
        const sessResult = await db.execute(
          sql`SELECT COUNT(DISTINCT visitor_id) as cnt FROM page_views WHERE viewed_at >= ${fiveMinAgo.toISOString()}`
        );
        activeSessions = parseInt((sessResult.rows?.[0] as any)?.cnt ?? "0");
      } catch (_) {}

      // Failed logins last hour (from loginFailures in-memory map)
      let failedLoginsLastHour = 0;
      let lockedIps = 0;
      const now = Date.now();
      for (const [, rec] of loginFailures.entries()) {
        if (rec.firstAt >= now - LOCKOUT_WINDOW_MS) failedLoginsLastHour += rec.count;
        if (rec.lockedUntil && rec.lockedUntil > now) lockedIps++;
      }

      // Blocked IPs count
      let blockedIpCount = 0;
      try {
        const bResult = await db.execute(
          sql`SELECT COUNT(*) as cnt FROM ip_blocks WHERE (expires_at IS NULL OR expires_at > NOW())`
        );
        blockedIpCount = parseInt((bResult.rows?.[0] as any)?.cnt ?? "0");
      } catch (_) {}

      // Security events by severity last hour
      let severityCounts = { critical: 0, high: 0, medium: 0, low: 0 };
      try {
        const sevResult = await db.execute(
          sql`SELECT severity, COUNT(*) as cnt FROM security_events WHERE created_at >= ${oneHourAgo.toISOString()} GROUP BY severity`
        );
        for (const row of (sevResult.rows ?? []) as any[]) {
          const sev = String(row.severity) as keyof typeof severityCounts;
          if (sev in severityCounts) severityCounts[sev] = parseInt(row.cnt);
        }
      } catch (_) {}

      // Recent login activity (successful logins last hour)
      let successfulLoginsLastHour = 0;
      try {
        const loginResult = await db.execute(
          sql`SELECT COUNT(*) as cnt FROM security_events WHERE type = 'login_success' AND created_at >= ${oneHourAgo.toISOString()}`
        );
        successfulLoginsLastHour = parseInt((loginResult.rows?.[0] as any)?.cnt ?? "0");
      } catch (_) {}

      // Top paths being hit in last 5 min
      let hotPaths: Array<{ path: string; count: number }> = [];
      try {
        const pathResult = await db.execute(
          sql`SELECT path, COUNT(*) as cnt FROM page_views WHERE viewed_at >= ${fiveMinAgo.toISOString()} GROUP BY path ORDER BY cnt DESC LIMIT 5`
        );
        hotPaths = (pathResult.rows ?? []).map((r: any) => ({ path: String(r.path), count: parseInt(r.cnt) }));
      } catch (_) {}

      res.json({
        recentEvents,
        trafficLast5Min,
        trafficLastMinute,
        activeSessions,
        failedLoginsLastHour,
        successfulLoginsLastHour,
        lockedIps,
        blockedIpCount,
        severityCounts,
        hotPaths,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      console.error("Security live feed error:", error);
      res.status(500).json({ message: "Failed to fetch live security data" });
    }
  });

  // ─── Security: Event Log ──────────────────────────────────────────────────────

  app.get("/api/admin/security/events", requireAdmin, async (req: Request, res: Response) => {
    try {
      const limit = Math.min(parseInt(req.query.limit as string ?? "50"), 200);
      const offset = parseInt(req.query.offset as string ?? "0");
      const severityFilter = req.query.severity as string | undefined;
      const typeFilter = req.query.type as string | undefined;
      const resolvedFilter = req.query.resolved as string | undefined;

      const conditions: any[] = [];
      if (severityFilter && severityFilter !== "all") conditions.push(eq(securityEvents.severity, severityFilter));
      if (typeFilter && typeFilter !== "all") conditions.push(eq(securityEvents.type, typeFilter));
      if (resolvedFilter === "false") conditions.push(eq(securityEvents.resolved, false));
      if (resolvedFilter === "true") conditions.push(eq(securityEvents.resolved, true));

      const query = db.select().from(securityEvents)
        .orderBy(desc(securityEvents.createdAt))
        .limit(limit)
        .offset(offset);

      const events = conditions.length > 0
        ? await query.where(and(...conditions))
        : await query;

      const totalResult = await db.execute(sql`SELECT COUNT(*) as cnt FROM security_events`);
      const total = parseInt((totalResult.rows?.[0] as any)?.cnt ?? "0");

      res.json({
        events: events.map(e => ({ ...e, createdAt: e.createdAt.toISOString() })),
        total,
        limit,
        offset,
      });
    } catch (error) {
      console.error("Security events error:", error);
      res.status(500).json({ message: "Failed to fetch security events" });
    }
  });

