  app.post("/api/admin/security/block-ip", requireAdmin, async (req: Request, res: Response) => {
    try {
      const schema = z.object({
        ip: z.string().min(1),
        reason: z.string().min(1),
        permanent: z.boolean().optional().default(false),
        durationHours: z.number().optional(),
      });
      const { ip, reason, permanent, durationHours } = schema.parse(req.body);

      const adminId = (req.session as any)?.userId ?? null;
      const expiresAt = !permanent && durationHours
        ? new Date(Date.now() + durationHours * 60 * 60 * 1000)
        : null;

      await db.insert(ipBlocks).values({ ip, reason, blockedBy: adminId, permanent, expiresAt })
        .onConflictDoUpdate({ target: ipBlocks.ip, set: { reason, permanent, expiresAt, blockedBy: adminId } });

      // Log as security event
      await db.insert(securityEvents).values({
        type: "ip_blocked",
        severity: "medium",
        ip,
        message: `IP blocked by admin: ${reason}`,
        metadata: { permanent, durationHours },
      }).catch(() => {});

      res.json({ success: true });
    } catch (error) {
      console.error("Block IP error:", error);
      res.status(500).json({ message: "Failed to block IP" });
    }
  });

