  // ── ADMIN DEAL FINDER ────────────────────────────────────────────────────────

  app.post("/api/admin/deal-search", requireAdmin, async (req: Request, res: Response) => {
    const { messages } = req.body;
    if (!Array.isArray(messages) || messages.length === 0) {
      return res.status(400).json({ message: "messages required" });
    }

    res.setHeader("Content-Type", "text/event-stream");
    res.setHeader("Cache-Control", "no-cache");
    res.setHeader("Connection", "keep-alive");
    res.setHeader("X-Accel-Buffering", "no");
    res.flushHeaders();

    const keepAlive = setInterval(() => {
      res.write(": keep-alive\n\n");
    }, 15000);

    try {
      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const client = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY || "",
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL || undefined,
      });

      const systemPrompt = `You are an expert product deal-finder assistant for an admin user in the Netherlands. 
Your job is to search the web and find the absolute best current deals, prices, and offers for any product they ask about.

When presenting results:
- List the top 3-6 best options with clear pricing in euros
- Include store names (Coolblue, Bol.com, MediaMarkt, Amazon.nl, etc.)
- Include direct product URLs when available
- Compare specs and value-for-money
- Highlight which deal is the BEST VALUE
- Mention any current promotions, discounts, or bundles
- Be specific about specs (RAM, storage, processor, etc.)
- Format clearly with **bold** for product names and prices
- Always search for Dutch/EU retailers first for best local pricing

Today's date: ${new Date().toLocaleDateString("nl-NL", { day: "numeric", month: "long", year: "numeric" })}`;

      const anthropicMessages = messages.slice(-10).map((m: any) => ({
        role: m.role as "user" | "assistant",
        content: m.content as string,
      }));

      let fullText = "";
      let loopMessages = [...anthropicMessages];
      const MAX_LOOPS = 8;
      let usedWebSearch = false;

      try {
        for (let loop = 0; loop < MAX_LOOPS; loop++) {
          const response: any = await (client.messages.create as any)(
            {
              model: "claude-opus-4-5",
              max_tokens: 8000,
              system: systemPrompt,
              tools: [{ type: "web_search_20250305", name: "web_search" }] as any,
              messages: loopMessages,
            },
            { headers: { "anthropic-beta": "web-search-2025-03-05" } }
          );

          for (const block of response.content) {
            if (block.type === "text") {
              fullText += block.text;
            } else if (block.type === "tool_use") {
              usedWebSearch = true;
            }
          }

          if (response.stop_reason === "end_turn" || response.stop_reason === "stop_sequence") {
            break;
          }

          if (response.stop_reason === "tool_use") {
            const toolResults = response.content
              .filter((b: any) => b.type === "tool_use")
              .map((b: any) => ({
                type: "tool_result",
                tool_use_id: b.id,
                content: [] as any[],
              }));
            loopMessages = [
              ...loopMessages,
              { role: "assistant" as const, content: response.content },
              { role: "user" as const, content: toolResults },
            ];
          } else {
            break;
          }
        }
      } catch (webSearchErr: any) {
        if (!fullText) {
          const fallback = await client.messages.create({
            model: "claude-sonnet-4-6",
            max_tokens: 4000,
            system: systemPrompt + "\n\nNote: Live web search is unavailable. Provide your best knowledge about typical prices and Dutch retailers, and advise the user to verify current pricing.",
            messages: anthropicMessages,
          });
          fullText = (fallback.content as any[])
            .filter((b: any) => b.type === "text")
            .map((b: any) => b.text)
            .join("");
          if (fullText) {
            fullText = "_(Note: based on knowledge, not live search)_\n\n" + fullText;
          }
        }
      }

      const chunkSize = 40;
      for (let i = 0; i < fullText.length; i += chunkSize) {
        res.write(`data: ${JSON.stringify({ type: "text", text: fullText.slice(i, i + chunkSize) })}\n\n`);
        await new Promise(r => setTimeout(r, 8));
      }

      res.write(`data: ${JSON.stringify({ type: "done" })}\n\n`);
    } catch (err: any) {
      res.write(`data: ${JSON.stringify({ type: "error", message: err.message || "Search failed" })}\n\n`);
    } finally {
      clearInterval(keepAlive);
      res.end();
    }
  });

