  app.post("/api/admin/outreach/leads", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { db } = await import("./db");
      const { outreachLeads } = await import("../shared/schema");
      const { sql: sqlFn, eq } = await import("drizzle-orm");
      const { organization, linkedinUrl } = req.body;
      if (organization) {
        const existing = await db.select({ id: outreachLeads.id, organization: outreachLeads.organization })
          .from(outreachLeads)
          .where(sqlFn`lower(regexp_replace(organization, '[^a-zA-Z0-9]', '', 'g')) = lower(regexp_replace(${organization}, '[^a-zA-Z0-9]', '', 'g'))`);
        if (existing.length > 0) {
          return res.status(409).json({ error: "duplicate", message: `"${existing[0].organization}" is already in your Outreach CRM` });
        }
      }
      if (linkedinUrl) {
        const urlMatch = await db.select({ id: outreachLeads.id }).from(outreachLeads).where(eq(outreachLeads.linkedinUrl, linkedinUrl));
        if (urlMatch.length > 0) {
          return res.status(409).json({ error: "duplicate", message: "A lead with this LinkedIn URL already exists" });
        }
      }
      const [lead] = await db.insert(outreachLeads).values(req.body).returning();
      res.json(lead);
    } catch (err: any) {
      res.status(500).json({ message: "Failed to create lead", error: err.message });
    }
  });

