      const { eq } = await import("drizzle-orm");
      const id = parseInt(req.params.id);
      const { name, organization, department, email, phone, website, city, notes, status, type } = req.body;
      const updateData: Record<string, any> = {};
      if (name !== undefined) updateData.name = name;
      if (organization !== undefined) updateData.organization = organization;
      if (department !== undefined) updateData.department = department;
      if (email !== undefined) updateData.email = email;
      if (phone !== undefined) updateData.phone = phone;
      if (website !== undefined) updateData.website = website;
      if (city !== undefined) updateData.city = city;
      if (notes !== undefined) updateData.notes = notes;
      if (status !== undefined) updateData.status = status;
      if (type !== undefined) updateData.type = type;
      if (Object.keys(updateData).length === 0) return res.status(400).json({ message: "No valid fields to update" });
      const [lead] = await db.update(outreachLeads).set(updateData).where(eq(outreachLeads.id, id)).returning();
      if (!lead) return res.status(404).json({ message: "Lead not found" });
      res.json(lead);
