  // ── Outreach tracking pixel (public — no auth required) ─────────────────────
  // Returns a 1×1 transparent GIF and records an open event for the email
  app.get("/api/outreach/track/:emailId", async (req: Request, res: Response) => {
    const TRANSPARENT_GIF = Buffer.from(
      "R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7", "base64"
    );
    res.setHeader("Content-Type", "image/gif");
    res.setHeader("Cache-Control", "no-store, no-cache, must-revalidate, max-age=0");
    res.setHeader("Pragma", "no-cache");
    res.end(TRANSPARENT_GIF);

    // Record open event asynchronously — don't block the response
    const emailId = parseInt(req.params.emailId, 10);
    if (!isNaN(emailId)) {
      (async () => {
        try {
          const { db } = await import("./db");
          const { outreachEmails, outreachEmailOpens } = await import("../shared/schema");
          const { eq, sql: sqlRaw } = await import("drizzle-orm");
          const ip = (req.headers["x-forwarded-for"] as string)?.split(",")[0]?.trim() || req.ip || "";
          const ua = req.headers["user-agent"] || "";
          // Insert open event
          await db.insert(outreachEmailOpens).values({ emailId, ipAddress: ip, userAgent: ua });
          // Update open count on the email record
          await db.update(outreachEmails).set({
            openCount: sqlRaw`COALESCE(open_count, 0) + 1`,
            firstOpenedAt: sqlRaw`COALESCE(first_opened_at, NOW())`,
            lastOpenedAt: new Date(),
          }).where(eq(outreachEmails.id, emailId));
        } catch {}
      })();
    }
  });

