  app.post("/api/admin/outreach/send-bulk", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { sendGenericEmail } = await import("./email");
      const { db } = await import("./db");
      const { outreachLeads, outreachEmails } = await import("../shared/schema");
      const { inArray } = await import("drizzle-orm");
      const { leadIds, subject, html, text } = req.body;
      if (!leadIds?.length || !subject || !html) return res.status(400).json({ message: "leadIds, subject and html are required" });

      const leads = await db.select().from(outreachLeads).where(inArray(outreachLeads.id, leadIds));
      const withEmail = leads.filter((l: any) => l.email);

      const { sql: sqlRaw } = await import("drizzle-orm");
      let sent = 0;
      const failed: string[] = [];
      for (const lead of withEmail) {
        try {
          const wrappedHtml = `<!DOCTYPE html>
<html lang="nl">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${subject}</title>
</head>
<body style="margin:0;padding:0;background:#f0f0f0;font-family:Arial,Helvetica,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f0f0;padding:32px 0;">
    <tr><td align="center">
      <table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 4px 16px rgba(0,0,0,0.10);max-width:600px;width:100%;">
        <tr><td style="background:linear-gradient(135deg,#111111 0%,#2a2a2a 100%);padding:24px 36px;">
          <table width="100%" cellpadding="0" cellspacing="0"><tr><td>
            <div style="display:inline-block;background:linear-gradient(135deg,#ff6b00,#ff9500);border-radius:8px;padding:6px 12px;margin-bottom:8px;">
              <span style="color:#ffffff;font-size:11px;font-weight:bold;letter-spacing:2px;text-transform:uppercase;">Urban Culture Hub</span>
            </div>
            <p style="margin:4px 0 0 0;color:#cccccc;font-size:12px;">Het platform voor hiphop &amp; straatcultuur in Nederland</p>
          </td></tr></table>
        </td></tr>
        <tr><td style="padding:36px;color:#333333;font-size:15px;line-height:1.8;">
          ${html}
        </td></tr>
        <tr><td style="padding:0 36px 28px 36px;text-align:center;">
          <table cellpadding="0" cellspacing="0" style="margin:0 auto;"><tr>
            <td style="padding:0 6px;"><a href="https://urbanculturehub.nl" style="display:inline-block;background:#111111;color:#ffffff;font-size:13px;font-weight:bold;text-decoration:none;padding:10px 20px;border-radius:8px;">🌐 urbanculturehub.nl</a></td>
            <td style="padding:0 6px;"><a href="https://apps.apple.com/nl/app/urban-culture-hub/id6743952291?l=en-GB" style="display:inline-block;background:#ff6b00;color:#ffffff;font-size:13px;font-weight:bold;text-decoration:none;padding:10px 20px;border-radius:8px;">📱 Download iOS App</a></td>
          </tr></table>
        </td></tr>
        <tr><td style="background:#fafafa;padding:20px 36px;border-top:1px solid #eeeeee;font-size:11px;color:#aaaaaa;text-align:center;">
          <p style="margin:0 0 6px 0;"><strong style="color:#888;">Urban Culture Hub</strong> &nbsp;·&nbsp; <a href="https://urbanculturehub.nl" style="color:#ff6b00;text-decoration:none;">urbanculturehub.nl</a> &nbsp;·&nbsp; <a href="https://apps.apple.com/nl/app/urban-culture-hub/id6743952291?l=en-GB" style="color:#aaa;text-decoration:none;">iOS App</a></p>
          <p style="margin:0;">Wilt u geen berichten meer ontvangen? Mail <a href="mailto:riki@dancehealthy.net?subject=uitschrijven" style="color:#aaa;">riki@dancehealthy.net</a> met onderwerp "uitschrijven".</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body>
</html>`;
          // Record email before sending to get the tracking ID
          const [emailRecord] = await db.insert(outreachEmails).values({
            leadId: lead.id,
            recipientEmail: lead.email!,
            recipientName: lead.name || lead.organization,
            subject,
            bodyHtml: html,
            isBulk: true,
            status: "sent",
          }).returning();
          const baseUrl = process.env.APP_URL || `https://${process.env.REPLIT_DEV_DOMAIN || "urbanculturehub.nl"}`;
          const trackingPixel = `<img src="${baseUrl}/api/outreach/track/${emailRecord.id}" width="1" height="1" style="display:block;width:1px;height:1px;border:0;" alt="" />`;
          const trackedHtml = wrappedHtml.replace("</body>", `${trackingPixel}</body>`);

          await sendGenericEmail({ to: lead.email!, subject, html: trackedHtml, text: text || subject, replyTo: "riki@dancehealthy.net" });
          await db.update(outreachLeads).set({
            status: "contacted", lastEmailSubject: subject, lastEmailSentAt: new Date(),
            emailSentCount: sqlRaw`COALESCE(email_sent_count, 0) + 1`,
          }).where(inArray(outreachLeads.id, [lead.id]));
          sent++;
        } catch (e: any) {
          failed.push(`${lead.email}: ${e.message}`);
        }
      }

      res.json({ success: true, sent, skipped: leads.length - withEmail.length, failed });
    } catch (err: any) {
      console.error("Outreach bulk email error:", err);
      res.status(500).json({ message: err.message || "Failed to send bulk emails" });
    }
  });

  app.post("/api/admin/outreach/ai-assist", requireAdmin, async (req: Request, res: Response) => {
    try {
      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const client = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY,
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL,
      });
      const { prompt, context } = req.body;

      const defaultSystemPrompt = `Je bent een professionele outreach-assistent voor Urban Culture Connect — het digitale platform voor hiphop en straatcultuur in Nederland. Het platform heeft een interactieve kaart met 96 gecureerde urban culture hotspots in 10 Nederlandse steden, een community feed, events systeem, Friends Nearby, Legal Hub, AI tools, en meer. Schrijf altijd in het Nederlands tenzij anders gevraagd. Wees authentiek, beknopt en overtuigend.`;

      const message = await client.messages.create({
        model: "claude-sonnet-4-6",
        max_tokens: 1500,
        system: context || defaultSystemPrompt,
        messages: [{ role: "user", content: prompt }],
      });

      const content = message.content[0];
      res.json({ text: content.type === "text" ? content.text : "" });
    } catch (err: any) {
      console.error("Outreach AI error:", err);
      res.status(500).json({ message: err.message || "AI service unavailable" });
    }
  });

