  // Mailgun inbound webhook — receives incoming emails (no auth, verified by signature)
  app.post("/api/webhook/mailgun/inbound", async (req: Request, res: Response) => {
    try {
      res.sendStatus(200); // acknowledge immediately

      const { db } = await import("./db");
      const { inboxEmails, outreachLeads } = await import("../shared/schema");
      const { ilike, or, eq } = await import("drizzle-orm");

      const body = req.body as any;
      const messageId = body["Message-Id"] || body["message-id"] || body["X-Mailgun-Message-Id"] || null;
      const fromRaw: string = body.From || body.from || body.sender || "";
      const toRaw: string = body.To || body.to || body.recipient || "";
      const subject: string = body.Subject || body.subject || "(no subject)";
      const bodyText: string = body["body-plain"] || body["stripped-text"] || body.text || "";
      const bodyHtml: string = body["body-html"] || body["stripped-html"] || body.html || "";
      const timestamp: string = body.timestamp || body.Date || body.date || "";

      // Parse from email
      const fromEmailMatch = fromRaw.match(/<([^>]+)>/) || fromRaw.match(/([^\s]+@[^\s]+)/);
      const fromEmail = fromEmailMatch ? fromEmailMatch[1].toLowerCase().trim() : fromRaw.toLowerCase().trim();
      const fromName = fromRaw.includes("<") ? fromRaw.split("<")[0].trim().replace(/"/g, "") : "";

      if (!fromEmail) return;

      // Deduplicate by mailgun message id
      if (messageId) {
        const existing = await db.select({ id: inboxEmails.id }).from(inboxEmails)
          .where(eq(inboxEmails.mailgunMessageId, messageId)).limit(1);
        if (existing.length > 0) return;
      }

      // Try to match sender to an outreach lead
      const matchedLeads = await db.select({ id: outreachLeads.id })
        .from(outreachLeads)
        .where(ilike(outreachLeads.email, fromEmail))
        .limit(1);
      const matchedLeadId = matchedLeads[0]?.id ?? null;

      // If matched, update lead status to replied
      if (matchedLeadId) {
        await db.update(outreachLeads)
          .set({ status: "replied" })
          .where(eq(outreachLeads.id, matchedLeadId));
      }

      const receivedAt = timestamp ? new Date(parseInt(timestamp) * 1000) : new Date();

      await db.insert(inboxEmails).values({
        mailgunMessageId: messageId,
        fromEmail,
        fromName: fromName || null,
        toEmail: toRaw || "riki@dancehealthy.net",
        subject,
        bodyText: bodyText.slice(0, 20000),
        bodyHtml: bodyHtml.slice(0, 50000),
        receivedAt,
        isRead: false,
        isStarred: false,
        matchedLeadId,
        inReplyToSubject: null,
        headers: JSON.stringify({ "Message-Id": messageId }),
      });
    } catch (err: any) {
      console.error("Mailgun inbound webhook error:", err);
    }
  });

