  // POST /api/admin/mailgun/setup-route — programmatically create the Mailgun inbound route
  app.post("/api/admin/mailgun/setup-route", requireAdmin, async (req: Request, res: Response) => {
    try {
      // Routes require the primary Mailgun API key (account-level), not a domain sending key
      const apiKey = process.env.MAILGUN_PRIMARY_KEY || process.env.MAILGUN_API_KEY;
      const domain = process.env.MAILGUN_DOMAIN;
      if (!apiKey || !domain) {
        return res.status(400).json({ message: "MAILGUN_PRIMARY_KEY or MAILGUN_DOMAIN not configured", needsPrimaryKey: true });
      }

      // Determine the public webhook URL
      const host = req.headers["x-forwarded-host"] || req.headers.host || "";
      const proto = req.headers["x-forwarded-proto"] || "https";
      const webhookUrl = `${proto}://${host}/api/webhook/mailgun/inbound`;
      const recipient = `riki@${domain.toLowerCase()}`;
      const expression = `match_recipient("${recipient}")`;

      // First, list existing routes to check if ours already exists
      const listResp = await fetch("https://api.mailgun.net/v3/routes?limit=100", {
        headers: {
          Authorization: `Basic ${Buffer.from(`api:${apiKey}`).toString("base64")}`,
        },
      });
      if (!listResp.ok) {
        const errText = await listResp.text();
        console.error("Mailgun list routes error:", errText);
        return res.status(502).json({ message: `Mailgun API error (list): ${listResp.status} ${errText}` });
      }
      const listData = await listResp.json() as { items?: Array<{ id: string; expression: string; actions: string[] }> };
      const authHeader = { Authorization: `Basic ${Buffer.from(`api:${apiKey}`).toString("base64")}` };

      // Check if a route already exists pointing to our inbound webhook path
      const existing = (listData.items || []).find(r =>
        r.expression === expression || r.actions.some(a => a.includes("/api/webhook/mailgun/inbound"))
      );

      // If existing route points to the exact current URL, we're done
      if (existing && existing.actions.some(a => a.includes(webhookUrl))) {
        return res.json({ ok: true, alreadyExists: true, routeId: existing.id, webhookUrl });
      }

      // If existing route exists but points to wrong/old URL, delete it first
      if (existing) {
        console.log(`Deleting stale Mailgun route ${existing.id} (wrong URL), recreating with: ${webhookUrl}`);
        await fetch(`https://api.mailgun.net/v3/routes/${existing.id}`, {
          method: "DELETE",
          headers: authHeader,
        });
      }

      // Create the route with the correct current URL
      const body = new URLSearchParams();
      body.append("priority", "0");
      body.append("description", "DanceHealthy inbound email route");
      body.append("expression", expression);
      body.append("action", `forward("${webhookUrl}")`);
      body.append("action", "stop()");

      const createResp = await fetch("https://api.mailgun.net/v3/routes", {
        method: "POST",
        headers: { ...authHeader, "Content-Type": "application/x-www-form-urlencoded" },
        body: body.toString(),
      });
      const createData = await createResp.json() as any;
      if (!createResp.ok) {
        console.error("Mailgun create route error:", createData);
        return res.status(502).json({ message: `Mailgun API error: ${createData.message || createResp.status}` });
      }

      console.log(`✅ Mailgun inbound route created → ${webhookUrl}`);
      res.json({ ok: true, alreadyExists: false, routeId: createData.route?.id, webhookUrl });
    } catch (err: any) {
      console.error("Mailgun setup route error:", err);
      res.status(500).json({ message: err.message });
    }
  });

  // GET /api/admin/mailgun/route-status — check if the inbound route exists
  app.get("/api/admin/mailgun/route-status", requireAdmin, async (req: Request, res: Response) => {
    try {
      const apiKey = process.env.MAILGUN_PRIMARY_KEY || process.env.MAILGUN_API_KEY;
      const domain = process.env.MAILGUN_DOMAIN;
      const hasPrimaryKey = !!process.env.MAILGUN_PRIMARY_KEY;
      if (!apiKey || !domain) {
        return res.json({ configured: false, routeExists: false, hasPrimaryKey: false });
      }

      const recipient = `riki@${domain.toLowerCase()}`;
      const expression = `match_recipient("${recipient}")`;

      const listResp = await fetch("https://api.mailgun.net/v3/routes?limit=100", {
        headers: {
          Authorization: `Basic ${Buffer.from(`api:${apiKey}`).toString("base64")}`,
        },
      });
      if (!listResp.ok) {
        const errBody = await listResp.json().catch(() => ({})) as any;
        const errMsg = (errBody?.message || "").toLowerCase();
        const permissionError = listResp.status === 401 || listResp.status === 403 ||
          errMsg.includes("permission") || errMsg.includes("unauthorized") || errMsg.includes("forbidden") || errMsg.includes("not authorized");
        return res.json({ configured: true, routeExists: false, hasPrimaryKey, permissionError,
          error: permissionError ? "API key lacks route management permissions — add MAILGUN_PRIMARY_KEY" : `Mailgun API error: ${listResp.status}` });
      }
      const host2 = req.headers["x-forwarded-host"] || req.headers.host || "";
      const proto2 = req.headers["x-forwarded-proto"] || "https";
      const currentWebhookUrl = `${proto2}://${host2}/api/webhook/mailgun/inbound`;

      const listData = await listResp.json() as { items?: Array<{ id: string; expression: string; actions: string[] }> };
      const existing = (listData.items || []).find(r =>
        r.expression === expression || r.actions.some(a => a.includes("/api/webhook/mailgun/inbound"))
      );
      const urlMatches = existing ? existing.actions.some(a => a.includes(currentWebhookUrl)) : false;
      res.json({ configured: true, routeExists: !!existing && urlMatches, routeId: existing?.id, hasPrimaryKey,
        staleUrl: existing && !urlMatches ? true : false });
    } catch (err: any) {
      res.json({ configured: false, routeExists: false, hasPrimaryKey: false, error: err.message });
    }
  });

