  // Import a specific Eventbrite event by URL or ID
  // ── Shared helper: fetch & insert one Eventbrite event by numeric ID ──────────
  async function importEventbriteEventById(
    eventId: string,
    organizerId: number,
    token: string
  ): Promise<{ status: "inserted" | "skipped" | "error"; title?: string; reason?: string }> {
    const ebRes = await fetch(
      `https://www.eventbriteapi.com/v3/events/${eventId}/?expand=venue,ticket_classes,category,subcategory`,
      { headers: { "Authorization": `Bearer ${token}` } }
    );
    if (!ebRes.ok) {
      const txt = await ebRes.text().catch(() => "");
      return { status: "error", reason: `HTTP ${ebRes.status}: ${txt.slice(0, 120)}` };
    }
    const ev = await ebRes.json() as any;
    if (ev.error) return { status: "error", reason: ev.error_description || ev.error };

    // Check duplicate
    const existing = await db.select({ id: events.id })
      .from(events)
      .where(and(eq(events.source, "eventbrite"), eq(events.externalId, ev.id)))
      .limit(1);
    if (existing.length > 0) return { status: "skipped", title: ev.name?.text };

    // ── Map fields ─────────────────────────────────────────────────────────────
    const EB_CAT: Record<string, string> = {
      "103": "music", "105": "art", "108": "sports", "110": "food",
      "113": "community", "115": "workshop", "119": "cultural", "199": "festival",
    };
    const EB_GENRE: Record<string, string> = {
      "1005": "hiphop", "1006": "jazz", "1007": "latin", "1008": "electronic",
      "1009": "reggae", "1011": "pop", "1012": "rnb", "1013": "rock",
    };
    const category = EB_CAT[ev.category_id] || "cultural";
    const musicGenre = EB_GENRE[ev.subcategory_id] || undefined;

    const isPaid = !ev.is_free;
    const ticketClasses: any[] = ev.ticket_classes || [];
    const minPriceMajor = ticketClasses
      .filter(t => !t.free && t.cost?.major_value)
      .reduce((min, t) => {
        const v = parseFloat(t.cost.major_value);
        return v < min ? v : min;
      }, Infinity);
    const maxPriceMajor = ticketClasses
      .filter(t => !t.free && t.cost?.major_value)
      .reduce((max, t) => {
        const v = parseFloat(t.cost.major_value);
        return v > max ? v : max;
      }, -Infinity);
    const price = isFinite(minPriceMajor) ? Math.round(minPriceMajor * 100) : null;
    const maxPrice = isFinite(maxPriceMajor) ? Math.round(maxPriceMajor * 100) : null;
    const priceModel = !isPaid ? "free" : (price && maxPrice && price < maxPrice) ? "from" : isPaid ? "paid" : "free";

    const venue = ev.venue;
    const city = venue?.address?.city || "Nederland";
    const addr = venue?.address?.localized_address_display || city;
    const location = venue?.name ? `${venue.name}, ${addr}` : addr;

    await db.insert(events).values({
      title: (ev.name?.text || "Eventbrite Event").slice(0, 200),
      description: (ev.description?.text || ev.name?.text || "").slice(0, 2000),
      date: new Date(ev.start?.utc || ev.start?.local),
      endDate: ev.end ? new Date(ev.end.utc || ev.end.local) : undefined,
      location,
      city,
      latitude: venue?.latitude ? String(venue.latitude) : undefined,
      longitude: venue?.longitude ? String(venue.longitude) : undefined,
      category,
      musicGenre,
      isPaid,
      price,
      priceModel,
      adultPrice: price,
      image: ev.logo?.original?.url || ev.logo?.url || undefined,
      externalTicketLink: ev.url,
      soldOut: ev.ticket_availability?.is_sold_out || false,
      source: "eventbrite",
      externalId: ev.id,
      status: "approved",
      organizerId,
      isVerifiedOrganizer: true,
      isFeatured: false,
      isTrending: false,
    } as any);

    return { status: "inserted", title: ev.name?.text };
  }

  app.post("/api/admin/events/import/eventbrite-url", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { url: rawUrl, urls: rawUrls } = req.body;
      const token = process.env.EVENTBRITE_PRIVATE_TOKEN || process.env.EVENTBRITE_API_KEY || process.env.EVENTBRITE_TOKEN;
      if (!token) return res.status(400).json({ message: "EVENTBRITE_PRIVATE_TOKEN niet geconfigureerd" });

      // Support single URL or array of URLs
      const urlList: string[] = rawUrls
        ? (Array.isArray(rawUrls) ? rawUrls : String(rawUrls).split(/[\n,]+/))
        : rawUrl ? [rawUrl] : [];
      if (urlList.length === 0) return res.status(400).json({ message: "url of urls is required" });

      const organizerId = (req as any).user?.id ?? 4;
      let synced = 0; let skipped = 0;
      const errors: string[] = [];
      const importedTitles: string[] = [];

      for (const rawU of urlList.map(u => u.trim()).filter(Boolean)) {
        // Extract numeric event ID from various Eventbrite URL formats
        const match = rawU.match(/(?:\/e\/[^/?#]+-|\/e\/)(\d+)|^(\d+)$/);
        const eventId = match?.[1] || match?.[2];
        if (!eventId) { errors.push(`Ongeldig URL: ${rawU.slice(0, 80)}`); continue; }

        const result = await importEventbriteEventById(eventId, organizerId, token);
        if (result.status === "inserted") { synced++; if (result.title) importedTitles.push(result.title); }
        else if (result.status === "skipped") skipped++;
        else errors.push(`${eventId}: ${result.reason}`);
      }

      eventsCache.flushAll();
      const summary = synced === 1 && importedTitles[0]
        ? `✅ "${importedTitles[0]}" succesvol geïmporteerd`
        : `✅ ${synced} event(s) geïmporteerd, ${skipped} al aanwezig`;
      res.json({ message: summary, synced, skipped, errors, importedTitles });
    } catch (err: any) {
      console.error("Eventbrite URL import error:", err);
      res.status(500).json({ message: err.message });
    }
  });

