  // ─── Event Quality Validation ───────────────────────────────────────────────

  async function checkUrl(url: string): Promise<{ reachable: boolean; httpStatus: number | null; ms: number; error?: string }> {
    const start = Date.now();
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 8000);
    try {
      const resp = await fetch(url, {
        method: "HEAD",
        signal: controller.signal,
        headers: { "User-Agent": "Mozilla/5.0 (compatible; UrbanCultureHub/1.0; +https://urbanculturehub.nl)" },
        redirect: "follow",
      });
      clearTimeout(timer);
      return { reachable: resp.status < 400, httpStatus: resp.status, ms: Date.now() - start };
    } catch (err: any) {
      clearTimeout(timer);
      if (err.name === "AbortError") return { reachable: false, httpStatus: null, ms: Date.now() - start, error: "timeout" };
      return { reachable: false, httpStatus: null, ms: Date.now() - start, error: err.message?.slice(0, 80) };
    }
  }

  function validateEventData(event: any): Array<{ field: string; type: "error" | "warning" | "info"; message: string; suggestion?: string }> {
    const issues: Array<{ field: string; type: "error" | "warning" | "info"; message: string; suggestion?: string }> = [];
    const now = new Date();

    if (!event.title?.trim()) issues.push({ field: "title", type: "error", message: "Titel ontbreekt", suggestion: "Voeg een duidelijke evenementtitel toe" });
    if (!event.description || event.description.trim().length < 50) issues.push({ field: "description", type: "warning", message: "Beschrijving te kort (< 50 tekens)", suggestion: "Schrijf een beschrijving van minimaal 100 woorden voor betere vindbaarheid" });
    if (!event.location?.trim()) issues.push({ field: "location", type: "error", message: "Locatie ontbreekt", suggestion: "Voeg het exacte adres of de zaalname toe" });
    if (!event.city?.trim()) issues.push({ field: "city", type: "warning", message: "Stad ontbreekt", suggestion: "Voeg de stad toe (bijv. Amsterdam, Rotterdam)" });
    if (!event.image?.trim()) issues.push({ field: "image", type: "warning", message: "Geen omslagafbeelding", suggestion: "Upload een afbeelding van minimaal 1200×630px" });
    if (!event.musicGenre?.trim()) issues.push({ field: "musicGenre", type: "info", message: "Geen muziekgenre ingesteld", suggestion: "Stel het genre in (bijv. Electronic, Hip-Hop, Afrobeats)" });
    if (!event.category?.trim()) issues.push({ field: "category", type: "warning", message: "Categorie ontbreekt" });
    if (event.isPaid && !event.price) issues.push({ field: "price", type: "warning", message: "Betaald evenement maar geen prijs ingesteld", suggestion: "Voeg de ticketprijs toe in euros" });

    if (event.date) {
      const d = new Date(event.date);
      if (isNaN(d.getTime())) {
        issues.push({ field: "date", type: "error", message: "Ongeldige datum" });
      } else if (d < now) {
        const daysAgo = Math.floor((now.getTime() - d.getTime()) / 86400000);
        issues.push({ field: "date", type: "warning", message: `Datum ligt ${daysAgo} dag(en) in het verleden`, suggestion: "Update de datum of verwijder het evenement" });
      } else if (d.getFullYear() > 2027) {
        issues.push({ field: "date", type: "info", message: "Datum ligt meer dan 2 jaar in de toekomst" });
      }
    } else {
      issues.push({ field: "date", type: "error", message: "Datum ontbreekt" });
    }

    if (!event.externalTicketLink?.trim()) {
      issues.push({ field: "externalTicketLink", type: "info", message: "Geen ticketlink", suggestion: "Voeg een directe link toe naar de ticketverkoop" });
    }

    return issues;
  }

  app.get("/api/admin/events/validate", requireAdmin, async (_req: Request, res: Response) => {
    try {
      const allEvents = await db.query.events.findMany({ orderBy: (e, { asc }) => [asc(e.date)] });

      const results = await Promise.all(
        allEvents.map(async (evt) => {
          const dataIssues = validateEventData(evt);
          let linkCheck: { reachable: boolean; httpStatus: number | null; ms: number; error?: string } | null = null;

          if (evt.externalTicketLink?.startsWith("http")) {
            linkCheck = await checkUrl(evt.externalTicketLink);
            if (!linkCheck.reachable) {
              dataIssues.push({
                field: "externalTicketLink",
                type: "error",
                message: `Ticketlink onbereikbaar${linkCheck.httpStatus ? ` (HTTP ${linkCheck.httpStatus})` : linkCheck.error === "timeout" ? " (timeout)" : ""}`,
                suggestion: "Vervang de link door de echte event- of venuepagina"
              });
            }
          }

          const errors = dataIssues.filter(i => i.type === "error").length;
          const warnings = dataIssues.filter(i => i.type === "warning").length;
          const status = errors > 0 ? "error" : warnings > 0 ? "warning" : "valid";

          return {
            id: evt.id,
            title: evt.title,
            date: evt.date,
            location: evt.location,
            city: evt.city,
            source: (evt as any).source,
            musicGenre: (evt as any).musicGenre,
            externalTicketLink: evt.externalTicketLink,
            status,
            issues: dataIssues,
            linkCheck,
          };
        })
      );

      res.json(results);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.post("/api/admin/events/validate/url", requireAdmin, async (req: Request, res: Response) => {
    const { url } = req.body;
    if (!url || typeof url !== "string") return res.status(400).json({ message: "url required" });
    try {
      const result = await checkUrl(url);
      res.json(result);
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  app.patch("/api/admin/events/:id/fields", requireAdmin, async (req: Request, res: Response) => {
    const id = parseInt(req.params.id);
    if (isNaN(id)) return res.status(400).json({ message: "Invalid id" });
    try {
      const allowed = ["externalTicketLink", "date", "endDate", "location", "city", "image", "price", "musicGenre", "description", "title"];
      const patch: Record<string, any> = {};
      for (const key of allowed) {
        if (key in req.body) patch[key] = req.body[key];
      }
      if (Object.keys(patch).length === 0) return res.status(400).json({ message: "No valid fields" });
      const adminId = (req as any).admin?.id ?? 1;
      const updated = await storage.modifyEvent(id, adminId, patch as any);
      if (!updated) return res.status(404).json({ message: "Event not found" });
      res.json({ success: true });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

  // ─────────────────────────────────────────────────────────────────────────────

  app.post("/api/admin/events/scheduler/toggle", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { pauseEventScheduler, resumeEventScheduler, getSchedulerStatus } = await import("./eventScheduler");
      const { enabled } = req.body;
      if (enabled) resumeEventScheduler(); else pauseEventScheduler();
      res.json(getSchedulerStatus());
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

