  // ── Seed endpoint (idempotent — safe to run multiple times) ──────────────
  app.post("/api/admin/funding/seed", requireAdmin, async (req: Request, res: Response) => {
    try {
      const existingOpps = await storage.getFundingOpportunities({ limit: 500 });
      const existingTitles = new Set(existingOpps.map(o => o.title));
      const existingSources = await storage.getFundingSources();
      const existingSourceNames = new Set(existingSources.map(s => s.name));

      let newSources = 0;
      for (const s of DUTCH_FUNDING_SOURCES_SEED) {
        if (!existingSourceNames.has(s.name)) {
          await storage.createFundingSource({ ...s, isActive: true, crawlFrequency: "weekly", lastSuccess: new Date() });
          newSources++;
        }
      }

      let inserted = 0;
      for (const opp of DUTCH_FUNDING_SEED) {
        if (!existingTitles.has(opp.title)) {
          await storage.createFundingOpportunity({
            ...opp,
            deadline: opp.deadline ? new Date(opp.deadline) : null,
            applicationStartDate: (opp as any).applicationStartDate ? new Date((opp as any).applicationStartDate) : null,
            lastCheckedDate: new Date(),
            publishedAt: new Date(),
          } as any);
          inserted++;
        }
      }
      const total = existingOpps.length + inserted;
      res.json({ message: inserted > 0 ? `${inserted} nieuwe subsidies toegevoegd (totaal: ${total})` : `Alles up-to-date (${total} subsidies)`, new: inserted, total });
    } catch (err: any) {
      res.status(500).json({ message: err.message });
    }
  });

