  app.post("/api/admin/push/send", requireAdmin, async (req: Request, res: Response) => {
    try {
      const adminId = (req as any).admin?.id;
      const { title, body, targetType, targetValue, iconUrl, actionUrl } = req.body;
      if (!title || !body) return res.status(400).json({ message: "title and body are required" });

      let userIds: number[] = [];
      if (targetType === 'user' && targetValue) {
        userIds = [parseInt(targetValue)];
      } else if (targetType === 'segment') {
        userIds = await storage.getUserIdsWithTokensBySegment(targetValue || 'all');
      } else {
        userIds = await storage.getAllUserIdsWithTokens();
      }

      let sentCount = 0;
      let failedCount = 0;

      await Promise.allSettled(
        userIds.map(async (uid) => {
          try {
            await sendPushToUser(uid, {
              title,
              body,
              icon: iconUrl || '/logo.jpg',
              url: actionUrl || '/',
              data: actionUrl ? { url: actionUrl } : {},
            });
            sentCount++;
          } catch {
            failedCount++;
          }
        })
      );

      const log = await storage.logPushNotification({
        sentBy: adminId,
        title,
        body,
        targetType: targetType || 'all',
        targetValue,
        sentCount,
        failedCount,
        iconUrl,
        actionUrl,
      });

      res.json({ success: true, sentCount, failedCount, log });
    } catch (err) {
      console.error("[Admin Push] Error sending:", err);
      res.status(500).json({ message: "Failed to send push notification" });
    }
  });

