  // ─────────────────────────────────────────────────────────────────────────────
  // Push Diagnostic Tool — runs full server-side diagnostic + real FCM send
  // Returns the EXACT FCM/APNs error code so we know exactly what's wrong
  // ─────────────────────────────────────────────────────────────────────────────
  const pushReports = new Map<string, { createdAt: number; data: any }>();

  app.post("/api/admin/push/diagnostic", requireAdmin, async (req: Request, res: Response) => {
    const adminId = (req as any).admin?.id;
    const out: any = {
      timestamp: new Date().toISOString(),
      admin: { id: adminId, email: (req as any).admin?.email },
      server: {},
      tokens: [],
      fcmTest: null,
    };

    try {
      out.server.firebaseAdminInitialized = false;
      out.server.firebaseProjectId = null;
      try {
        const { getApps } = await import("firebase-admin/app");
        const apps = getApps();
        out.server.firebaseAdminInitialized = apps.length > 0;
        if (apps.length > 0) {
          const opts = (apps[0] as any).options || {};
          out.server.firebaseProjectId =
            opts.projectId ||
            opts.credential?.projectId ||
            (apps[0] as any).projectId ||
            null;
        }
        if (!out.server.firebaseProjectId && process.env.FIREBASE_SERVICE_ACCOUNT) {
          try {
            const sa = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT);
            out.server.firebaseProjectId = sa.project_id || sa.projectId || null;
          } catch {}
        }
        if (!out.server.firebaseProjectId) {
          out.server.firebaseProjectId =
            process.env.FIREBASE_PROJECT_ID ||
            process.env.GOOGLE_CLOUD_PROJECT ||
            process.env.GCLOUD_PROJECT ||
            null;
        }
      } catch (e: any) {
        out.server.firebaseAdminError = e?.message || String(e);
      }

      out.server.envVars = {
        FIREBASE_SERVICE_ACCOUNT: !!process.env.FIREBASE_SERVICE_ACCOUNT,
        VITE_FIREBASE_API_KEY: !!process.env.VITE_FIREBASE_API_KEY,
        VITE_FIREBASE_PROJECT_ID: !!process.env.VITE_FIREBASE_PROJECT_ID,
        VITE_FIREBASE_AUTH_DOMAIN: !!process.env.VITE_FIREBASE_AUTH_DOMAIN,
        VITE_FIREBASE_MESSAGING_SENDER_ID: !!process.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
        VITE_FIREBASE_APP_ID: !!process.env.VITE_FIREBASE_APP_ID,
        VITE_FIREBASE_VAPID_KEY: !!process.env.VITE_FIREBASE_VAPID_KEY,
      };
      out.server.publicProjectId = process.env.VITE_FIREBASE_PROJECT_ID || null;

      const { pushTokens } = await import("@shared/schema");
      const rows = await db
        .select({ id: pushTokens.id, token: pushTokens.token, platform: pushTokens.platform, createdAt: pushTokens.createdAt, updatedAt: pushTokens.updatedAt })
        .from(pushTokens)
        .where(eq(pushTokens.userId, adminId));

      out.tokens = rows.map(r => ({
        id: r.id,
        platform: r.platform,
        tokenPreview: r.token ? `${r.token.slice(0, 18)}…${r.token.slice(-8)}` : null,
        tokenLength: r.token?.length || 0,
        createdAt: r.createdAt,
        updatedAt: r.updatedAt,
      }));

      if (rows.length === 0) {
        out.fcmTest = { skipped: true, reason: "no_tokens", message: "No push tokens registered for this admin. Open the app in iOS, log in as this admin, and tap 'Enable Push'." };
      } else if (!out.server.firebaseAdminInitialized) {
        out.fcmTest = { skipped: true, reason: "firebase_not_initialized", message: "Firebase Admin SDK is not initialized on the server — FIREBASE_SERVICE_ACCOUNT is missing or invalid." };
      } else {
        const { getMessaging } = await import("firebase-admin/messaging");
        const messaging = getMessaging();

        const results = await Promise.all(rows.map(async (r) => {
          const result: any = { tokenId: r.id, platform: r.platform };
          try {
            const messageId = await messaging.send({
              token: r.token,
              notification: { title: "🔔 Diagnostic Test", body: "If you see this, push works on this device." },
              apns: {
                payload: { aps: { alert: { title: "🔔 Diagnostic Test", body: "If you see this, push works on this device." }, sound: "default", badge: 1 } },
              },
              webpush: {
                notification: { title: "🔔 Diagnostic Test", body: "If you see this, push works on this device.", icon: "/logo.jpg" },
              },
            });
            result.success = true;
            result.messageId = messageId;
          } catch (err: any) {
            result.success = false;
            result.errorCode = err?.errorInfo?.code || err?.code || "unknown";
            result.errorMessage = err?.errorInfo?.message || err?.message || String(err);
            const c = result.errorCode;
            if (c === "messaging/registration-token-not-registered") {
              result.diagnosis = "Token is no longer valid. The user uninstalled the app, denied notifications, or the token expired. Re-register from the iOS device.";
            } else if (c === "messaging/invalid-registration-token") {
              result.diagnosis = "Token format is invalid. The bridge returned a malformed token — check WTN Firebase plugin version.";
            } else if (c === "messaging/invalid-apns-credentials" || c === "messaging/third-party-auth-error") {
              result.diagnosis = "APNs Auth Key is missing or invalid in Firebase Console. Upload .p8 key under Project Settings → Cloud Messaging → Apple app.";
            } else if (c === "messaging/mismatched-credential") {
              result.diagnosis = "FIREBASE_SERVICE_ACCOUNT does not match the project of the iOS token. The GoogleService-Info.plist in WTN points to a different Firebase project.";
            } else if (c === "messaging/sender-id-mismatch") {
              result.diagnosis = "Sender ID mismatch — the FCM token belongs to a different Firebase project than the server is sending from.";
            } else {
              result.diagnosis = "Unexpected FCM error. Full error message above.";
            }
          }
          return result;
        }));

        out.fcmTest = { skipped: false, results };
      }

      res.json(out);
    } catch (err: any) {
      console.error("[Admin Push] Diagnostic error:", err);
      res.status(500).json({ ...out, fatalError: err?.message || String(err) });
    }
  });

  // Save a client-collected diagnostic report and return a short ID to share
  app.post("/api/admin/push/diagnostic-report", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = Math.random().toString(36).slice(2, 8).toUpperCase();
      pushReports.set(id, { createdAt: Date.now(), data: req.body || {} });
      // Prune old reports (older than 24h)
      const cutoff = Date.now() - 24 * 60 * 60 * 1000;
      for (const [k, v] of pushReports.entries()) if (v.createdAt < cutoff) pushReports.delete(k);
      res.json({ reportId: id });
    } catch (err: any) {
      res.status(500).json({ message: err?.message || "Failed to save report" });
    }
  });

