  // ─────────────────────────────────────────────────────────────────────────────

  // ==================== ADMIN AI STUDIO ====================

  // In-memory video job store (survives navigation, lives for server lifetime)
  const aiVideoJobs = new Map<string, { status: string; url?: string; error?: string; prompt: string; modelId: string; createdAt: number; startedAt: number }>();

  // Background server-side polling — keeps running even when user navigates away
  const startSoraServerPolling = (jobId: string, apiKey: string) => {
    let attempts = 0;
    const maxAttempts = 60; // ~10 minutes at 10s intervals
    const timer = setInterval(async () => {
      attempts++;
      if (attempts > maxAttempts) {
        const job = aiVideoJobs.get(jobId);
        if (job) { job.status = "failed"; job.error = "Timed out after 10 minutes"; }
        clearInterval(timer);
        return;
      }
      try {
        const res = await fetch(`https://api.openai.com/v1/videos/${jobId}`, {
          headers: { "Authorization": `Bearer ${apiKey}` },
        });
        const rawText = await res.text();
        let data: any = {};
        try { data = JSON.parse(rawText); } catch { return; }
        if (!res.ok) { console.error(`[Sora BG] poll error ${res.status}:`, rawText.slice(0, 200)); return; }

        const job = aiVideoJobs.get(jobId);
        if (!job) { clearInterval(timer); return; }

        console.log(`[Sora BG] job ${jobId} status: ${data.status}`);

        if (data.status === "completed" || data.status === "succeeded") {
          clearInterval(timer);
          // Download and upload to Cloudinary for a persistent URL
          try {
            const contentRes = await fetch(`https://api.openai.com/v1/videos/${jobId}/content`, {
              headers: { "Authorization": `Bearer ${apiKey}` },
            });
            if (contentRes.ok) {
              const buffer = Buffer.from(await contentRes.arrayBuffer());
              const base64 = `data:video/mp4;base64,${buffer.toString("base64")}`;
              const { uploadImage } = await import('./cloudinary');
              const uploadResult = await uploadImage(base64, 'ai-studio/sora', 'video');
              job.status = "succeeded";
              job.url = uploadResult.url;
              console.log(`[Sora BG] job ${jobId} completed, uploaded to Cloudinary`);
              return;
            }
          } catch (uploadErr: any) {
            console.error("[Sora BG] Cloudinary upload failed:", uploadErr.message);
          }
          job.status = "succeeded";
          job.url = data.url || data.data?.[0]?.url;
        } else if (data.status === "failed") {
          clearInterval(timer);
          job.status = "failed";
          job.error = data.error?.message || "Generation failed";
        } else {
          job.status = data.status || "in_progress";
        }
      } catch (err: any) {
        console.error("[Sora BG] poll exception:", err.message);
      }
    }, 10000);
  };

  // Start Sora video generation
  app.post("/api/admin/ai-studio/video", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = (req as any).user;
      if (!user || (user.role !== "admin" && user.role !== "super_admin")) return res.status(403).json({ error: "Admin only" });
      const { prompt, size = "1280x720", duration = 5 } = req.body;
      if (!prompt?.trim()) return res.status(400).json({ error: "Prompt is required" });

      const apiKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
      if (!apiKey) return res.status(500).json({ error: "OpenAI API key not configured" });

      // Map duration to nearest valid Sora 2 value (4, 8, or 12)
      const rawDuration = Number(duration) || 5;
      const seconds = rawDuration <= 4 ? "4" : rawDuration <= 8 ? "8" : "12";
      // Map size to valid Sora 2 sizes
      const validSizes: Record<string, string> = { "1920x1080": "1280x720", "1280x720": "1280x720", "720x1280": "720x1280", "1024x1792": "1024x1792", "1792x1024": "1792x1024" };
      const mappedSize = validSizes[size] || "1280x720";

      const requestBody = { model: "sora-2", prompt: prompt.trim(), size: mappedSize, seconds };
      console.log("[Sora] Request body:", JSON.stringify(requestBody));

      const response = await fetch("https://api.openai.com/v1/videos", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${apiKey}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(requestBody),
      });

      const rawText = await response.text();
      console.log("[Sora] Response status:", response.status, "body:", rawText.slice(0, 600));

      let data: any = {};
      try { data = JSON.parse(rawText); } catch { data = {}; }

      if (!response.ok) {
        const rawErr = typeof data?.error === "string" ? data.error : data?.error?.message || data?.message || rawText.slice(0, 300);
        let errMsg = rawErr;
        if (response.status === 429) errMsg = "Rate limit reached — OpenAI Sora API has a request limit. Please wait a minute and try again.";
        else if (response.status === 401 || response.status === 403) errMsg = "OpenAI API key is invalid or doesn't have access to Sora. Check your key at platform.openai.com.";
        else if (response.status === 402) errMsg = "OpenAI account needs API credits. Add credits at platform.openai.com/settings/billing.";
        else if (!errMsg) errMsg = `OpenAI returned error ${response.status}`;
        return res.status(500).json({ error: errMsg });
      }

      const jobId = data.id || data.generation_id;
      if (!jobId) return res.status(500).json({ error: "No job ID returned: " + rawText.slice(0, 200) });

      const now = Date.now();
      aiVideoJobs.set(jobId, { status: data.status || "queued", prompt, modelId: "sora", createdAt: now, startedAt: now });

      // Start server-side background polling — continues even if user navigates away
      startSoraServerPolling(jobId, apiKey);

      res.json({ jobId, status: data.status || "queued" });
    } catch (err: any) {
      console.error("AI Studio video error:", err);
      res.status(500).json({ error: err.message || "Failed to start video generation" });
    }
  });

  // List all Sora jobs (for re-syncing when user returns to the page)
  app.get("/api/admin/ai-studio/jobs", authenticateJWT, async (req: Request, res: Response) => {
    const user = (req as any).user;
    if (!user || (user.role !== "admin" && user.role !== "super_admin")) return res.status(403).json({ error: "Admin only" });
    const jobs = Array.from(aiVideoJobs.entries()).map(([id, job]) => ({ id, ...job }));
    // Return most recent first, cap at 50
    jobs.sort((a, b) => b.createdAt - a.createdAt);
    res.json(jobs.slice(0, 50));
  });

  // Poll Sora video job status
  app.get("/api/admin/ai-studio/video/:jobId", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = (req as any).user;
      if (!user || (user.role !== "admin" && user.role !== "super_admin")) return res.status(403).json({ error: "Admin only" });
      const { jobId } = req.params;
      const apiKey = process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
      if (!apiKey) return res.status(500).json({ error: "OpenAI API key not configured" });

      const response = await fetch(`https://api.openai.com/v1/videos/${jobId}`, {
        headers: { "Authorization": `Bearer ${apiKey}` },
      });

      const rawText = await response.text();
      console.log("[Sora Poll] status:", response.status, "body:", rawText.slice(0, 600));
      let data: any = {};
      try { data = JSON.parse(rawText); } catch { data = {}; }

      if (!response.ok) {
        const rawErr = typeof data?.error === "string" ? data.error : data?.error?.message || data?.message || rawText.slice(0, 200);
        return res.status(500).json({ error: rawErr || `Status check failed (${response.status})` });
      }

      const job = aiVideoJobs.get(jobId);
      if (data.status === "completed" || data.status === "succeeded") {
        // Download video content and upload to Cloudinary for persistent URL
        try {
          const contentRes = await fetch(`https://api.openai.com/v1/videos/${jobId}/content`, {
            headers: { "Authorization": `Bearer ${apiKey}` },
          });
          if (contentRes.ok) {
            const buffer = Buffer.from(await contentRes.arrayBuffer());
            const base64 = `data:video/mp4;base64,${buffer.toString("base64")}`;
            const { uploadImage } = await import('./cloudinary');
            const uploadResult = await uploadImage(base64, 'ai-studio/sora', 'video');
            const videoUrl = uploadResult.url;
            if (job) job.status = "succeeded";
            if (job) (job as any).url = videoUrl;
            return res.json({ status: "succeeded", url: videoUrl, prompt: job?.prompt });
          }
        } catch (uploadErr: any) {
          console.error("[Sora] Failed to upload video to Cloudinary:", uploadErr.message);
        }
        // Fallback: check if URL is in response
        const videoUrl = data.url || data.data?.[0]?.url;
        if (job) job.status = "succeeded";
        return res.json({ status: "succeeded", url: videoUrl, prompt: job?.prompt });
      }
      if (data.status === "failed") {
        if (job) job.status = "failed";
        return res.json({ status: "failed", error: data.error?.message || "Generation failed" });
      }
      res.json({ status: data.status || "in_progress", prompt: job?.prompt });
    } catch (err: any) {
      console.error("AI Studio poll error:", err);
      res.status(500).json({ error: err.message || "Failed to check status" });
    }
  });

  // DALL-E 3 image generation
  app.post("/api/admin/ai-studio/image", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = (req as any).user;
      if (!user || (user.role !== "admin" && user.role !== "super_admin")) return res.status(403).json({ error: "Admin only" });
      const { prompt, size = "1024x1024", quality = "high", style = "vivid", model = "gpt-image-1" } = req.body;
      if (!prompt?.trim()) return res.status(400).json({ error: "Prompt is required" });

      const OpenAI = (await import("openai")).default;
      const openaiClient = new OpenAI({
        apiKey: process.env.OPENAI_API_KEY || process.env.AI_INTEGRATIONS_OPENAI_API_KEY || "",
        baseURL: "https://api.openai.com/v1",
      });

      // ── Flux 1.1 Pro via Replicate ──────────────────────────────────────────
      if (model === "flux-1.1-pro") {
        const replicateToken = process.env.REPLICATE_API_TOKEN;
        if (!replicateToken) return res.status(400).json({ error: "Replicate API key not configured" });
        const aspectRatio = size === "1536x1024" ? "3:2" : size === "1024x1536" ? "2:3" : "1:1";
        const startResp = await fetch("https://api.replicate.com/v1/models/black-forest-labs/flux-1.1-pro/predictions", {
          method: "POST",
          headers: { "Authorization": `Bearer ${replicateToken}`, "Content-Type": "application/json", "Prefer": "wait" },
          body: JSON.stringify({ input: { prompt: prompt.trim(), aspect_ratio: aspectRatio, output_format: "webp", output_quality: 95, safety_tolerance: 2 } }),
        });
        const startData = await startResp.json() as any;
        const outputUrl = Array.isArray(startData.output) ? startData.output[0] : startData.output;
        if (!outputUrl) return res.status(500).json({ error: startData.error || "Flux generation failed" });
        return res.json({ url: outputUrl, model: "flux-1.1-pro" });
      }

      // ── DALL-E 3 (legacy) ───────────────────────────────────────────────────
      if (model === "dall-e-3") {
        const d3size = size === "1536x1024" ? "1792x1024" : size === "1024x1536" ? "1024x1792" : "1024x1024";
        const response = await openaiClient.images.generate({
          model: "dall-e-3",
          prompt: prompt.trim(),
          n: 1,
          size: d3size as any,
          quality: (quality === "high" ? "hd" : "standard") as any,
          style: style as any,
        });
        const url = response.data?.[0]?.url;
        const revisedPrompt = response.data?.[0]?.revised_prompt;
        return res.json({ url, revisedPrompt, model: "dall-e-3" });
      }

      // ── GPT Image 1 (default, newest OpenAI model) ──────────────────────────
      const gptSize = ["1024x1024", "1536x1024", "1024x1536", "auto"].includes(size) ? size : "1024x1024";
      const gptQuality = ["low", "medium", "high", "auto"].includes(quality) ? quality : "high";
      const response = await openaiClient.images.generate({
        model: "gpt-image-1",
        prompt: prompt.trim(),
        n: 1,
        size: gptSize as any,
        quality: gptQuality as any,
      } as any);
      const b64 = (response.data?.[0] as any)?.b64_json;
      if (!b64) return res.status(500).json({ error: "No image data returned from GPT Image 1" });
      const dataUrl = `data:image/png;base64,${b64}`;
      res.json({ url: dataUrl, model: "gpt-image-1" });
    } catch (err: any) {
      console.error("AI Studio image error:", err);
      res.status(500).json({ error: err.message || "Image generation failed" });
    }
  });

