  app.get("/api/admin/ai-studio/fal/status", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = (req as any).user;
      if (!user || (user.role !== "admin" && user.role !== "super_admin")) return res.status(403).json({ error: "Admin only" });
      const apiKey = process.env.FAL_KEY;
      if (!apiKey) return res.status(503).json({ error: "FAL_KEY not set" });

      const { model, requestId } = req.query as Record<string, string>;
      if (!model || !requestId) return res.status(400).json({ error: "model and requestId required" });

      const statusRes = await fetch(`https://queue.fal.run/${model}/requests/${requestId}/status`, {
        headers: { "Authorization": `Key ${apiKey}` },
      });
      const statusData = await statusRes.json() as any;

      if (statusData.status === "COMPLETED") {
        const resultRes = await fetch(`https://queue.fal.run/${model}/requests/${requestId}`, {
          headers: { "Authorization": `Key ${apiKey}` },
        });
        const result = await resultRes.json() as any;
        const video = result.video?.url || result.videos?.[0]?.url || result.output?.video?.url;
        const image = result.images?.[0]?.url || result.image?.url;
        return res.json({ status: "succeeded", url: video || image, logs: statusData.logs });
      }
      if (statusData.status === "FAILED" || statusData.status === "ERROR") {
        return res.json({ status: "failed", error: statusData.error || "Generation failed" });
      }
      res.json({ status: "in_progress", logs: statusData.logs });
    } catch (err: any) {
      res.status(500).json({ error: err.message });
    }
  });

