  // ==================== HIGGSFIELD AI (Community AI Studio) ====================

  // Submit a Higgsfield video generation job (text-to-video or image-to-video)
  app.post("/api/community/ai-studio/higgsfield/generate", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = (req as any).user;
      if (!user || (user.role !== "admin" && user.role !== "super_admin")) {
        return res.status(403).json({ error: "Admin only" });
      }

      const HF_API_KEY    = process.env.HF_API_KEY;
      const HF_API_SECRET = process.env.HF_API_SECRET;
      if (!HF_API_KEY || !HF_API_SECRET) {
        return res.status(503).json({
          error: "Higgsfield credentials not configured",
          setupKeys: ["HF_API_KEY", "HF_API_SECRET"],
          setupUrl: "https://cloud.higgsfield.ai/api-keys",
        });
      }

      const { prompt, imageUrl, aspectRatio = "9:16", duration = 5, dopModel = "dop-turbo" } = req.body;
      if (!prompt?.trim()) return res.status(400).json({ error: "Prompt is required" });
      if (!imageUrl?.trim()) return res.status(400).json({ error: "A source image URL is required for video generation (DOP is image-to-video)" });

      // DOP model only supports image-to-video
      const endpoint = "/v1/image2video/dop";

      // Build input for DOP image-to-video
      const input: Record<string, any> = {
        prompt: prompt.trim(),
        aspect_ratio: aspectRatio,
        duration,
        model: dopModel,
        input_images: [{ type: "image_url", image_url: imageUrl.trim() }],
      };

      // Submit using V2 API — Authorization: Key KEY_ID:KEY_SECRET
      const authHeader = `Key ${HF_API_KEY}:${HF_API_SECRET}`;
      const submitResp = await fetch(`https://platform.higgsfield.ai${endpoint}`, {
        method: "POST",
        headers: {
          "Authorization": authHeader,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ input }),
      });

      if (!submitResp.ok) {
        const errData = await submitResp.json().catch(() => ({})) as any;
        console.error("[Higgsfield] submit error:", submitResp.status, errData);
        return res.status(submitResp.status).json({ error: errData?.detail || errData?.message || errData?.error || "Higgsfield submission failed" });
      }

      const submitData = await submitResp.json() as any;
      const jobId = submitData.request_id || submitData.id || submitData.job_id;
      res.json({
        jobId,
        status: submitData.status || "queued",
        statusUrl: submitData.status_url,
      });
    } catch (err: any) {
      console.error("[Higgsfield] generate error:", err);
      res.status(500).json({ error: err.message || "Higgsfield request failed" });
    }
  });

  // Poll a Higgsfield job status
  app.get("/api/community/ai-studio/higgsfield/:jobId", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const user = (req as any).user;
      if (!user || (user.role !== "admin" && user.role !== "super_admin")) {
        return res.status(403).json({ error: "Admin only" });
      }

      const HF_API_KEY    = process.env.HF_API_KEY;
      const HF_API_SECRET = process.env.HF_API_SECRET;
      if (!HF_API_KEY || !HF_API_SECRET) {
        return res.status(503).json({ error: "Higgsfield credentials not configured" });
      }

      const authHeader = `Key ${HF_API_KEY}:${HF_API_SECRET}`;
      const { jobId } = req.params;

      // V2 API polling: /requests/{request_id}/status
      const pollResp = await fetch(`https://platform.higgsfield.ai/requests/${jobId}/status`, {
        headers: { "Authorization": authHeader },
      });

      if (!pollResp.ok) {
        const errData = await pollResp.json().catch(() => ({})) as any;
        console.error("[Higgsfield] poll error:", pollResp.status, errData);
        return res.status(pollResp.status).json({ error: errData?.detail || errData?.message || "Poll failed" });
      }

      const data = await pollResp.json() as any;
      const rawStatus = (data.status || "").toLowerCase();

      if (rawStatus === "completed") {
        // V2 response: { video: { url: "..." } } or { images: [{ url: "..." }] }
        const videoUrl = data.video?.url ||
          (Array.isArray(data.images) && data.images[0]?.url) ||
          data.output?.video_url || data.output?.url;
        return res.json({ status: "succeeded", url: videoUrl });
      }
      if (rawStatus === "failed" || rawStatus === "nsfw" || rawStatus === "cancelled") {
        return res.json({ status: "failed", error: data.error || data.message || "Generation failed" });
      }
      // queued / in_progress
      return res.json({ status: rawStatus === "in_progress" ? "processing" : "queued", progress: data.progress });
    } catch (err: any) {
      console.error("[Higgsfield] poll error:", err);
      res.status(500).json({ error: err.message });
    }
  });

