  // Get multiple reels by IDs (for saved reels batch fetch)
  app.get("/api/reels/batch", async (req: Request, res: Response) => {
    try {
      const rawIds = (req.query.ids as string) || "";
      const ids = rawIds.split(",").map(Number).filter(n => !isNaN(n) && n > 0).slice(0, 50);
      if (ids.length === 0) return res.json([]);
      const requestingUserId = (req as any).user?.id;
      const rows = await Promise.all(ids.map(id => storage.getReel(id)));
      const valid = rows.filter(Boolean);
      const likedSet = new Set<number>();
      if (requestingUserId) {
        try {
          const likes = await db.select({ reelId: reelLikes.reelId }).from(reelLikes).where(eq(reelLikes.userId, requestingUserId));
          likes.forEach(l => likedSet.add(l.reelId));
        } catch {}
      }
      const feed = await Promise.all(valid.map(async (reel: any) => {
        const [userRow] = await db.select({ id: users.id, displayName: users.displayName, profilePicture: users.profilePicture }).from(users).where(eq(users.id, reel.userId)).limit(1);
        return { ...reel, isLiked: likedSet.has(reel.id), user: userRow || null };
      }));
      res.json(feed);
    } catch (err: any) {
      res.status(500).json({ error: "Failed to fetch reels batch" });
    }
  });

