  // Increment share count (called when user shares via ShareSheet)
  app.post("/api/reels/:id/share", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const reelId = parseInt(req.params.id);
      if (isNaN(reelId)) return res.status(400).json({ error: "Invalid reel ID" });

      // Server-side share permission check — admin or canShareContent flag required
      const authUser: any = (req as any).user;
      let canShare = false;
      if (authUser?.role === "admin" || authUser?.role === "super_admin") {
        canShare = true;
      } else if (typeof authUser?.canShareContent === "boolean") {
        canShare = authUser.canShareContent === true;
      } else if (authUser?.id) {
        const fresh = await storage.getUser(authUser.id);
        canShare = !!(fresh && ((fresh as any).canShareContent || fresh.role === "admin" || fresh.role === "super_admin"));
      }
      if (!canShare) {
        return res.status(403).json({ error: "Sharing is restricted. Contact an admin to request share access." });
      }

      await storage.incrementReelShares(reelId);
      reelsCache.del("all");
      res.json({ success: true });
    } catch (err) {
      res.status(500).json({ error: "Failed to record share" });
    }
  });

  // Save reel — zero server memory, zero JS memory.
  // Redirects straight to a Cloudinary URL with fl_attachment so the OS
  // downloads the file natively (no JavaScript blob, no WebView crash).
  app.get("/api/reels/:id/save", async (req: Request, res: Response) => {
    try {
      const reelId = parseInt(req.params.id);
      if (isNaN(reelId)) return res.status(400).json({ error: "Invalid reel ID" });

      const reel = await storage.getReel(reelId);
      if (!reel) return res.status(404).json({ error: "Reel not found" });

      const videoUrl: string = (reel as any).videoUrl;
      if (!videoUrl) return res.status(404).json({ error: "Video not found" });

      // Insert Cloudinary transformations: compress + force-download header
      const idx = videoUrl.indexOf("/upload/");
      const saveUrl = idx !== -1
        ? videoUrl.slice(0, idx + 8) + "fl_attachment,q_auto:low,w_720/" + videoUrl.slice(idx + 8)
        : videoUrl;

      // 302 redirect — browser follows it, Cloudinary responds with
      // Content-Disposition: attachment  →  OS saves the file natively
      return res.redirect(302, saveUrl);
    } catch (err: any) {
      console.error("[Reel save] Error:", err?.message);
      return res.status(500).json({ error: "Failed to generate save URL" });
    }
  });

  // Download reel with Urban Culture Hub watermark (server-side ffmpeg)
  app.get("/api/reels/:id/download", async (req: Request, res: Response) => {
    try {
      const reelId = parseInt(req.params.id);
      if (isNaN(reelId)) return res.status(400).json({ error: "Invalid reel ID" });

      const reel = await storage.getReel(reelId);
      if (!reel) return res.status(404).json({ error: "Reel not found" });

      const videoUrl = (reel as any).videoUrl;
      if (!videoUrl) return res.status(404).json({ error: "Video not found" });

      // Pre-flight check: verify ffmpeg is available BEFORE sending any headers.
      // In production (Replit Deploy) ffmpeg may not be present — fall back to
      // the original video URL so the client can still download/share.
      const ffmpegAvailable: boolean = await new Promise((resolve) => {
        const probe = spawn("ffmpeg", ["-version"]);
        probe.on("error", () => resolve(false));
        probe.on("spawn", () => { probe.kill(); resolve(true); });
      });

      if (!ffmpegAvailable) {
        console.warn("[Reel download] ffmpeg not available — proxying original video");
        try {
          const proxyRes = await axios.get(videoUrl, {
            responseType: "stream",
            timeout: 30_000,
            headers: { "User-Agent": "Mozilla/5.0" },
          });
          res.setHeader("Content-Type", proxyRes.headers["content-type"] || "video/mp4");
          res.setHeader("Content-Disposition", `attachment; filename="urban-culture-hub-${reelId}.mp4"`);
          if (proxyRes.headers["content-length"]) {
            res.setHeader("Content-Length", proxyRes.headers["content-length"]);
          }
          res.setHeader("Cache-Control", "public, max-age=3600");
          res.setHeader("Access-Control-Allow-Origin", "*");
          proxyRes.data.pipe(res);
          req.on("close", () => { try { proxyRes.data.destroy(); } catch {} });
          return;
        } catch (proxyErr: any) {
          console.error("[Reel download] proxy failed, falling back to redirect:", proxyErr.message);
          return res.redirect(videoUrl);
        }
      }

      const logoPath = path.join(process.cwd(), "client", "public", "logo.png");
      const hasLogo = fs.existsSync(logoPath);

      res.setHeader("Content-Type", "video/mp4");
      res.setHeader(
        "Content-Disposition",
        `attachment; filename="urban-culture-hub-${reelId}.mp4"`
      );
      res.setHeader("Cache-Control", "no-store");
      // Prevent reverse-proxies / CDN from buffering — client sees bytes as they arrive
      res.setHeader("X-Accel-Buffering", "no");
      res.setHeader("Transfer-Encoding", "chunked");

      const filterComplex = hasLogo
        ? [
            "[1:v]scale=90:90,format=rgba,colorchannelmixer=aa=0.92[logo];",
            "[0:v][logo]overlay=x=W-w-18:y=H-h-90:format=auto[wl];",
            "[wl]drawtext=text='Urban Culture Hub':",
            "fontsize=26:fontcolor=white@0.95:",
            "shadowcolor=black@0.8:shadowx=2:shadowy=2:",
            "x=W-236:y=H-52",
          ].join("")
        : [
            "[0:v]drawtext=text='Urban Culture Hub':",
            "fontsize=28:fontcolor=white@0.9:",
            "shadowcolor=black@0.8:shadowx=2:shadowy=2:",
            "x=W-240:y=H-50",
          ].join("");

      const ffmpegArgs = hasLogo
        ? [
            "-y",
            "-i", videoUrl,
            "-i", logoPath,
            "-filter_complex", filterComplex,
            "-c:v", "libx264",
            "-preset", "ultrafast",
            "-crf", "24",
            "-c:a", "copy",
            "-movflags", "frag_keyframe+empty_moov",
            "-f", "mp4",
            "pipe:1",
          ]
        : [
            "-y",
            "-i", videoUrl,
            "-vf", filterComplex,
            "-c:v", "libx264",
            "-preset", "ultrafast",
            "-crf", "24",
            "-c:a", "copy",
            "-movflags", "frag_keyframe+empty_moov",
            "-f", "mp4",
            "pipe:1",
          ];

      const ffmpeg = spawn("ffmpeg", ffmpegArgs);

      ffmpeg.stdout.pipe(res);

      ffmpeg.stderr.on("data", (_d) => { /* suppress ffmpeg output */ });

      req.on("close", () => {
        try { ffmpeg.kill("SIGKILL"); } catch {}
      });

      ffmpeg.on("error", (err) => {
        console.error("[Reel download] ffmpeg error:", err.message);
        if (!res.headersSent) res.redirect(videoUrl);
      });

      ffmpeg.on("exit", (code) => {
        if (code !== 0 && code !== null) {
          console.warn(`[Reel download] ffmpeg exited ${code} for reel ${reelId}`);
        }
      });

    } catch (err: any) {
      console.error("[Reel download] Error:", err?.message);
      if (!res.headersSent) res.status(500).json({ error: "Download failed" });
    }
  });

