  // ── App Settings (admin write) ────────────────────────────────────────────
  app.post("/api/admin/settings", requireAdmin, async (req: Request, res: Response) => {
    try {
      const adminId = (req as any).user?.id;
      const { key, value } = req.body;
      if (!key || value === undefined) return res.status(400).json({ error: "key and value are required" });

      const existing = await db.select().from(appSettings).where(eq(appSettings.key, key));
      if (existing.length > 0) {
        await db.update(appSettings)
          .set({ value: String(value), updatedAt: new Date(), updatedBy: adminId })
          .where(eq(appSettings.key, key));
      } else {
        await db.insert(appSettings).values({
          key,
          value: String(value),
          label: req.body.label || key,
          description: req.body.description || null,
          updatedBy: adminId,
        });
      }
      res.json({ success: true });
    } catch (err) {
      res.status(500).json({ error: "Failed to update setting" });
    }
  });

  // ── Admin: get all settings ───────────────────────────────────────────────
  app.get("/api/admin/settings", requireAdmin, async (_req: Request, res: Response) => {
    try {
      const rows = await db.select().from(appSettings).orderBy(appSettings.key);
      res.json(rows);
    } catch (err) {
      res.status(500).json({ error: "Failed to fetch settings" });
    }
  });

  // ─────────────────────────────────────────────────────────────────────────────

  // ── App Health Check ─────────────────────────────────────────────────────
  app.get("/api/admin/app-health", requireAdmin, async (_req: Request, res: Response) => {
    const force = _req.query.force === "1";
    if (!force) {
      const cached = appHealthCache.get("result");
      if (cached) return res.json({ ...cached, cached: true });
    }

    const checks: {
      id: string;
      name: string;
      category: string;
      status: "ok" | "warn" | "error";
      message: string;
      recommendation?: string;
      latencyMs?: number;
    }[] = [];

    const run = async (id: string, name: string, category: string, fn: () => Promise<{ status: "ok" | "warn" | "error"; message: string; recommendation?: string }>) => {
      const t0 = Date.now();
      try {
        const result = await fn();
        checks.push({ id, name, category, ...result, latencyMs: Date.now() - t0 });
      } catch (e: any) {
        checks.push({ id, name, category, status: "error", message: e.message || "Unexpected error", recommendation: "Check server logs for stack trace", latencyMs: Date.now() - t0 });
      }
    };

    // ── Database (parallel) ───────────────────────────
    await Promise.all([
      run("db_conn", "Database Connection", "Database", async () => {
        await db.execute(sql`SELECT 1 AS ping`);
        return { status: "ok", message: "PostgreSQL is reachable and responding" };
      }),
      run("db_users", "Users Table", "Database", async () => {
        const result = await db.execute(sql`SELECT COUNT(*) AS cnt FROM users`);
        const cnt = parseInt((result.rows[0] as any)?.cnt ?? "0", 10);
        return { status: "ok", message: `${cnt} users in database` };
      }),
      run("db_events", "Events Table", "Database", async () => {
        const result = await db.execute(sql`SELECT COUNT(*) AS cnt FROM events`);
        const cnt = parseInt((result.rows[0] as any)?.cnt ?? "0", 10);
        return { status: cnt === 0 ? "warn" : "ok", message: cnt === 0 ? "No events found — add real events via the admin panel" : `${cnt} events in database`, recommendation: cnt === 0 ? "Go to Events → Create Event to add your first real event" : undefined };
      }),
      run("db_posts", "Posts Table", "Database", async () => {
        const result = await db.execute(sql`SELECT COUNT(*) AS cnt FROM posts`);
        const cnt = parseInt((result.rows[0] as any)?.cnt ?? "0", 10);
        return { status: "ok", message: `${cnt} community posts in database` };
      }),
    ]);

    // ── Environment Variables ────────────────────────
    const envChecks: { key: string; name: string; critical: boolean }[] = [
      { key: "FIREBASE_SERVICE_ACCOUNT", name: "Firebase Service Account", critical: true },
      { key: "DATABASE_URL", name: "Database URL", critical: true },
      { key: "SESSION_SECRET", name: "Session Secret", critical: true },
      { key: "STRIPE_SECRET_KEY", name: "Stripe Secret Key", critical: false },
      { key: "MAILGUN_API_KEY", name: "Mailgun API Key", critical: false },
      { key: "CLOUDINARY_CLOUD_NAME", name: "Cloudinary Cloud Name", critical: false },
      { key: "CLOUDINARY_API_KEY", name: "Cloudinary API Key", critical: false },
      { key: "ANTHROPIC_API_KEY", name: "Anthropic (AI) API Key", critical: false },
      { key: "OPENAI_API_KEY", name: "OpenAI API Key", critical: false },
    ];
    for (const ev of envChecks) {
      const present = !!process.env[ev.key];
      checks.push({
        id: `env_${ev.key.toLowerCase()}`,
        name: ev.name,
        category: "Environment",
        status: present ? "ok" : ev.critical ? "error" : "warn",
        message: present ? "Set ✓" : `Missing — ${ev.name} is not configured`,
        recommendation: present ? undefined : ev.critical ? `Set the ${ev.key} secret in Replit Secrets (critical for app to work)` : `Set ${ev.key} in Replit Secrets to enable this feature`,
      });
    }

    // ── Integrations (parallel) ──────────────────────
    await Promise.all([
      run("int_firebase", "Firebase Admin SDK", "Integration", async () => {
        if (!process.env.FIREBASE_SERVICE_ACCOUNT) return { status: "error", message: "Firebase Admin SDK not configured — authentication will not work", recommendation: "Set the FIREBASE_SERVICE_ACCOUNT secret in Replit Secrets (must be valid JSON)" };
        try {
          const adminApp = await import("firebase-admin/app");
          const apps = adminApp.getApps();
          if (apps.length === 0) return { status: "error", message: "Firebase Admin SDK failed to initialize", recommendation: "Check FIREBASE_SERVICE_ACCOUNT JSON is valid and not expired" };
          return { status: "ok", message: `Firebase Admin SDK initialized (${apps.length} app instance)` };
        } catch (e: any) {
          return { status: "error", message: `Firebase error: ${e.message}`, recommendation: "Verify FIREBASE_SERVICE_ACCOUNT credentials are correct" };
        }
      }),
      run("int_stripe", "Stripe API", "Integration", async () => {
        const key = process.env.STRIPE_SECRET_KEY;
        if (!key) return { status: "warn", message: "Stripe not configured", recommendation: "Set STRIPE_SECRET_KEY secret for payment features" };
        const validFormat = key.startsWith("sk_live_") || key.startsWith("sk_test_");
        if (!validFormat) return { status: "error", message: "STRIPE_SECRET_KEY has invalid format (must start with sk_live_ or sk_test_)", recommendation: "Check that STRIPE_SECRET_KEY is a valid Stripe secret key" };
        const mode = key.startsWith("sk_live_") ? "live" : "test";
        return { status: mode === "test" ? "warn" : "ok", message: `Stripe key configured (${mode} mode)`, recommendation: mode === "test" ? "Using test key — switch to a live key for production payments" : undefined };
      }),
      run("int_mailgun", "Mailgun Email", "Integration", async () => {
        if (!process.env.MAILGUN_API_KEY) return { status: "warn", message: "Mailgun not configured", recommendation: "Set MAILGUN_API_KEY secret for email features" };
        if (!process.env.MAILGUN_DOMAIN) return { status: "warn", message: "Mailgun domain not configured", recommendation: "Set MAILGUN_DOMAIN secret" };
        return { status: "ok", message: `Mailgun configured for domain: ${process.env.MAILGUN_DOMAIN}` };
      }),
      run("int_cloudinary", "Cloudinary Media", "Integration", async () => {
        if (!process.env.CLOUDINARY_CLOUD_NAME || !process.env.CLOUDINARY_API_KEY) return { status: "warn", message: "Cloudinary not configured — image uploads will not work", recommendation: "Set CLOUDINARY_CLOUD_NAME, CLOUDINARY_API_KEY, and CLOUDINARY_API_SECRET secrets" };
        return { status: "ok", message: `Cloudinary configured for cloud: ${process.env.CLOUDINARY_CLOUD_NAME}` };
      }),
      run("int_ai", "AI Services (Claude/GPT)", "Integration", async () => {
        const anthropic = !!process.env.ANTHROPIC_API_KEY;
        const openai = !!process.env.OPENAI_API_KEY;
        if (!anthropic && !openai) return { status: "warn", message: "No AI keys configured — AI Assistant and AI features will not work", recommendation: "Set ANTHROPIC_API_KEY or OPENAI_API_KEY in Replit Secrets" };
        const active = [anthropic && "Claude", openai && "OpenAI"].filter(Boolean).join(" + ");
        return { status: "ok", message: `AI services active: ${active}` };
      }),
    ]);

    // ── API Endpoint Smoke Tests ─────────────────────
    const apiTests: { id: string; name: string; path: string; menuName: string; critical: boolean }[] = [
      { id: "api_users", name: "Users API", path: "/api/users", menuName: "Manage → Users", critical: true },
      { id: "api_events", name: "Events API", path: "/api/events", menuName: "Manage → Events", critical: true },
      { id: "api_locations", name: "Spots/Map API", path: "/api/locations", menuName: "Manage → Spots", critical: true },
      { id: "api_posts", name: "Community Posts API", path: "/api/posts", menuName: "Community", critical: true },
      { id: "api_admin_stats", name: "Admin Stats API", path: "/api/admin/stats", menuName: "Dashboard", critical: true },
      { id: "api_admin_analytics", name: "Analytics API", path: "/api/admin/analytics/overview", menuName: "Analytics", critical: false },
      { id: "api_notifications", name: "Notifications API", path: "/api/admin/notifications", menuName: "Operations → Notifications", critical: false },
      { id: "api_content_flags", name: "Content Moderation API", path: "/api/admin/content-flags", menuName: "Manage → Content", critical: false },
      { id: "api_city_spots", name: "City Spots (Map) API", path: "/api/city-spots", menuName: "Nearby Map", critical: false },
      { id: "api_spotlights", name: "Spotlight API", path: "/api/city-spots/spotlights", menuName: "Tools → Spotlight", critical: false },
      { id: "api_marketplace", name: "Marketplace Products API", path: "/api/marketplace/products", menuName: "Marketplace", critical: false },
      { id: "api_services", name: "Services API", path: "/api/services", menuName: "Services / Bookings", critical: false },
      { id: "api_service_bookings", name: "Service Bookings API", path: "/api/service-bookings", menuName: "Manage → Bookings", critical: false },
      { id: "api_performance", name: "Performance Monitor API", path: "/api/admin/performance", menuName: "System → Performance", critical: false },
    ];

    // ── API Endpoint Smoke Tests (all parallel) ───────
    await Promise.all(apiTests.map(test =>
      run(test.id, test.name, "API Endpoint", async () => {
        const t0 = Date.now();
        const resp = await fetch(`http://localhost:${process.env.PORT || 5000}${test.path}`, {
          headers: { "x-internal-health-check": "1", "Cookie": "" },
        });
        const ms = Date.now() - t0;
        if (resp.status === 401 || resp.status === 403) {
          return { status: "ok", message: `Responding (auth required) — ${ms}ms` };
        }
        if (resp.status >= 500) {
          await resp.text().catch(() => "");
          return { status: "error", message: `HTTP ${resp.status} error — check the ${test.menuName} menu`, recommendation: `The ${test.name} is returning server errors. Check server logs for details.` };
        }
        if (ms > 2000) {
          return { status: "warn", message: `Slow response: ${ms}ms (${test.menuName})`, recommendation: `The ${test.name} is slow. Check DB queries and caching for this endpoint.` };
        }
        return { status: "ok", message: `OK — ${ms}ms (${test.menuName})` };
      })
    ));

    const errorCount = checks.filter(c => c.status === "error").length;
    const warnCount = checks.filter(c => c.status === "warn").length;
    const report = { checks, summary: { total: checks.length, errors: errorCount, warnings: warnCount, healthy: checks.filter(c => c.status === "ok").length }, generatedAt: new Date().toISOString() };
    appHealthCache.set("result", report);
    res.json(report);
  });

