  // ── Programme Registrations (public + user booking) ──────────────────────

  // Helper: expand a recurring programme item into occurrences within [from, to]
  function expandProgrammeItem(event: any, from: Date, to: Date): any[] {
    const start = new Date(event.startTime);
    const end = new Date(event.endTime);
    const durationMs = end.getTime() - start.getTime();
    if (!event.isRecurring || !event.recurrenceType) {
      if (start >= from && start <= to) {
        return [{ ...event, occurrenceDate: start.toISOString().slice(0, 10) }];
      }
      return [];
    }
    const recEnd = event.recurrenceEnd ? new Date(event.recurrenceEnd) : to;
    const results: any[] = [];
    let cur = new Date(start);
    // Advance cur to at least `from`
    while (cur < from) {
      if (event.recurrenceType === "daily") cur.setDate(cur.getDate() + 1);
      else if (event.recurrenceType === "weekly") cur.setDate(cur.getDate() + 7);
      else if (event.recurrenceType === "monthly") cur.setMonth(cur.getMonth() + 1);
      else break;
    }
    while (cur <= to && cur <= recEnd) {
      const occDate = cur.toISOString().slice(0, 10);
      const occEnd = new Date(cur.getTime() + durationMs);
      results.push({
        ...event,
        startTime: new Date(cur),
        endTime: occEnd,
        occurrenceDate: occDate,
      });
      if (event.recurrenceType === "daily") cur.setDate(cur.getDate() + 1);
      else if (event.recurrenceType === "weekly") cur.setDate(cur.getDate() + 7);
      else if (event.recurrenceType === "monthly") cur.setMonth(cur.getMonth() + 1);
      else break;
    }
    return results;
  }

  // Public: list upcoming public programme events (across all venues)
  app.get("/api/programme/public", async (req: Request, res: Response) => {
    const { category, from: fromQ, to: toQ } = req.query;
    const from = fromQ ? new Date(fromQ as string) : new Date();
    from.setHours(0, 0, 0, 0);
    const to = toQ ? new Date(toQ as string) : new Date(from.getTime() + 28 * 24 * 60 * 60 * 1000);
    to.setHours(23, 59, 59, 999);

    let conditions: any[] = [
      eq(programmeItems.isPublic, true),
      eq(programmeItems.isActive, true),
    ];
    if (category) conditions.push(eq(programmeItems.category, category as string));

    const events = await db.select({
      id: programmeItems.id,
      userId: programmeItems.userId,
      title: programmeItems.title,
      description: programmeItems.description,
      category: programmeItems.category,
      startTime: programmeItems.startTime,
      endTime: programmeItems.endTime,
      isRecurring: programmeItems.isRecurring,
      recurrenceType: programmeItems.recurrenceType,
      recurrenceEnd: programmeItems.recurrenceEnd,
      isPublic: programmeItems.isPublic,
      capacity: programmeItems.capacity,
      ticketPrice: programmeItems.ticketPrice,
      venueName: programmeAccess.venueName,
      venueType: programmeAccess.venueType,
      organizerName: users.displayName,
      organizerPicture: users.profilePicture,
    }).from(programmeItems)
      .leftJoin(programmeAccess, and(
        eq(programmeItems.userId, programmeAccess.userId),
        eq(programmeAccess.isEnabled, true),
      ))
      .leftJoin(users, eq(programmeItems.userId, users.id))
      .where(and(...conditions));

    // Expand recurring events into occurrences within the date range
    const occurrences: any[] = [];
    for (const ev of events) {
      occurrences.push(...expandProgrammeItem(ev, from, to));
    }
    occurrences.sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

    // Enrich with per-occurrence registration counts
    const itemIds = [...new Set(occurrences.map(e => e.id))];
    const regRows = itemIds.length > 0
      ? await db.select({
          programmeItemId: programmeRegistrations.programmeItemId,
          occurrenceDate: programmeRegistrations.occurrenceDate,
          count: sql<number>`COUNT(*)::int`,
        }).from(programmeRegistrations)
          .where(and(
            inArray(programmeRegistrations.programmeItemId, itemIds),
            ne(programmeRegistrations.status, 'cancelled'),
            ne(programmeRegistrations.status, 'pending_payment'),
          ))
          .groupBy(programmeRegistrations.programmeItemId, programmeRegistrations.occurrenceDate)
      : [];
    const countMap = new Map(regRows.map(r => [`${r.programmeItemId}:${r.occurrenceDate}`, r.count]));

    const enriched = occurrences.map(e => {
      const key = `${e.id}:${e.occurrenceDate}`;
      const regCount = countMap.get(key) || 0;
      return {
        ...e,
        registrationCount: regCount,
        spotsLeft: e.capacity ? Math.max(0, e.capacity - regCount) : null,
        isFree: !e.ticketPrice || parseFloat(e.ticketPrice as string) === 0,
      };
    });
    res.json(enriched);
  });

