  // Warm up slow caches after a 5s delay — gives the DB connection pool time to initialise
  setTimeout(async () => {
    try {
      const realTimeStats = await storage.getRealTimeAdminStats();
      const now = new Date();
      const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
      const sixtyDaysAgo = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);
      const previousRevenue = await storage.getRevenueForPeriod(sixtyDaysAgo, thirtyDaysAgo);
      const currentRevenue = realTimeStats.totalRevenue || 0;
      let revenueChange = 0;
      if (previousRevenue > 0) {
        revenueChange = Math.round(((currentRevenue - previousRevenue) / previousRevenue) * 100);
      } else if (currentRevenue > 0) {
        revenueChange = 100;
      }
      adminStatsCache.set("stats", {
        totalUsers: realTimeStats.totalUsers || 0,
        newUsers: realTimeStats.newUsers || 0,
        activeEvents: realTimeStats.activeEvents || 0,
        pendingEvents: realTimeStats.pendingEvents || 0,
        totalPosts: realTimeStats.totalPosts || 0,
        totalComments: realTimeStats.totalComments || 0,
        totalLikes: realTimeStats.totalLikes || 0,
        totalRsvps: realTimeStats.totalRsvps || 0,
        flaggedContent: realTimeStats.flaggedContent || 0,
        totalRevenue: currentRevenue,
        ticketRevenue: realTimeStats.ticketRevenue || 0,
        serviceRevenue: realTimeStats.serviceRevenue || 0,
        ticketsSold: realTimeStats.ticketsSold || 0,
        revenueChange,
        processingTime: 0,
      });
    } catch (_) {}

    try {
      const campaigns = await storage.getAllMarketingCampaigns();
      campaignsCache.set("all", campaigns);
    } catch (_) {}
  }, 5000);

