  app.patch("/api/admin/ai-training/:id", requireAuth, requireAdmin, async (req, res) => {
    try {
      const id = Number(req.params.id);
      const entry = await storage.updateAiTrainingEntry(id, req.body);
      res.json(entry);
    } catch (e) { res.status(500).json({ error: String(e) }); }
  });

  app.delete("/api/admin/ai-training/:id", requireAuth, requireAdmin, async (req, res) => {
    try {
      await storage.deleteAiTrainingEntry(Number(req.params.id));
      res.json({ ok: true });
    } catch (e) { res.status(500).json({ error: String(e) }); }
  });

  // ══════════════════════════════════════════════════════════════
  //  SECURITY CENTER
  // ══════════════════════════════════════════════════════════════
  {
    const { runSecurityScan, sendSecurityReportEmail } = await import("./securityScanner");
    const { securityReports } = await import("@shared/schema");
    const { randomUUID } = await import("crypto");

    // GET /api/admin/security/reports — list recent reports
    app.get("/api/admin/security/reports", requireAdmin, async (req: Request, res: Response) => {
      try {
        const reports = await db
          .select()
          .from(securityReports)
          .orderBy(desc(securityReports.createdAt))
          .limit(20);
        res.json(reports);
      } catch (err: any) {
        res.status(500).json({ error: err.message });
      }
    });

    // GET /api/admin/security/reports/:scanId — get single report
    app.get("/api/admin/security/reports/:scanId", requireAdmin, async (req: Request, res: Response) => {
      try {
        const [report] = await db
          .select()
          .from(securityReports)
          .where(eq(securityReports.scanId, req.params.scanId))
          .limit(1);
        if (!report) return res.status(404).json({ error: "Report not found" });
        res.json(report);
      } catch (err: any) {
        res.status(500).json({ error: err.message });
      }
    });

    // Helper: get security setting value
    const getSecSetting = async (key: string) => {
      const [row] = await db.select().from(appSettings).where(eq(appSettings.key, key)).limit(1);
      return row?.value ?? null;
    };
    const setSecSetting = async (key: string, value: string) => {
      const existing = await db.select().from(appSettings).where(eq(appSettings.key, key)).limit(1);
      if (existing.length > 0) {
        await db.update(appSettings).set({ value, updatedAt: new Date() }).where(eq(appSettings.key, key));
      } else {
        await db.insert(appSettings).values({ key, value, label: key });
      }
    };

    // GET /api/admin/security/settings — get scan settings
    app.get("/api/admin/security/settings", requireAdmin, async (req: Request, res: Response) => {
      try {
        const [enabled, freq, email, lastScan] = await Promise.all([
          getSecSetting("security_scan_enabled"),
          getSecSetting("security_scan_frequency"),
          getSecSetting("security_notify_email"),
          getSecSetting("security_last_scan"),
        ]);
        res.json({
          scanEnabled: enabled === "true",
          scanFrequency: freq || "weekly",
          notifyEmail: email || "",
          lastScan,
        });
      } catch (err: any) {
        res.status(500).json({ error: err.message });
      }
    });

    // POST /api/admin/security/settings — save settings
    app.post("/api/admin/security/settings", requireAdmin, async (req: Request, res: Response) => {
      try {
        const schema = z.object({
          scanEnabled: z.boolean().optional(),
          scanFrequency: z.enum(["weekly", "monthly"]).optional(),
          notifyEmail: z.string().email().or(z.literal("")).optional(),
        });
        const { scanEnabled, scanFrequency, notifyEmail } = schema.parse(req.body);
        if (typeof scanEnabled === "boolean") {
          await setSecSetting("security_scan_enabled", String(scanEnabled));
        }
        if (scanFrequency) await setSecSetting("security_scan_frequency", scanFrequency);
        if (typeof notifyEmail === "string") {
          await setSecSetting("security_notify_email", notifyEmail);
        }
        res.json({ success: true });
      } catch (err: any) {
        if (err?.issues) {
          return res.status(400).json({ error: "Invalid settings", details: err.issues });
        }
        res.status(500).json({ error: err.message });
      }
    });

    // DELETE /api/admin/security/reports/:scanId — delete an old report
    app.delete("/api/admin/security/reports/:scanId", requireAdmin, async (req: Request, res: Response) => {
      try {
        const result = await db.delete(securityReports)
          .where(eq(securityReports.scanId, req.params.scanId))
          .returning({ id: securityReports.id });
        if (result.length === 0) return res.status(404).json({ error: "Report not found" });
        res.json({ success: true });
      } catch (err: any) {
        res.status(500).json({ error: err.message });
      }
    });

    // POST /api/admin/security/reports/:scanId/resend-email — resend a completed report
    app.post("/api/admin/security/reports/:scanId/resend-email", requireAdmin, async (req: Request, res: Response) => {
      try {
        const [row] = await db.select().from(securityReports)
          .where(eq(securityReports.scanId, req.params.scanId))
          .limit(1);
        if (!row) return res.status(404).json({ error: "Report not found" });
        if (row.status !== "complete" || row.overallScore == null) {
          return res.status(400).json({ error: "Only completed reports can be emailed" });
        }
        const requester = (req as any).user;
        const targetEmail =
          (typeof req.body?.email === "string" && req.body.email) ||
          (await getSecSetting("security_notify_email")) ||
          requester?.email ||
          null;
        if (!targetEmail) {
          return res.status(400).json({ error: "No notify email configured. Save one in Settings or pass { email } in body." });
        }
        const fullReport = {
          overallScore: row.overallScore,
          grade: row.grade || "",
          summary: row.summary || "",
          sections: (row.sections as any) || [],
          criticalCount: row.criticalCount || 0,
          highCount: row.highCount || 0,
          mediumCount: row.mediumCount || 0,
          lowCount: row.lowCount || 0,
        };
        await sendSecurityReportEmail(fullReport as any, row.scanId, targetEmail);
        await db.update(securityReports).set({ emailSent: true }).where(eq(securityReports.scanId, row.scanId));
        res.json({ success: true, email: targetEmail });
      } catch (err: any) {
        console.error("[SecurityScan] Resend email failed:", err);
        res.status(500).json({ error: err.message });
      }
    });

    // POST /api/admin/security/scan — trigger scan immediately
    app.post("/api/admin/security/scan", requireAdmin, async (req: Request, res: Response) => {
      try {
        const creator = (req as any).user;
        const scanId = randomUUID();
        const sendEmail = req.body?.sendEmail !== false;

        // Create pending record
        await db.insert(securityReports).values({
          scanId,
          status: "pending",
          triggeredBy: "manual",
          triggeredByUserId: creator?.id || null,
        });

        // Return scanId immediately — client polls for completion
        res.json({ scanId, status: "pending" });

        // Run scan in background
        (async () => {
          try {
            const report = await runSecurityScan(scanId, "manual", creator?.id);

            if (sendEmail) {
              // Prefer the saved admin notify email; fall back to the admin
              // who triggered this scan; otherwise skip emailing rather than
              // silently sending to a hardcoded address.
              const notifyEmail =
                (await getSecSetting("security_notify_email")) ||
                creator?.email ||
                null;
              if (notifyEmail) {
                try {
                  await sendSecurityReportEmail(report, scanId, notifyEmail);
                  await db.update(securityReports).set({ emailSent: true }).where(eq(securityReports.scanId, scanId));
                } catch (emailErr) {
                  console.error("[SecurityScan] Email failed:", emailErr);
                }
              } else {
                console.warn("[SecurityScan] No notify email configured — skipping email.");
              }
            }

            await setSecSetting("security_last_scan", new Date().toISOString());
          } catch (err: any) {
            console.error("[SecurityScan] Scan failed:", err);
            // Persist the actual error reason in `summary` so the UI can show
            // it instead of forcing the admin to dig through server logs.
            const reason = (err?.message || String(err)).slice(0, 500);
            await db.update(securityReports).set({
              status: "failed",
              summary: `Scan failed: ${reason}`,
              completedAt: new Date(),
            }).where(eq(securityReports.scanId, scanId));
          }
        })();
      } catch (err: any) {
        res.status(500).json({ error: err.message });
      }
    });

    // Weekly security scan scheduler
    (async () => {
      const CHECK_INTERVAL = 60 * 60 * 1000; // check every hour
      setInterval(async () => {
        try {
          const enabled = await getSecSetting("security_scan_enabled");
          if (enabled !== "true") return;

          const lastScan = await getSecSetting("security_last_scan");
          if (lastScan) {
            const elapsed = Date.now() - new Date(lastScan).getTime();
            const freq = await getSecSetting("security_scan_frequency") || "weekly";
            const threshold = freq === "monthly" ? 30 * 24 * 60 * 60 * 1000 : 7 * 24 * 60 * 60 * 1000;
            if (elapsed < threshold) return;
          }

          console.log("[SecurityScan] Starting scheduled scan...");
          const { randomUUID: uuid2 } = await import("crypto");
          const scanId = uuid2();

          await db.insert(securityReports).values({
            scanId,
            status: "pending",
            triggeredBy: "scheduled",
          });

          const report = await runSecurityScan(scanId, "scheduled");
          const notifyEmail = await getSecSetting("security_notify_email");
          if (notifyEmail) {
            try {
              await sendSecurityReportEmail(report, scanId, notifyEmail);
              await db.update(securityReports).set({ emailSent: true }).where(eq(securityReports.scanId, scanId));
            } catch (emailErr) {
              console.error("[SecurityScan] Scheduled email failed:", emailErr);
            }
          } else {
            console.warn("[SecurityScan] Scheduled scan complete but no notify email configured.");
          }
          await setSecSetting("security_last_scan", new Date().toISOString());
          console.log("[SecurityScan] Scheduled scan complete. Score:", report.overallScore);
        } catch (err) {
          console.error("[SecurityScan] Scheduler error:", err);
        }
      }, CHECK_INTERVAL);
    })();
  }

