  // ══════════════════════════════════════════════════════════════════════
  // SPOT OWNERSHIP / CLAIMING SYSTEM (Edmond)
  // ══════════════════════════════════════════════════════════════════════

  // GET /api/spot-claims — admin: all claims
  app.get("/api/spot-claims", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { status } = req.query;
      const baseQuery = db.select({
        claim: spotClaims,
        claimantName: users.displayName,
        claimantEmail: users.email,
        claimantAvatar: users.profilePicture,
      })
        .from(spotClaims)
        .leftJoin(users, eq(spotClaims.claimantId, users.id));

      const rows = status && status !== "all"
        ? await baseQuery.where(eq(spotClaims.status, status as string)).orderBy(desc(spotClaims.claimedAt))
        : await baseQuery.orderBy(desc(spotClaims.claimedAt));
      return res.json(rows);
    } catch (err) {
      console.error("spot-claims GET error:", err);
      return res.status(500).json({ message: "Failed to fetch claims" });
    }
  });

  // GET /api/spot-claims/my — auth user: their own claims
  app.get("/api/spot-claims/my", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      const rows = await db.select().from(spotClaims)
        .where(eq(spotClaims.claimantId, userId))
        .orderBy(desc(spotClaims.claimedAt));
      return res.json(rows);
    } catch (err) {
      return res.status(500).json({ message: "Failed to fetch your claims" });
    }
  });

  // POST /api/spot-claims — user submits a claim
  app.post("/api/spot-claims", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = (req as any).user?.id;
      const { spotRef, spotName, spotCategory, spotAddress, businessName, businessEmail, businessPhone, role, verificationNote, websiteUrl, kvkNumber } = req.body;
      if (!spotRef || !spotName) return res.status(400).json({ message: "spotRef and spotName required" });

      // Check for existing pending/approved claim by this user for this spot
      const existing = await db.select().from(spotClaims)
        .where(and(eq(spotClaims.spotRef, spotRef), eq(spotClaims.claimantId, userId), eq(spotClaims.status, "pending")))
        .limit(1);
      if (existing.length > 0) return res.status(400).json({ message: "You already have a pending claim for this spot" });

      // Check if already owned
      const owned = await db.select().from(spotOwnerships)
        .where(and(eq(spotOwnerships.spotRef, spotRef), eq(spotOwnerships.isActive, true)))
        .limit(1);
      if (owned.length > 0 && owned[0].ownerId !== userId) {
        return res.status(400).json({ message: "This spot already has an active owner" });
      }

      const [claim] = await db.insert(spotClaims).values({
        spotRef, spotName, spotCategory: spotCategory || null, spotAddress: spotAddress || null,
        claimantId: userId, businessName: businessName || null, businessEmail: businessEmail || null,
        businessPhone: businessPhone || null, role: role || "owner",
        verificationNote: verificationNote || null, websiteUrl: websiteUrl || null,
        kvkNumber: kvkNumber || null, status: "pending",
      }).returning();
      return res.json(claim);
    } catch (err) {
      console.error("spot-claims POST error:", err);
      return res.status(500).json({ message: "Failed to submit claim" });
    }
  });

  // POST /api/spot-claims/ai-assist — Claude helps generate claim summary / verify
  app.post("/api/spot-claims/ai-assist", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { claimId, action } = req.body; // action: "summarize" | "verify" | "draft_response"
      const [claimRow] = await db.select({
        claim: spotClaims,
        claimantName: users.displayName,
        claimantEmail: users.email,
      }).from(spotClaims).leftJoin(users, eq(spotClaims.claimantId, users.id)).where(eq(spotClaims.id, claimId)).limit(1);

      if (!claimRow) return res.status(404).json({ message: "Claim not found" });
      const { claim, claimantName, claimantEmail } = claimRow;

      const systemPrompt = `You are Edmond, the AI assistant for the Urban Culture Hub Netherlands admin system. 
You help admins review and process spot ownership claims for the 32,000+ urban culture spots in the Netherlands.
Be concise, professional, and practical. Respond in Dutch or English based on context.`;

      const userMsg = action === "verify"
        ? `Please analyze this spot ownership claim and provide a brief verification assessment:
Spot: ${claim.spotName} (${claim.spotRef})
Address: ${claim.spotAddress || "Unknown"}
Category: ${claim.spotCategory || "Unknown"}
Claimant: ${claimantName} (${claimantEmail})
Business: ${claim.businessName || "Not provided"}
Role: ${claim.role}
KvK: ${claim.kvkNumber || "Not provided"}
Website: ${claim.websiteUrl || "Not provided"}
Verification note: ${claim.verificationNote || "None"}

Assess: 1) Legitimacy (is this claim plausible?), 2) Missing info, 3) Recommendation (approve/reject/request more info). Keep it under 150 words.`
        : action === "draft_response"
        ? `Draft a polite email response to this spot claim (approve or request more info based on the data):
Claimant: ${claimantName}, Spot: ${claim.spotName}, Status intent: ${req.body.intent || "approve"}`
        : `Summarize this spot claim in 2-3 sentences for quick admin review:
${JSON.stringify(claim, null, 2)}`;

      const { default: Anthropic } = await import("@anthropic-ai/sdk");
      const anthropic = new Anthropic();
      const msg = await anthropic.messages.create({
        model: "claude-opus-4-5",
        max_tokens: 400,
        system: systemPrompt,
        messages: [{ role: "user", content: userMsg }],
      });
      const aiText = (msg.content[0] as any).text || "";

      // Save AI summary back to claim
      if (action === "summarize" || action === "verify") {
        await db.update(spotClaims).set({ aiSummary: aiText }).where(eq(spotClaims.id, claimId));
      }
      return res.json({ result: aiText });
    } catch (err) {
      console.error("spot-claims AI assist error:", err);
      return res.status(500).json({ message: "AI assist failed" });
    }
  });

  // POST /api/spot-claims/ai-chat — Edmond AI chat for admin spot assignment
  app.post("/api/spot-claims/ai-chat", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { message, context } = req.body;
      const { default: Anthropic } = await import("@anthropic-ai/sdk");
      const anthropic = new Anthropic();

      // Get pending claims count for context
      const [{ count: pendingCount }] = await db.select({ count: sql<number>`count(*)` })
        .from(spotClaims).where(eq(spotClaims.status, "pending"));

      const systemPrompt = `You are Edmond, the intelligent admin assistant for the Urban Culture Hub Netherlands.
You help the admin manage 32,000+ urban culture spots — skate parks, graffiti walls, cafés, restaurants, dance studios, and more across the Netherlands.
Your role is to help assign spots to owners, review claims, and make the process smooth.
Current stats: ${pendingCount} pending claims awaiting review.
Context: ${context || "Admin spot management panel"}
Be helpful, concise, and proactive. Respond in English. If asked to approve/reject/assign, explain what action to take.`;

      const msg = await anthropic.messages.create({
        model: "claude-opus-4-5",
        max_tokens: 600,
        system: systemPrompt,
        messages: [{ role: "user", content: message }],
      });
      return res.json({ reply: (msg.content[0] as any).text || "" });
    } catch (err) {
      console.error("edmond AI chat error:", err);
      return res.status(500).json({ message: "Edmond is unavailable" });
    }
  });

  // PATCH /api/spot-claims/:id/approve — admin approves claim, creates ownership
  app.patch("/api/spot-claims/:id/approve", requireAdmin, async (req: Request, res: Response) => {
    try {
      const id = parseInt(req.params.id);
      const adminId = (req as any).user?.id;
      const { adminNote, permissions } = req.body;

      const [claim] = await db.select().from(spotClaims).where(eq(spotClaims.id, id)).limit(1);
      if (!claim) return res.status(404).json({ message: "Claim not found" });

      // Update claim status
      await db.update(spotClaims).set({
        status: "approved", adminNote: adminNote || null,
        reviewedBy: adminId, reviewedAt: new Date(),
      }).where(eq(spotClaims.id, id));

      // Create or update ownership
      const existing = await db.select().from(spotOwnerships)
        .where(and(eq(spotOwnerships.spotRef, claim.spotRef), eq(spotOwnerships.ownerId, claim.claimantId)))
        .limit(1);
      if (existing.length === 0) {
        await db.insert(spotOwnerships).values({
          spotRef: claim.spotRef, spotName: claim.spotName,
          spotCategory: claim.spotCategory || null, spotAddress: claim.spotAddress || null,
          ownerId: claim.claimantId, claimId: id,
          businessName: claim.businessName || null, role: claim.role || "owner",
          permissions: permissions || ["schedule", "info", "photos"],
          grantedBy: adminId, isActive: true,
        });
      } else {
        await db.update(spotOwnerships).set({ isActive: true, grantedBy: adminId }).where(eq(spotOwnerships.id, existing[0].id));
      }
      return res.json({ success: true });
    } catch (err) {
      console.error("approve claim error:", err);
      return res.status(500).json({ message: "Failed to approve claim" });
    }
  });

