      await db.insert(appSettings)
        .values({ key: HOMEPAGE_CONFIG_KEY, value, label: "Homepage Builder Config", description: "Drag-and-drop homepage section config", updatedBy: (req.session as any)?.userId || null })
        .onConflictDoUpdate({ target: appSettings.key, set: { value, updatedAt: new Date(), updatedBy: (req.session as any)?.userId || null } });
      return res.json({ success: true, config });
