  app.post("/api/admin/homepage-builder/ai", requireAdmin, async (req: Request, res: Response) => {
    const { message, context } = req.body;
    if (!message) return res.status(400).json({ message: "No message provided" });
    try {
      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const client = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY || "",
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL || undefined,
      });

      const currentContent = context?.currentContent || {};
      const contentSnapshot = JSON.stringify({
        hero: currentContent.hero || {},
        about: currentContent.about || {},
        stats: currentContent.stats || [],
        founder: currentContent.founder || {},
        contact: currentContent.contact || {},
      }, null, 2);

      const systemPrompt = `You are an AI live-editor for Urban Culture Hub — a Dutch urban culture platform for breaking, graffiti, hip-hop, and skateboarding. You help the admin edit the homepage DIRECTLY, applying real changes instantly.

CURRENT HOMEPAGE CONTENT:
${contentSnapshot}

ACTIVE TEMPLATE: ${context?.currentTemplate || "standard"}
VISIBLE SECTIONS: ${(context?.visibleSections || []).join(", ")}
HERO TAGLINE: "${context?.heroTagline || "not set"}"

== YOUR JOB ==
When the admin gives an instruction, APPLY the change directly. You must respond with a JSON block containing both a reply and a configPatch.

EDITABLE FIELDS:
- hero: badge, tagline, ctaPrimary, ctaSecondary
- about: title, subtitle, description
- stats: array of {value, label} (4 items)
- founder: name, role, quote, email
- contact: title, desc, email

RESPONSE FORMAT — always output exactly this structure:
<reply>Your friendly 1-sentence explanation of what you changed</reply>
<configPatch>{"content": {"hero": {"tagline": "new text here"}}}</configPatch>

RULES:
- If asked to change text → produce a configPatch with the new text
- If asked a question or for advice only → still include <configPatch>{}</configPatch> (empty)  
- Keep reply to 1-2 sentences max, friendly and direct
- For the patch: only include the fields you're changing, nested under "content"
- Write copy that reflects Dutch urban culture: raw, authentic, community-driven
- Stats values: keep them short (e.g. "12K+", "🇳🇱", "Gratis", "Live")
- Be bold and confident with copy suggestions`;

      const response = await client.messages.create({
        model: "claude-opus-4-5",
        max_tokens: 600,
        system: systemPrompt,
        messages: [{ role: "user", content: message }],
      });

      const raw = (response.content[0] as any).text || "";

      // Extract reply and configPatch from structured response
      const replyMatch = raw.match(/<reply>([\s\S]*?)<\/reply>/);
      const patchMatch = raw.match(/<configPatch>([\s\S]*?)<\/configPatch>/);

      const reply = replyMatch ? replyMatch[1].trim() : raw.slice(0, 200);
      let configPatch: any = null;
      if (patchMatch) {
        try {
          const parsed = JSON.parse(patchMatch[1].trim());
          // Only return patch if it has actual content changes
          if (parsed && typeof parsed === "object" && Object.keys(parsed).length > 0) {
            const hasChanges = parsed.content && Object.values(parsed.content).some(
              v => v && typeof v === "object" && Object.keys(v as object).length > 0
            );
            if (hasChanges) configPatch = parsed;
          }
        } catch {}
      }

      return res.json({ reply, configPatch });
    } catch (err) {
      console.error("homepage builder AI error:", err);
      return res.status(500).json({ message: "AI request failed" });
    }
  });

