  // GET /api/groups — list active groups (optionally filter by type/discipline/city)
  app.get("/api/groups", async (req: Request, res: Response) => {
    try {
      const { type, discipline, city, search, limit: lim, offset: off } = req.query as Record<string, string>;
      const limitNum = Math.min(parseInt(lim || "50"), 100);
      const offsetNum = parseInt(off || "0");
      const result = await db.execute(sql`
        SELECT g.id, g.name, g.description, g.cover_image, g.type, g.city, g.discipline,
               g.tags, g.is_private, g.status, g.created_by, g.member_count, g.post_count,
               g.created_at, g.updated_at,
               u.display_name as creator_username, u.profile_picture as creator_profile_picture
        FROM groups g
        LEFT JOIN users u ON g.created_by = u.id
        WHERE g.status = 'active'
          AND (${!type} OR g.type = ${type || ''})
          AND (${!discipline} OR g.discipline = ${discipline || ''})
          AND (${!city} OR g.city ILIKE ${'%' + (city || '') + '%'})
          AND (${!search} OR g.name ILIKE ${'%' + (search || '') + '%'} OR g.description ILIKE ${'%' + (search || '') + '%'})
        ORDER BY g.created_at DESC
        LIMIT ${limitNum} OFFSET ${offsetNum}
      `);
      const rows = (result as any).rows ?? result;
      // camelCase the rows
      const mapped = rows.map((r: any) => ({
        id: r.id, name: r.name, description: r.description, coverImage: r.cover_image,
        type: r.type, city: r.city, discipline: r.discipline, tags: r.tags,
        isPrivate: r.is_private, status: r.status, createdBy: r.created_by,
        memberCount: r.member_count, postCount: r.post_count,
        createdAt: r.created_at, updatedAt: r.updated_at,
        creatorUsername: r.creator_username, creatorProfilePicture: r.creator_profile_picture,
      }));
      res.json(mapped);
    } catch (err: any) { console.error("[/api/groups] error:", err.stack || err.message); res.status(500).json({ message: err.message }); }
  });

