  // POST /api/groups — create group (any logged-in user; starts as pending)
  app.post("/api/groups", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const { groups, groupMembers } = await import("../shared/schema");
      const user = (req as any).user;
      const { name, description, type, city, discipline, tags, isPrivate, coverImage } = req.body;
      if (!name?.trim()) return res.status(400).json({ message: "Name required" });
      const [created] = await db.insert(groups).values({
        name: name.trim(), description: description || null, type: type || "topic",
        city: city || null, discipline: discipline || null, tags: tags || null,
        isPrivate: !!isPrivate, status: "pending", createdBy: user.id, coverImage: coverImage || null,
      }).returning();
      // auto-add creator as admin member (approved)
      await db.insert(groupMembers).values({ groupId: created.id, userId: user.id, role: "admin", status: "approved" });
      await db.update(groups).set({ memberCount: 1 }).where((await import("drizzle-orm")).eq(groups.id, created.id));
      res.status(201).json(created);
    } catch (err: any) { res.status(500).json({ message: err.message }); }
  });

  // PATCH /api/groups/:id — update group (creator or admin)
  app.patch("/api/groups/:id", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const { groups } = await import("../shared/schema");
      const { eq } = await import("drizzle-orm");
      const user = (req as any).user;
      const isAdmin = ["admin", "super_admin"].includes(user.role);
      const id = parseInt(req.params.id);
      const [existing] = await db.select().from(groups).where(eq(groups.id, id)).limit(1);
      if (!existing) return res.status(404).json({ message: "Not found" });
      if (!isAdmin && existing.createdBy !== user.id) return res.status(403).json({ message: "Forbidden" });
      const { name, description, type, city, discipline, tags, isPrivate, coverImage, status } = req.body;
      const updates: any = { updatedAt: new Date() };
      if (name !== undefined) updates.name = name;
      if (description !== undefined) updates.description = description;
      if (type !== undefined) updates.type = type;
      if (city !== undefined) updates.city = city;
      if (discipline !== undefined) updates.discipline = discipline;
      if (tags !== undefined) updates.tags = tags;
      if (isPrivate !== undefined) updates.isPrivate = isPrivate;
      if (coverImage !== undefined) updates.coverImage = coverImage;
      if (isAdmin && status !== undefined) updates.status = status;
      const [updated] = await db.update(groups).set(updates).where(eq(groups.id, id)).returning();
      res.json(updated);
    } catch (err: any) { res.status(500).json({ message: err.message }); }
  });

