  // POST /api/groups/:id/join — join (or request to join if private)
  app.post("/api/groups/:id/join", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const { groups, groupMembers } = await import("../shared/schema");
      const { eq, and } = await import("drizzle-orm");
      const user = (req as any).user;
      const id = parseInt(req.params.id);
      const [group] = await db.select().from(groups).where(eq(groups.id, id)).limit(1);
      if (!group) return res.status(404).json({ message: "Group not found" });
      if (group.status !== "active") return res.status(400).json({ message: "Group not active" });
      const existing = await db.select().from(groupMembers).where(and(eq(groupMembers.groupId, id), eq(groupMembers.userId, user.id))).limit(1);
      if (existing.length) return res.status(409).json({ message: "Already a member or pending" });
      const status = group.isPrivate ? "pending" : "approved";
      await db.insert(groupMembers).values({ groupId: id, userId: user.id, role: "member", status });
      if (!group.isPrivate) {
        await db.update(groups).set({ memberCount: (group.memberCount || 0) + 1, updatedAt: new Date() }).where(eq(groups.id, id));
      }
      res.json({ status, message: group.isPrivate ? "Join request sent" : "Joined successfully" });
    } catch (err: any) { res.status(500).json({ message: err.message }); }
  });

