  // ── TikTok OAuth ─────────────────────────────────────────────────────────────
  // Step 1: Redirect to TikTok authorization page
  app.get("/api/tiktok/auth", (req: Request, res: Response) => {
    const clientKey = process.env.TIKTOK_CLIENT_KEY;
    if (!clientKey) {
      return res.status(500).json({ message: "TIKTOK_CLIENT_KEY not configured" });
    }
    const redirectUri = process.env.TIKTOK_REDIRECT_URI ||
      `https://${req.headers.host}/api/tiktok/callback`;
    const state = Math.random().toString(36).slice(2) + Date.now().toString(36);
    const scopes = [
      "user.info.basic",
      "user.info.stats",
      "video.list",
      "video.publish",
      "share.sound.single",
    ].join(",");
    const authUrl = new URL("https://www.tiktok.com/v2/auth/authorize");
    authUrl.searchParams.set("client_key", clientKey);
    authUrl.searchParams.set("scope", scopes);
    authUrl.searchParams.set("response_type", "code");
    authUrl.searchParams.set("redirect_uri", redirectUri);
    authUrl.searchParams.set("state", state);
    res.redirect(authUrl.toString());
  });

  // Step 2: TikTok redirects here with ?code=...&state=...
  app.get("/api/tiktok/callback", async (req: Request, res: Response) => {
    const { code, error, error_description } = req.query as Record<string, string>;
    if (error) {
      console.error("[TikTok OAuth] Error:", error, error_description);
      return res.redirect(`/admin/tiktok?error=${encodeURIComponent(error_description || error)}`);
    }
    if (!code) {
      return res.redirect("/admin/tiktok?error=no_code");
    }
    try {
      const clientKey = process.env.TIKTOK_CLIENT_KEY;
      const clientSecret = process.env.TIKTOK_CLIENT_SECRET;
      if (!clientKey || !clientSecret) {
        return res.redirect("/admin/tiktok?error=missing_credentials");
      }
      const redirectUri = process.env.TIKTOK_REDIRECT_URI ||
        `https://${req.headers.host}/api/tiktok/callback`;
      const tokenRes = await fetch("https://open.tiktokapis.com/v2/oauth/token/", {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: new URLSearchParams({
          client_key: clientKey,
          client_secret: clientSecret,
          code,
          grant_type: "authorization_code",
          redirect_uri: redirectUri,
        }),
      });
      const tokenData = await tokenRes.json() as any;
      if (tokenData.error) {
        console.error("[TikTok OAuth] Token exchange error:", tokenData);
        return res.redirect(`/admin/tiktok?error=${encodeURIComponent(tokenData.error_description || tokenData.error)}`);
      }
      // Store tokens in cookie (admin-only, short-lived in production)
      res.cookie("tiktok_access_token", tokenData.access_token, {
        httpOnly: true,
        secure: true,
        sameSite: "lax",
        maxAge: tokenData.expires_in * 1000,
      });
      res.cookie("tiktok_open_id", tokenData.open_id, {
        httpOnly: true,
        secure: true,
        sameSite: "lax",
        maxAge: tokenData.expires_in * 1000,
      });
      console.log("[TikTok OAuth] Connected. open_id:", tokenData.open_id);
      res.redirect("/admin/tiktok?connected=true");
    } catch (err: any) {
      console.error("[TikTok OAuth] Callback error:", err.message);
      res.redirect(`/admin/tiktok?error=${encodeURIComponent(err.message)}`);
    }
  });

  // GET /api/tiktok/status — check if TikTok is connected (cookie-based)
  app.get("/api/tiktok/status", (req: Request, res: Response) => {
    const token = req.cookies?.tiktok_access_token;
    const openId = req.cookies?.tiktok_open_id;
    res.json({ connected: !!token, openId: openId || null });
  });

  // DELETE /api/tiktok/disconnect — clear TikTok cookies
  app.delete("/api/tiktok/disconnect", (_req: Request, res: Response) => {
    res.clearCookie("tiktok_access_token");
    res.clearCookie("tiktok_open_id");
    res.json({ success: true });
  });
  // ── End TikTok OAuth ──────────────────────────────────────────────────────────

