  app.get("/api/admin/gemeente", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { db } = await import("./db");
      const { gemeenteOutreach } = await import("../shared/schema");
      const { desc, eq, like, or, and } = await import("drizzle-orm");
      const { status, province, priority, search } = req.query as Record<string, string>;

      let query = db.select().from(gemeenteOutreach).$dynamic();
      const conditions: any[] = [];
      if (status) conditions.push(eq(gemeenteOutreach.outreachStatus, status));
      if (province) conditions.push(eq(gemeenteOutreach.province, province));
      if (priority) conditions.push(eq(gemeenteOutreach.priority, priority));
      if (search) {
        conditions.push(or(
          like(gemeenteOutreach.municipalityName, `%${search}%`),
          like(gemeenteOutreach.city, `%${search}%`),
          like(gemeenteOutreach.contactName, `%${search}%`),
          like(gemeenteOutreach.department, `%${search}%`),
        ));
      }
      if (conditions.length) query = query.where(and(...conditions));
      const results = await query.orderBy(desc(gemeenteOutreach.createdAt));
      res.json(results);
    } catch (err: any) {
      res.status(500).json({ message: "Failed to fetch gemeente outreach", error: err.message });
    }
  });

