  // ── AI Score gemeente records ─────────────────────────────────────────────
  app.post("/api/admin/gemeente/:id/ai-score", requireAdmin, async (req: Request, res: Response) => {
    try {
      const { db } = await import("./db");
      const { gemeenteOutreach } = await import("../shared/schema");
      const { eq } = await import("drizzle-orm");
      const id = parseInt(req.params.id);
      const [record] = await db.select().from(gemeenteOutreach).where(eq(gemeenteOutreach.id, id));
      if (!record) return res.status(404).json({ message: "Not found" });

      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const anthropic = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY || "",
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL || undefined,
      });
      const prompt = `Analyseer deze gemeente outreach lead voor Urban Culture Hub en geef een score (0-100) en advies.

Gemeente: ${record.municipalityName}
Afdeling: ${record.department || "onbekend"}
Stad: ${record.city || "onbekend"}
Provincie: ${record.province || "onbekend"}
Doel: ${record.outreachGoal || "partnerschap"}
Status: ${record.outreachStatus}
Heeft urban culture budget: ${record.hasUrbanCultureBudget ? "ja" : "nee/onbekend"}
Notities: ${record.internalNotes || "geen"}

Geef terug als JSON:
{
  "score": 0-100,
  "summary": "korte samenvatting in 2 zinnen",
  "suggestedApproach": "concreet advies in 2-3 zinnen"
}`;
      const msg = await anthropic.messages.create({
        model: "claude-haiku-4-5",
        max_tokens: 500,
        messages: [{ role: "user", content: prompt }],
      });
      const text = msg.content[0].type === "text" ? msg.content[0].text : "{}";
      let parsed: any = {};
      try { parsed = JSON.parse(text.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim()); } catch {}
      const [updated] = await db.update(gemeenteOutreach)
        .set({
          aiScore: parsed.score || null,
          aiSummary: parsed.summary || null,
          aiSuggestedApproach: parsed.suggestedApproach || null,
          updatedAt: new Date(),
        })
        .where(eq(gemeenteOutreach.id, id))
        .returning();
      res.json(updated);
    } catch (err: any) {
      res.status(500).json({ message: "AI scoring failed", error: err.message });
    }
  });

