  // ── Studio AI Smart Editor — Claude-powered timeline analysis & auto-edit ──
  app.post("/api/studio/ai-smart-edit", authenticateJWT, async (req: Request, res: Response) => {
    try {
      const Anthropic = (await import("@anthropic-ai/sdk")).default;
      const anthropic = new Anthropic({
        apiKey: process.env.AI_INTEGRATIONS_ANTHROPIC_API_KEY || process.env.ANTHROPIC_API_KEY || "",
        baseURL: process.env.AI_INTEGRATIONS_ANTHROPIC_BASE_URL || undefined,
      });

      const { clips, textLayers, totalDuration, platform, aspectRatio, transition, transcript, userContext, userGoal } = req.body;

      const clipsSummary = (clips || []).map((c: any) =>
        `- Clip ${c.index + 1}: "${c.filename || "video"}" | abs trim: ${c.currentAbsTrimStart?.toFixed(2)}s–${c.currentAbsTrimEnd?.toFixed(2)}s | effective: ${c.effectiveDuration?.toFixed(1)}s`
      ).join("\n") || "- No clips loaded";

      const textSummary = (textLayers || []).length > 0
        ? (textLayers || []).map((l: any) => `- "${l.text}" | ${l.position} | ${l.startTime?.toFixed(1)}s–${l.endTime?.toFixed(1)}s`).join("\n")
        : "No text layers";

      const systemPrompt = `You are an elite video editor and content strategist specializing in viral short-form social media content (TikTok, Instagram Reels, YouTube Shorts). You work with urban culture creators — breakdancers, graffiti artists, DJs, skaters, BMX riders, street performers.

Your job: analyze the creator's timeline and return precise, actionable edit decisions that maximize hook strength, pacing, and audience retention. Be brutally specific — name exact timestamps, identify exact speech problems, give exact cut points.

IMPORTANT: Return ONLY valid JSON. No markdown, no text outside the JSON object.`;

      const userPrompt = `Analyze this video timeline and deliver expert edit decisions:

**TIMELINE:**
Total duration: ${(totalDuration || 0).toFixed(1)}s
Platform: ${platform || "tiktok"} | Aspect: ${aspectRatio || "9:16"}
Current transition: ${transition || "cut"}

**CLIPS (absolute timestamps in the source file):**
${clipsSummary}

**TEXT OVERLAYS:**
${textSummary}

**CREATOR CONTEXT:** ${userContext || "Urban culture creator"}
**SPEECH TRANSCRIPT:** ${transcript || "No transcript — analyze structure and pacing only"}
**GOAL:** ${userGoal || "Viral hook, cut dead air, tight pacing, under 30s if possible"}

**YOUR ANALYSIS MUST:**
1. Flag every wasted second: slow intros, dead air (>0.4s silence), outro drag
2. Detect speech issues in the transcript: stutters (word repeated), fillers (um/uh/like/so/you know), repetitions (same point twice), long pauses
3. Score the hook (first 3 seconds) — it must be visually/verbally arresting
4. Check pacing — energy must stay elevated throughout
5. Return ABSOLUTE timestamps (matching the source file's trimStart/trimEnd numbers) for all trim suggestions
6. If transcript reveals a stutter/filler, calculate approx timestamp and suggest trim to remove it
7. Suggest 1-3 text overlays that boost hook or retention

Return EXACTLY this JSON structure:
{
  "summary": "2-3 sentence brutal honest assessment",
  "hookScore": 0-100,
  "hookIssue": "exact problem or null",
  "paceScore": 0-100,
  "overallReadiness": 0-100,
  "readinessIssues": ["issue1", "issue2"],
  "transitionRecommendation": "cut|fade|zoom|slide|wipe",
  "clipAnalysis": [
    {
      "clipIndex": 0,
      "action": "keep|trim|cut",
      "newTrimStart": 1.5,
      "newTrimEnd": 9.0,
      "reason": "Dead air first 1.5s removed; cut last 1s weak outro",
      "issue": "slow_start|stutter|repetition|filler|too_long|off_topic|weak_energy|none",
      "confidence": 85
    }
  ],
  "globalSuggestions": ["tip 1", "tip 2", "tip 3"],
  "textSuggestions": [
    {
      "action": "add|remove",
      "layerId": null,
      "text": "HOOK TEXT HERE",
      "startTime": 0,
      "endTime": 3,
      "position": "top|center|bottom",
      "reason": "why"
    }
  ]
}`;

      const response = await anthropic.messages.create({
        model: "claude-sonnet-4-6",
        max_tokens: 2500,
        system: systemPrompt,
        messages: [{ role: "user", content: userPrompt }],
      });

      const raw = response.content[0].type === "text" ? response.content[0].text.trim() : "{}";
      // Strip any accidental markdown code fences
      const cleaned = raw.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/i, "").trim();
      const analysis = JSON.parse(cleaned);
      res.json(analysis);
    } catch (err: any) {
      console.error("[StudioSmartEdit] Error:", err?.message || err);
      res.status(500).json({ error: "AI analysis failed", details: err?.message });
    }
  });

